INSERT INTO members (id, name, title, role, institution, department, country, city, lat, lng, bio, photo_url, orcid_id, interests, email, website_url, is_leadership, leadership_role, sort_order)
VALUES ('craig-press', 'Craig A. Press', 'MD, PhD', 'Co-Director', 'Children''s Hospital of Philadelphia', 'Neurology', 'USA', 'Philadelphia, PA', 39.9483, -75.1935, 'Craig is a physician-scientist who bridges the gap between EEG signal processing and bedside decision-making for critically ill children. Trained in both molecular biology (PhD, Washington University) and pediatric neurology, he completed fellowships in neurocritical care at Lurie Children''s Hospital and epilepsy at Children''s Hospital Colorado before joining CHOP and Penn. As Associate Professor of Pediatrics and Neurology, he directs the Neuroscience Unit and leads neurocritical care consults at CHOP. Craig co-founded PedQuEST to build the multicenter infrastructure he wished existed — a platform where sites can pool EEG data, validate qEEG biomarkers, and translate research into real-time clinical tools. When he''s not reading EEGs or writing grants, you''ll find him hiking with his family or plotting the next PedQuEST pilot study.', '/images/craig-press.jpg', '0000-0003-4435-206X', ARRAY['qEEG','Pediatric Neurocritical Care','EEG Biomarkers','Neurorecovery','Cardiac Arrest Outcomes'], 'pressca@chop.edu', NULL, TRUE, 'co_director', 1)
ON CONFLICT (id) DO NOTHING;

INSERT INTO members (id, name, title, role, institution, department, country, city, lat, lng, bio, photo_url, orcid_id, interests, email, website_url, is_leadership, leadership_role, sort_order)
VALUES ('giulia-benedetti', 'Giulia M. Benedetti', 'MD, FACNS', 'Co-Director', 'University of Michigan / C.S. Mott Children''s Hospital', 'Pediatric Neurology', 'USA', 'Ann Arbor, MI', 42.2808, -83.743, 'Giulia is a pediatric neurologist and neurocritical care specialist whose research is reshaping how we monitor children''s brains during critical illness. She earned her MD summa cum laude from The Ohio State University, completed residency in pediatric neurology and fellowships in neurocritical care (Lurie Children''s/Northwestern) and epilepsy (University of Michigan), and directed pediatric ICU EEG at Seattle Children''s Hospital before returning to Michigan. Now Clinical Associate Professor and Director of Pediatric Neurocritical Care at C.S. Mott Children''s Hospital, she leads efforts to validate quantitative EEG as a bedside decision-making tool. Giulia serves as Site PI for two NIH R01-funded Neonatal Seizure Registry studies (NSR-GENE and NSR-DEV) and was named a Fellow of the American Clinical Neurophysiology Society in 2024. As PedQuEST Co-Director, she shapes the consortium''s scientific direction and mentors the next generation of investigators. Her vision: every child in an ICU should benefit from the same quality of brain monitoring, regardless of which hospital they''re in.', '/images/giulia-benedetti.jpg', NULL, ARRAY['qEEG','Neonatal Neurology','Neurocritical Care','Neuromonitoring','Cardiac Arrest','Epilepsy'], 'gbenedet@med.umich.edu', NULL, TRUE, 'co_director', 2)
ON CONFLICT (id) DO NOTHING;

