INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-1', 'Predicting pediatric cardiac arrest outcomes using early quantitative EEG', ARRAY['Benedetti GM','Pardo AC','Nelson Sanchez-Pinto L','Straley M','Wainwright MS','Kurz JE','Press CA'], 'Resuscitation', 2025, 9, '10.1016/j.resuscitation.2025.110838', '41005642', NULL, 'Accuracy of neuroprognostication after pediatric cardiac arrest (CA) is critical for directing clinical care. Current limitations include imprecise neuroprognostication models, inability to discriminate between degrees of disability, and lack of modifiable post-CA biomarkers. Models including quantitative EEG (qEEG) characteristics may improve post-CA prognostic accuracy. Retrospective multicenter cohort of children (3mo-18 yr) without return to neurologic baseline post-CA at two pediatric tertiary care hospitals (2010-2016) with &#x2265; 6-hours of EEG within 24-hours post-CA and baseline Pediatric Cerebral Performance Category (PCPC) 1-3. Primary outcome measure was 6-month PCPC dichotomized into favorable (1-3) and unfavorable (4-6 and &#x394; > 1). Training and validation sets were derived from clinical variables, qualitative EEG (qualEEG) features, and qEEG analysis using Persyst software. Among 221 subjects, 84 (38%) had favorable 6-month outcomes. All models including clinical features (AUC 0.73 [0.59-0.87]), qualEEG (0.90 [0.81-0.97]) and qEEG features (0.85 [0.74-0.94]) predict outcomes well. A parsimonious model incorporating clinical, qualEEG and qEEG variables had an AUC of 0.92 (0.85-0.97) for predicting outcome. Increased SR was associated with degree of disability and unfavorable outcomes. Machine learning models were not superior to the more transparent parsimonious model. qEEG features measured with 24-h post-CA add to predictive outcome models and can be trended at the bedside. SR is an objective measure that may improve the precision of outcome prediction. qEEG features may be targetable dynamic brain injury biomarkers which could aid in future studies of neuroprotective interventions.', 'article', ARRAY['Cardiac Arrest','qEEG','Machine Learning'], ARRAY['cardiac arrest','quantitative EEG','machine learning','pediatric','outcomes'], 'Pediatric', TRUE, ARRAY['giulia-benedetti','mark-wainwright','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-2', 'Pediatric cardiac arrest outcome prediction using data-driven machine learning of early quantitative electroencephalogram (qEEG) features', ARRAY['Silva LEV','Chen CC','Press CA','Graham K','Shi L','Abend NS','Morgan RW','Topjian A','Tsui FR','Kirschen MP'], 'Resuscitation', 2025, 10, '10.1016/j.resuscitation.2025.110854', '41072601', 'PMC12705236', 'Hypoxic-ischemic brain injury drives poor outcomes after pediatric cardiac arrest, highlighting the need for early prognostication. This study evaluates whether machine learning models using a high-dimensional set of quantitative EEG (qEEG) features improve prediction of unfavorable neurologic outcome compared to a previously studied 7-feature model. We also assessed performance stability over time and the added value of clinical variables. Single-center retrospective cohort study of children aged 3 months to 18 years who experienced cardiac arrest and received EEG monitoring within 24 h post-arrest. Patients with pre-arrest Pediatric Cerebral Performance Category (PCPC) >3 were excluded. Unfavorable outcome was defined as death or PCPC &#x2265;4 at hospital discharge or 30 days post-arrest. We extracted 164 qEEG features and trained models using three established algorithms. Performance was evaluated using area under the ROC curve (AUROC). Seventy patients were included (median age 7.0 years, IQR 1.5-11.5); 53 % had unfavorable outcomes. Models using 164 qEEG features outperformed the 7-feature model: LASSO [0.81 (95 % CI: 0.69-0.91) vs 0.45 (0.31-0.58)] and Random Forest [0.80 (0.67-0.90) vs 0.65 (0.50-0.78)]. Adding clinical variables did not improve performance. AUROCs were stable across 6-h epochs from 6 to 24 h. Higher phase locking value, fractal exponent, and coherence were associated with better outcomes; higher delta power and suppression ratio variability were associated with worse outcomes. Data-driven models using 164 qEEG features accurately predicted neurologic outcomes after pediatric cardiac arrest, with stable performance over time. Future work includes external validation to assess generalizability.', 'article', ARRAY['Cardiac Arrest','Machine Learning','qEEG'], ARRAY['cardiac arrest','machine learning','qEEG','outcome prediction'], 'Pediatric', TRUE, ARRAY['craig-press','nicholas-abend','matthew-kirschen'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-3', 'Influenza-Associated Acute Necrotizing Encephalopathy in US Children', ARRAY['Silverman A','Walsh R','Santoro JD','Thomas K','Ballinger E','Fisher KS','Thomas AX','Appavu B','Kruer MC','Neilson D','Knoll J','Sharp AN','Edelman HE','Otallah S','Morgan A','Grzezulkowska A','Nguyen J','Rao LM','Hecht SM','Catalano L','Daigle H','Kronfol C','Wharton J','Adams D','Kalawi AZ','Kung M','Arellano JL','Smith L','Segal D','Feja K','Broomall E','Jayakar A','Arnold SR','Retallack H','Press CA','Gombolay G','McLaughlin MH','Kannan V','Thakkar K','Rezwan T','Hulfish E','Eid D','Meylor J','Peng D','Hurtado R','Nickerson T','Mandell I','Carbonell AU','Kerner-Rossi M','Jayaraman D','Davis M','Olivero R','Shah N','Osborne CM','Zhang B','Cortina C','Randolph AG','Rao S','LaRocca T','Van Haren KP','Wilson-Murphy M'], 'JAMA', 2025, 8, '10.1001/jama.2025.11534', '40736730', 'PMC12311823', 'Acute necrotizing encephalopathy (ANE) is a rare, but severe, neurologic condition for which epidemiologic and management data remain limited. During the 2024-2025 US influenza season, clinicians at large pediatric centers anecdotally reported an increased number of children with influenza-associated ANE, prompting this national investigation. To understand the clinical presentation, interventions, and outcomes among US children diagnosed with influenza-associated ANE. This study was a multicenter case series of children diagnosed with ANE with longitudinal follow-up. A call for cases was issued via academic societies, public health agencies, and by directly contacting pediatric specialists at 76 US academic centers, requesting cases between October 1, 2023, and May 30, 2025. Inclusion criteria required acute encephalopathy with radiologic evidence of acute thalamic injury and laboratory confirmation of influenza infection in individuals aged 21 years or younger. Influenza-associated ANE. Presenting symptoms, vaccination history, laboratory and genetic findings, interventions, and clinical outcomes, including modified Rankin Scale score (0: no symptoms; 1-2: mild disability; 3-5: moderate to severe disability; 6: death), length of stay, and functional outcomes. Of 58 submitted cases, 41 cases (23 females; median age, 5 years [IQR, 2-8]) from 23 US hospitals met inclusion criteria. Thirty-one cases (76%) had no significant medical history; 5 (12%) were medically complex. Clinical presentation included fever in 38 patients (93%), encephalopathy in 41 (100%), and seizures in 28 (68%). Thirty-nine patients (95%) had influenza A (14 with A/H1pdm/2009, 7 with A/H3N2, and 18 with no subtype) and 2 had influenza B. Laboratory deviations included elevated liver enzymes (78%), thrombocytopenia (63%), and elevated cerebrospinal fluid protein (63%). Among 32 patients (78%) with genetic testing, 15 (47%) had genetic risk alleles potentially related to risk of ANE including 11 (34%) with RANBP2 variants. Among 38 patients with available vaccination history, only 6 (16%) had received age-appropriate seasonal influenza vaccination. Most patients received multiple immunomodulatory treatments, including methylprednisolone (95%), intravenous immunoglobulin (66%), tocilizumab (51%), plasmapheresis (32%), anakinra (5%), and intrathecal methylprednisolone (5%). Median intensive care unit and hospital lengths of stay were 11 days (IQR, 4-19) and 22 days (IQR, 7-36), respectively. Eleven patients (27%) died a median of 3 days (IQR, 2-4) from symptom onset, primarily from cerebral herniation (91%). Among the 27 survivors with 90-day follow-up, 63% had at least moderate disability (modified Rankin Scale score &#x2265;3). In this case series of children with influenza-associated ANE from the 2 most recent influenza seasons in the US, the condition was associated with high morbidity and mortality in this cohort of predominantly young and previously healthy children. The findings emphasize the need for prevention, early recognition, intensive treatment, and standardized management protocols.', 'article', ARRAY['Neurocritical Care','Seizures','Biomarkers'], ARRAY['acute necrotizing encephalopathy','influenza','pediatric','encephalopathy'], 'Pediatric', TRUE, ARRAY['ajay-thomas','brian-appavu','anuj-jayakar','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-4', 'Association of EEG Response to Hypertonic Saline and Neurologic Outcomes in Pediatric Acute Brain Injury', ARRAY['Mazzio EL','Catenaccio E','Liu R','Vossough A','Abend NS','Alcamo AM','Huh JW','Chen SS','Berg RA','Topjian AA','Press CA','Kirschen MP'], 'Res Sq', 2025, 7, '10.21203/rs.3.rs-7200528/v1', '40766247', 'PMC12324595', 'EEG is a critical tool for neuromonitoring and neuroprognostication in children with acute brain injury. Quantitative EEG (qEEG), particularly the alpha-delta ratio (ADR), can detect worsening cerebral ischemia in adults, but it is unknown whether it can identify more subtle and transient changes in cerebral blood flow, such as those induced by hypertonic saline (HTS), in children. We aimed to determine whether we could identify a cohort of patients with an ADR response to HTS and to evaluate the association between an ADR response and neurologic outcomes in critically ill children with acute brain injury. We conducted a retrospective cohort study of patients admitted to a pediatric intensive care unit with acute brain injury who received HTS during EEG monitoring from 2018-2023. The ADR was calculated before and after HTS administration. An ADR response was defined as > 20% increase from baseline within 30 minutes of receiving HTS in either hemisphere. The primary outcome was survival with favorable neurologic outcome, defined as a Functional Status Scale (FSS) change < 3 from pre-hospital baseline to discharge. Secondary outcome was survival to hospital discharge. Among 87 patients (median age 10 years [IQR 3.6-14.5], 46% female), 28% (24/87) had an ADR response to HTS. ADR responders were older (12.9 vs. 8.0 years, p = 0.004) and more likely to have continuous, normal-voltage EEG backgrounds (67% vs. 40%, p = 0.006). Patients with an ADR response had 4 times increased odds of favorable outcome and survival (OR 4.0, 95% CI 1.3-12.7; OR 3.9, 95% CI 1.0-10.7, respectively). An ADR increase > 20% following HTS was associated with increased odds of survival with favorable neurologic outcome and survival to hospital discharge in critically ill pediatric patients with acute brain injury. qEEG response to HTS may serve as a real-time, noninvasive biomarker of cerebral perfusion responsiveness.', 'article', ARRAY['qEEG','Neurocritical Care','Brain Injury'], ARRAY['qEEG','hypertonic saline','brain injury','neuroprognostication'], 'Pediatric', TRUE, ARRAY['nicholas-abend','craig-press','matthew-kirschen'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-5', 'Focal Cerebral Injury in Pediatric ECLS: Timing in Relation to Cannulation', ARRAY['Caffarelli M','Li Y','Amorim E','Benedetti G','Press CA','Harrar D','Thomas AX'], 'Pediatr Crit Care Med', 2025, NULL, NULL, '40167357', NULL, NULL, 'article', ARRAY['ECMO/ECLS','Brain Injury','Neurocritical Care'], ARRAY['ECLS','cerebral injury','cannulation','pediatric'], 'Pediatric', TRUE, ARRAY['giulia-benedetti','craig-press','dana-harrar','ajay-thomas'])
