INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-6', 'Practice patterns for acquiring neuroimaging after pediatric in-hospital cardiac arrest', ARRAY['Kirschen MP','Ullman NL','Reeder RW','Ahmed T','Bell MJ','Berg RA','Burns C','Carcillo JA','Carpenter TC','Wesley Diddle J','Federman M','Fink EL','Frazier AH','Friess SH','Graham K','Horvat CM','Huard LL','Kilbaugh TJ','Maa T','Manga A','McQuillen PS','Meert KL','Morgan RW','Mourani PM','Nadkarni VM','Naim MY','Notterman D','Palmer CA','Pollack MM','Sapru A','Sharron MP','Srivastava N','Tilford B','Viteri S','Wolfe HA','Yates AR','Topjian A','Sutton RM','Press CA'], 'Resuscitation', 2025, 1, '10.1016/j.resuscitation.2025.110506', '39848427', 'PMC11842214', 'To determine which patient and cardiac arrest factors were associated with obtaining neuroimaging after in-hospital cardiac arrest, and among those patients who had neuroimaging, factors associated with which neuroimaging modality was obtained. Retrospective cohort study of patients who survived in-hospital cardiac arrest (IHCA) and were enrolled in the ICU-RESUS trial (NCT02837497). We tabulated ultrasound (US), CT, and MRI frequency within 7 days following IHCA and identified patient and cardiac arrest factors associated with neuroimaging modalities utilized. Multivariable models determined which factors were associated with obtaining neuroimaging. Of 1000 patients, 44% had &#x2265; 1 neuroimaging study (US in 31%, CT in 18%, and MRI in 6% of patients). Initial USs were performed a median of 0.3 [0.1,0.5], CTs 1.4 [0.4,2.8], and MRIs 4.1 [2.2,5.1] days post-arrest. Neuroimaging timing and frequency varied by site. Factors associated with greater odds of neuroimaging were cardiac arrest in CICU (versus PICU), longer duration CPR, receiving ECMO post-arrest, and post-arrest care with targeted temperature management or EEG monitoring. US performance was associated with congenital heart disease. CT was associated with age &#x2265; 1-month, greater pre-arrest disability, and receiving CPR for &#x2265; 16 min. MRI utilization increased with pre-existing respiratory insufficiency and respiratory decompensation as arrest cause, and medical cardiac and surgical non-cardiac or trauma illness category. Overall, if neuroimaging was obtained, US was more common in CICU while CT/MRI were utilized more in PICU. Practice patterns for acquiring neuroimaging after IHCA are variable and influenced by patient, cardiac arrest, and site factors.', 'article', ARRAY['Cardiac Arrest','Neuroimaging','Survey'], ARRAY['neuroimaging','cardiac arrest','in-hospital','pediatric'], 'Pediatric', TRUE, ARRAY['matthew-kirschen','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-7', 'Lack of association of first and second-line medication dosing and progression to refractory status epilepticus in children', ARRAY['Barcia Aguilar C','Amengual-Gual M','Brenton JN','Chapman KE','Clark J','Gaillard WD','Goldstein JL','Goodkin HP','Kahoud R','Lai YC','Mikati MA','Morgan LA','Payne ET','Press CA','Reece L','Sands TT','Sannagowdara K','Sheehan T','Shellhaas RA','Tasker RC','Wainwright MS','Zhang B','Loddenkemper T'], 'Seizure', 2024, 10, '10.1016/j.seizure.2024.10.017', '39550933', NULL, 'Evaluate the relationship between first and second-line medication dosing and progression to refractory status epilepticus (RSE) in children. This is a retrospective analysis of prospectively collected data from September 2014 to February 2020 of children with status epilepticus (SE) who received at least two antiseizure medications (ASMs). We evaluated the risk of developing RSE after receiving a low total benzodiazepine dose (lower than 100 % of the minimum recommended dose for each benzodiazepine dose administered within 10 min) and a low first non-benzodiazepine ASM dose (lower than 100 % of the minimum recommended dose of non-benzodiazepine ASM given as the first single-dose) using a logistic regression model, adjusting for confounders such as time to ASMs. The proportion of patients receiving low first non-benzodiazepine ASM doses was calculated and a logistic regression model was used to evaluate risk factors for low dosing of the first non-benzodiazepine ASM. Among 320 children, 170 (53.1 %) developed RSE, and 150 (46.9 %) responded to the first non-benzodiazepine ASM dose (non-RSE). One hundred thirty-seven (42.8 %) received a low total benzodiazepine dose, and 128 (40 %) received a low first non-benzodiazepine ASM dose. The odds of developing RSE were not higher after a low total benzodiazepine dose (OR=0.76, 95 %CI 0.47-1.23, p = 0.27) or low first non-benzodiazepine ASM dose (OR=0.85, 95 %CI 0.42-1.71, p = 0.65). Receiving a low first non-benzodiazepine ASM dose was independently associated with having received a low total benzodiazepine dose (OR=1.65, 95 %CI 1.01-2.70, p = 0.04). For most patients, dosing variability in first and second-line medications for SE was not the sole clinical feature predicting progression to RSE in this cohort of benzodiazepine-resistant patients. Identification of additional modifiable clinical biomarkers that predict progression to RSE is needed. Though lower ASM doses did not predict RSE in this model, the administration of ASMs at doses likely to prevent RSE remains crucial in SE treatment.', 'article', ARRAY['Status Epilepticus','Pharmacology'], ARRAY['status epilepticus','medication dosing','refractory','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press','mark-wainwright','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-8', 'Association of EEG characteristics with outcomes following pediatric ICU cardiac arrest: A secondary analysis of the ICU-RESUScitation trial', ARRAY['Mazzio EL','Topjian AA','Reeder RW','Sutton RM','Morgan RW','Berg RA','Nadkarni VM','Wolfe HA','Graham K','Naim MY','Friess SH','Abend NS','Press CA'], 'Resuscitation', 2024, 6, '10.1016/j.resuscitation.2024.110271', '38866233', 'PMC11331055', 'There are limited tools available following cardiac arrest to prognosticate neurologic outcomes. Prior retrospective and single center studies have demonstrated early EEG features are associated with neurologic outcome. This study aimed to evaluate the prognostic value of EEG for pediatric in-hospital cardiac arrest (IHCA) in a prospective, multicenter study. This cohort study is a secondary analysis of the ICU-Resuscitation trial, a multicenter randomized interventional trial conducted at 18 pediatric and pediatric cardiac ICUs in the United States. Patients who achieved return of circulation (ROC) and had post-ROC EEG monitoring were eligible for inclusion. Patients < 90 days old and those with pre-arrest Pediatric Cerebral Performance Category (PCPC) scores > 3 were excluded. EEG features of interest included EEG Background Category, and presence of focal abnormalities, sleep spindles, variability, reactivity, periodic and rhythmic patterns, and seizures. The primary outcome was survival to hospital discharge with favorable neurologic outcome. Associations between EEG features and outcomes were assessed with multivariable logistic regression. Prediction models with and without EEG Background Category were developed and receiver operator characteristic curves compared. Of the 1129 patients with an index cardiac arrest who achieved ROC in the parent study, 261 had EEG within 24 h of ROC, of which 151 were evaluable. The cohort included 57% males with a median age of 1.1 years (IQR 0.4, 6.8). EEG features including EEG Background Category, sleep spindles, variability, and reactivity were associated with survival with favorable outcome and survival, (all p < 0.001). The addition of EEG Background Category to clinical models including age category, illness category, PRISM score, duration of CPR, first documented rhythm, highest early post-arrest arterial lactate improved the prediction accuracy achieving an AUROC of 0.84 (CI 0.77-0.92), compared to AUROC of 0.76 (CI 0.67-0.85) (p = 0.005) without EEG Background Category. This multicenter study demonstrates the value of EEG, in the first 24 h following ROC, for predicting survival with favorable outcome after a pediatric IHCA.', 'article', ARRAY['Cardiac Arrest','EEG','Clinical Trial'], ARRAY['cardiac arrest','EEG','ICU-RESUScitation','clinical trial','outcomes'], 'Pediatric', TRUE, ARRAY['nicholas-abend','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-9', 'Review of Noninvasive Neuromonitoring Modalities in Children II: EEG, qEEG', ARRAY['Benedetti GM','Guerriero RM','Press CA'], 'Neurocrit Care', 2023, 3, '10.1007/s12028-023-01686-5', '36949358', 'PMC10033183', 'Critically ill children with acute neurologic dysfunction are at risk for a variety of complications that can be detected by noninvasive bedside neuromonitoring. Continuous electroencephalography (cEEG) is the most widely available and utilized form of neuromonitoring in the pediatric intensive care unit. In this article, we review the role of cEEG and the emerging role of quantitative EEG (qEEG) in this patient population. cEEG has long been established as the gold standard for detecting seizures in critically ill children and assessing treatment response, and its role in background assessment and neuroprognostication after brain injury is also discussed. We explore the emerging utility of both cEEG and qEEG as biomarkers of degree of cerebral dysfunction after specific injuries and their ability to detect both neurologic deterioration and improvement.', 'review', ARRAY['Neuromonitoring','qEEG','Review'], ARRAY['neuromonitoring','EEG','qEEG','pediatric','review'], 'Pediatric', TRUE, ARRAY['giulia-benedetti','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-10', 'A quantitative EEG index for the recognition of arterial ischemic stroke in children', ARRAY['Caffarelli M','Karukonda V','Aghaeeaval M','McQuillen PS','Numis AL','Mackay MT','Press CA','Wintermark M','Fox CK','Amorim E'], 'Clin Neurophysiol', 2023, 10, '10.1016/j.clinph.2023.10.001', '37918222', NULL, 'To describe and assess performance of the Correlate Of Injury to the Nervous system (COIN) index, a quantitative electroencephalography (EEG) metric designed to identify areas of cerebral dysfunction concerning for stroke. Case-control study comparing continuous EEG data from children with acute ischemic stroke to children without stroke, with or without encephalopathy. COIN is calculated continuously and compares EEG power between cerebral hemispheres. Stroke relative infarct volume (RIV) was calculated from quantitative neuroimaging analysis. Significance was determined using a two-sample t-test. Sensitivity, specificity, and accuracy were measured using logistic regression. Average COIN values were -34.7 in the stroke cohort compared to -9.5 in controls without encephalopathy (p = 0.003) and -10.5 in controls with encephalopathy (p = 0.006). The optimal COIN cutoff to discriminate stroke from controls was -15 in non-encephalopathic and -18 in encephalopathic controls with >92% accuracy in strokes with RIV > 5%. A COIN cutoff of -20 allowed discrimination between strokes with <5% and >5% RIV (p = 0.027). We demonstrate that COIN can identify children with acute ischemic stroke. COIN may be a valuable tool for stroke identification in children. Additional studies are needed to determine utility as a monitoring technique for children at risk for stroke.', 'article', ARRAY['qEEG','Stroke','EEG'], ARRAY['quantitative EEG','ischemic stroke','COIN index','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-11', 'Profiles and Predictors of Neurodevelopmental Outcome at 5-6 Years in Children With a History of Acute Provoked Neonatal Seizures', ARRAY['Glass HC','Numis AL','Soul JS','Wusthoff CJ','Lemmon ME','Benedetti GM','Chu CJ','Massey SL','Thomas C','Anwar T','Sturza J','Berl MM','Li Y','Rogers EE','Rau S','Gidley Larson JC','Guerrero JL','Franck LS','McCulloch CE','Shellhaas RA'], 'Ann Neurol', 2026, 1, '10.1002/ana.78100', '41482857', NULL, 'The objective of this study was to characterize the neurodevelopment and risk factors for impairment at age 5 to 6 years after acute provoked neonatal seizures. Multicenter study of neonates with acute provoked seizures. Wechsler Preschool and Primary Scale of Intelligence IV (WPPSI-IV), Vineland-3 Adaptive Behavior Scales, Behavior Assessment System for Children, Behavior Rating Inventory of Executive Function, Social Responsiveness Scale, cerebral palsy (CP), and epilepsy were assessed at age 5 to 6 years. Latent class analysis defined outcome profiles. Least absolute shrinkage and selection operator (LASSO) was used to determine outcome predictors. We characterized 3 latent classes among 164 children: (1) Typical Development (63%); (2) Behavioral Dysregulation (13%; low likelihood of physical impairment or severely impaired cognition, high likelihood of attention deficit hyperactivity disorder [ADHD]); and (3) Multi-Domain Impairment (24%; high likelihood of epilepsy and impairment across all domains). Among 144 children with standardized testing, mean WPPSI-IV was 91 &#xb1; 25 and Vineland-3 Adaptive Behavior Composite 90 &#xb1; 20. Twenty-nine percent had ADHD or elevated attention/hyperactivity scores; 19% had autism or elevated Social Responsiveness scores; 20% had epilepsy, and 19% had CP. Risk factors for Multi-Domain Impairment were abnormal neonatal neurologic examination (odds ratio [OR] = 3.94, 95% confidence interval [CI] = 1.74-8.95), impaired functional development at age 24 months (OR = 3.82, 95% CI = 1.25-11.66), and CP (OR = 3.71, 95% CI = 1.74-7.90). No neonatal or infant characteristics were significantly associated with Behavioral Dysregulation. Nearly two-thirds of 5 to 6-year-old children with provoked neonatal seizures had typical development. Yet, executive and behavioral dysregulation were prevalent, even with preserved cognitive and physical function. These findings can inform outcome discussions and interventions to promote neurodevelopment. ANN NEUROL 2026;99:777-791.', 'article', ARRAY['Neonatal','Seizures','Neurodevelopment'], ARRAY['neonatal seizures','neurodevelopment','outcomes','long-term'], 'Pediatric', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-12', 'Postneonatal epilepsy after acute provoked neonatal seizures: Incidence, predictors, and clinical burden in a multicenter cohort followed through early childhood', ARRAY['Numis AL','Glass HC','Soul JS','Wusthoff CJ','Massey SL','Benedetti GM','Chu CJ','Thomas C','Anwar T','Lemmon ME','Franck LS','Berl MM','Pilon B','Rau SMD','Li Y','Sturza J','McCulloch CE','Shellhaas RA'], 'Epilepsia', 2025, 8, '10.1111/epi.18590', '40770895', 'PMC12779315', 'Epilepsy is a known potential outcome following acute provoked neonatal seizures, but its onset, treatment patterns, and health care utilization through childhood remain poorly characterized. This study aimed to define the incidence and timing of postneonatal epilepsy, identify perinatal predictors, and describe the clinical burden of epilepsy among survivors of acute provoked neonatal seizures through early childhood. This prospective, multicenter cohort study followed neonates with acute provoked seizures from the Neonatal Seizure Registry (NSR-II) in an extended follow-up through early childhood (Developmental Functional Evaluation). Neonatal clinical and neuroimaging data were collected, and epilepsy outcomes (including semiology, treatments, and health care use) were assessed annually through at least 5 years via structured interviews and medical record review. Kaplan-Meier and Cox proportional hazards models evaluated epilepsy risk, with data censored at loss to follow-up. Among 282 neonates evaluated for epilepsy in NSR-II, 183 (65%) continued into the extended follow-up study. Across the entire follow-up period through early childhood, 50 (18%) developed epilepsy, with a cumulative incidence of 21.6% (95% confidence interval [CI] = 16.7%-27.7%). Earlier epilepsy onset was associated with &#x2265;3 days of neonatal seizures (hazard ratio [HR] = 2.8, 95% CI = 1.5-5.2), abnormal discharge neurological exam (HR = 2.4, 95% CI = 1.3-4.4), and deep gray/brainstem injury (HR = 2.4, 95% CI = 1.2-4.7). Prematurity (<37 weeks) was associated with later epilepsy onset (HR = 3.7, 95% CI = 2.0-6.8). Half (50%) of children with epilepsy developed intractable epilepsy, and 40% required intensive care unit admission. Despite this, only one child received vagus nerve stimulation, and none underwent other epilepsy surgeries. These findings highlight the early and persistent epilepsy risk after neonatal seizures. Preterm infants face increased risk later in childhood compared to infants born at term. Risk factor stratification may improve early surveillance, guide clinical decisions, and support family counseling. The underutilization of epilepsy surgery in this cohort suggests multifactorial barriers that warrant further investigation.', 'article', ARRAY['Neonatal','Epilepsy','Seizures'], ARRAY['postneonatal epilepsy','neonatal seizures','incidence','predictors'], 'Pediatric', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

