INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-43', 'Spectral Electroencephalogram Analysis for the Evaluation of Encephalopathy Grade in Children With Acute Liver Failure', ARRAY['Press CA','Morgan L','Mills M','Stack CV','Goldstein JL','Alonso EM','Wainwright MS'], 'Pediatr Crit Care Med', 2017, 1, '10.1097/PCC.0000000000001016', '27811533', NULL, 'Spectral electroencephalogram analysis is a method for automated analysis of electroencephalogram patterns, which can be performed at the bedside. We sought to determine the utility of spectral electroencephalogram for grading hepatic encephalopathy in children with acute liver failure. Retrospective cohort study. Tertiary care pediatric hospital. Patients between 0 and 18 years old who presented with acute liver failure and were admitted to the PICU. None. Electroencephalograms were analyzed by spectral analysis including total power, relative &#x3b4;, relative &#x3b8;, relative &#x3b1;, relative &#x3b2;, &#x3b8;-to-&#x394; ratio, and &#x3b1;-to-&#x394; ratio. Normal values and ranges were first derived using normal electroencephalograms from 70 children of 0-18 years old. Age had a significant effect on each variable measured (p < 0.03). Electroencephalograms from 33 patients with acute liver failure were available for spectral analysis. The median age was 4.3 years, 14 of 33 were male, and the majority had an indeterminate etiology of acute liver failure. Neuroimaging was performed in 26 cases and was normal in 20 cases (77%). The majority (64%) survived, and 82% had a good outcome with a score of 1-3 on the Pediatric Glasgow Outcome Scale-Extended at the time of discharge. Hepatic encephalopathy grade correlated with the qualitative visual electroencephalogram scores assigned by blinded neurophysiologists (rs = 0.493; p < 0.006). Spectral electroencephalogram characteristics varied significantly with the qualitative electroencephalogram classification (p < 0.05). Spectral electroencephalogram variables including relative &#x394;, relative &#x3b8;, relative &#x3b1;, &#x3b8;-to-&#x394; ratio, and &#x3b1;-to-&#x394; ratio all significantly varied with the qualitative electroencephalogram (p < 0.025). Moderate to severe hepatic encephalopathy was correlated with a total power of less than or equal to 50% of normal for children 0-3 years old, and with a relative &#x3b8; of less than or equal to 50% normal for children more than 3 years old (p > 0.05). Spectral electroencephalogram classification correlated with outcome (p < 0.05). Spectral electroencephalogram analysis can be used to evaluate even young patients for hepatic encephalopathy and correlates with outcome. Spectral electroencephalogram may allow improved quantitative and reproducible assessment of hepatic encephalopathy grade in children with acute liver failure.', 'article', ARRAY['qEEG','Cardiac Arrest','Neurocritical Care'], ARRAY['spectral EEG','encephalopathy','cardiac arrest','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press','mark-wainwright'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-44', 'Early Presence of Sleep Spindles on Electroencephalography Is Associated With Good Outcome After Pediatric Cardiac Arrest', ARRAY['Ducharme-Crevier L','Press CA','Kurz JE','Mills MG','Goldstein JL','Wainwright MS'], 'Pediatr Crit Care Med', 2017, 5, '10.1097/PCC.0000000000001137', '28328788', NULL, 'The role of sleep architecture as a biomarker for prognostication after resuscitation from cardiac arrest in children hospitalized in an ICU remains poorly defined. We sought to investigate the association between features of normal sleep architecture in children after cardiac arrest and a favorable neurologic outcome at 6 months. Retrospective review of medical records and continuous electroencephalography monitoring. Cardiac and PICU of a tertiary children''s hospital. All patients from 6 months to 18 years old resuscitated from cardiac arrest who underwent continuous electroencephalography monitoring in the first 24 hours after in- or out-of-hospital cardiac arrest from January 2010 to June 2015. None. Thirty-four patients underwent continuous electroencephalography monitoring after cardiac arrest. The median age was 6.1 years (interquartile range, 1.5-12.5 yr), 20 patients were male (59%). Most cases (n = 23, 68%) suffered from in-hospital cardiac arrest. Electroencephalography monitoring was initiated a median of 9.3 hours (5.8-14.9 hr) after return of spontaneous circulation, for a median duration of 14.3 hours (6.0-16.0 hr) within the first 24-hour period after the cardiac arrest. Five patients had normal spindles, five had abnormal spindles, and 24 patients did not have any sleep architecture. The presence of spindles was associated with a favorable neurologic outcome at 6-month postcardiac arrest (p = 0.001). Continuous electroencephalography monitoring can be used in children to assess spindles in the ICU. The presence of spindles on continuous electroencephalography monitoring in the first 24 hours after resuscitation from cardiac arrest is associated with a favorable neurologic outcome. Assessment of sleep architecture on continuous electroencephalography after cardiac arrest could improve outcome prediction.', 'article', ARRAY['EEG','Cardiac Arrest','Sleep'], ARRAY['sleep spindles','cardiac arrest','EEG','prognostication','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press','mark-wainwright'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-45', 'Targeted Temperature Management in Pediatric Neurocritical Care', ARRAY['Benedetti GM','Silverstein FS'], 'Pediatr Neurol', 2018, 7, '10.1016/j.pediatrneurol.2018.07.004', '30309737', NULL, 'Targeted temperature management encompasses a range of clinical interventions to regulate systemic temperature, and includes both induction of varying degrees of hypothermia and fever prevention ("targeted normothermia"). Targeted temperature management plays a key role in the contemporary management of critically ill neonates and children with acute brain injury. Yet, many unanswered questions remain regarding optimal temperature management in pediatric neurocritical care. The introduction highlights experimental studies that have evaluated the neuroprotective efficacy of therapeutic hypothermia and explored possible mechanisms of action in several brain injury models. The next section focuses on three major clinical conditions in which therapeutic hypothermia has been evaluated in randomized controlled trials in pediatric populations: neonatal hypoxic-ischemic encephalopathy, postcardiac arrest encephalopathy, and traumatic brain injury. Clinical implications of targeted temperature management in pediatric neurocritical care are also discussed. The final section examines some of the factors that may underlie the limited neuroprotective efficacy of hypothermia that has been observed in several major pediatric clinical trials, and outlines important directions for future research.', 'review', ARRAY['Neurocritical Care','Review'], ARRAY['targeted temperature management','hypothermia','neurocritical care','pediatric'], 'Pediatric', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-46', 'Early Electroencephalogram Background Could Guide Tailored Duration of Monitoring for Neonatal Encephalopathy Treated with Therapeutic Hypothermia', ARRAY['Benedetti GM','Vartanian RJ','McCaffery H','Shellhaas RA'], 'J Pediatr', 2020, 3, '10.1016/j.jpeds.2020.01.066', '32222256', NULL, 'To evaluate whether features of the early electroencephalographic (EEG) background could guide the optimal duration of continuous video EEG monitoring for seizure detection in newborn infants treated with therapeutic hypothermia for hypoxic ischemic encephalopathy (HIE). Retrospective cohort study of 114 consecutive infants treated with therapeutic hypothermia for moderate to severe HIE at a level IV neonatal intensive care unit (NICU) between 2012 and 2018. All infants were monitored with continuous video EEG through cooling and rewarming. Archived samples from the first 24 hours of these EEG traces were reviewed systematically and classified by background characteristics. Electrographic seizures occurred in 56 of the 114 infants (49%). Seizure onset was within the first 24 hours after initiation of continuous video EEG in 49 if these 56 infants (88%), between 24 and 48 hours in 4 infants (7%), and >72 hours in 3 infants (5%). Infants with a normal or mildly abnormal EEG background either had seizure onset within the first 24 hours or never developed seizures. Four patients with seizure onset between 24 and 48 hours had markedly abnormal EEG backgrounds. The 3 patients with seizure onset beyond 72 hours had moderate or severely abnormal early continuous video EEG backgrounds. The use of early continuous video EEG background categorization may be appropriate to guide the duration of continuous video EEG for infants with HIE treated with therapeutic hypothermia. Some infants may reasonably be monitored for 24 hours rather than throughout cooling and rewarming without a significant risk of missed seizures. This could have significant implications for continuous video EEG resource utilization.', 'article', ARRAY['Neonatal','EEG','Neuromonitoring'], ARRAY['EEG background','neonatal encephalopathy','hypothermia','monitoring duration'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-47', 'Treatment of Neonatal Seizures: Comparison of Treatment Pathways From 11 Neonatal Intensive Care Units', ARRAY['Keene JC','Morgan LA','Abend NS','Bates SV','Bauer Huang SL','Chang T','Chu CJ','Glass HC','Massey SL','Ostrander B','Pardo AC','Press CA','Soul JS','Shellhaas RA','Thomas C','Natarajan N'], 'Pediatr Neurol', 2021, 10, '10.1016/j.pediatrneurol.2021.10.004', '34750046', NULL, 'Seizures are a common neonatal neurologic emergency. Many centers have developed pathways to optimize management. We evaluated neonatal seizure management pathways at level IV neonatal intensive care units (NICUs) in the United States to highlight areas of consensus and describe aspects of variability. We conducted a descriptive analysis of 11 neonatal seizure management pathways from level IV NICUs that specialize in neonatal neurocritical care including guidelines for electroencephalography (EEG) monitoring, antiseizure medication (ASM) choice, timing, and dose. Study center NICUs had a median of 70 beds (interquartile range: 52-96). All sites had 24/7 conventional EEG initiation, monitoring, and review capability. Management pathways uniformly included prompt EEG confirmation of seizures. Most pathways included a provision for intravenous benzodiazepine administration if either EEG or loading of ASM was delayed. Phenobarbital 20 mg/kg IV was the first-line ASM in all pathways. Pathways included either fosphenytoin or levetiracetam as the second-line ASM with variable dosing. Third-line ASMs were most commonly fosphenytoin or levetiracetam, with alternatives including topiramate or lacosamide. All pathways provided escalation to continuous midazolam infusion with variable dosing for seizures refractory to initial medication trials. Three pathways also included lidocaine infusion. Nine pathways discussed ASM discontinuation after resolution of acute symptomatic seizures with variable timing. Despite a paucity of data from controlled trials regarding optimal neonatal seizure management, there are areas of broad agreement among institutional pathways. Areas of substantial heterogeneity that require further research include optimal second-line ASM, dosage, and timing of ASM discontinuation.', 'article', ARRAY['Neonatal','Seizures','Pharmacology'], ARRAY['neonatal seizures','treatment pathways','NICU','anticonvulsants'], 'Neonatal', TRUE, ARRAY['nicholas-abend','giulia-benedetti','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-48', 'Multicenter Study of the Impact of COVID-19 Shelter-In-Place on Tertiary Hospital-based Care for Pediatric Neurologic Disease', ARRAY['Hutchinson ML','Nash KB','Abend NS','Moharir M','Wells E','Messer RD','Palaganas J','Helbig I','Wietstock SO','Suslovic W','Gonzalez AK','Kaufman MC','Press CA','Piantino J'], 'Neurohospitalist', 2022, 2, '10.1177/19418744211063075', '35414846', 'PMC8814588', 'To describe changes in hospital-based care for children with neurologic diagnoses during the initial 6 weeks following regional Coronavirus 2019 Shelter-in-Place orders. This retrospective cross-sectional study of 7 US and Canadian pediatric tertiary care institutions included emergency and inpatient encounters with a neurologic primary discharge diagnosis code in the initial 6 weeks of Shelter-in-Place (COVID-SiP), compared to the same period during the prior 3 years (Pre-COVID). Patient demographics, encounter length, and neuroimaging and electroencephalography use were extracted from the medical record. 27,900 encounters over 4 years were included. Compared to Pre-COVID, there was a 54% reduction in encounters during Shelter-in-Place. COVID-SiP patients were younger (median 5 years vs 7 years). The incidence of encounters for migraine fell by 72%, and encounters for acute diagnoses of status epilepticus, infantile spasms, and traumatic brain injury dropped by 53%, 55%, and 56%, respectively. There was an increase in hospital length of stay, relative utilization of intensive care, and diagnostic testing (long-term electroencephalography, brain MRI, and head CT (all<.01)). During the initial 6 weeks of SiP, there was a significant decrease in neurologic hospital-based encounters. Those admitted required a high level of care. Hospital-based neurologic services are needed to care for acutely ill patients. Precise factors causing these shifts are unknown and raise concern for changes in care seeking of patients with serious neurologic conditions. Impacts of potentially delayed diagnosis or treatment require further investigation.', 'article', ARRAY['COVID-19','Neurocritical Care'], ARRAY['COVID-19','shelter-in-place','pediatric neurology','hospital care'], 'Pediatric', TRUE, ARRAY['nicholas-abend','craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-49', 'Use of Magnetic Resonance Imaging in Neuroprognostication After Pediatric Cardiac Arrest: Survey of Current Practices', ARRAY['Piantino JA','Ruzas CM','Press CA','Subramanian S','Balakrishnan B','Panigrahy A','Pettersson D','Maloney JA','Vossough A','Topjian A','Kirschen MP','Doughty L','Chung MG','Maloney D','Haller T','Fabio A','Fink EL'], 'Pediatr Neurol', 2022, 6, '10.1016/j.pediatrneurol.2022.06.011', '35835025', 'PMC9883065', 'Use of magnetic resonance imaging (MRI) as a tool to aid in neuroprognostication after cardiac arrest (CA) has been described, yet details of specific indications, timing, and sequences are unknown. We aim to define the current practices in use of brain MRI in prognostication after pediatric CA. A survey was distributed to pediatric institutions participating in three international studies. Survey questions related to center demographics, clinical practice patterns of MRI after CA, neuroimaging resources, and details regarding MRI decision support. Response rate was 31% (44 of 143). Thirty-four percent (15 of 44) of centers have a clinical pathway informing the use of MRI after CA. Fifty percent (22 of 44) of respondents reported that an MRI is obtained in nearly all patients with CA, and 32% (14 of 44) obtain an MRI in those who do not return to baseline neurological status. Poor neurological examination was reported as the most common factor (91% [40 of 44]) determining the timing of the MRI. Conventional sequences (T1, T2, fluid-attenuated inversion recovery, and diffusion-weighted imaging/apparent diffusion coefficient) are routinely used at greater than 97% of centers. Use of advanced imaging techniques (magnetic resonance spectroscopy, diffusion tensor imaging, and functional MRI) were reported by less than half of centers. Conventional brain MRI is a common practice for prognostication after CA. Advanced imaging techniques are used infrequently. The lack of standardized clinical pathways and variability in reported practices support a need for higher-quality evidence regarding the indications, timing, and acquisition protocols of clinical MRI studies.', 'article', ARRAY['Cardiac Arrest','Neuroimaging','Survey'], ARRAY['MRI','neuroprognostication','cardiac arrest','survey','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press','matthew-kirschen'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-50', 'Association of Blood-Based Brain Injury Biomarker Concentrations With Outcomes After Pediatric Cardiac Arrest', ARRAY['Fink EL','Kochanek PM','Panigrahy A','Beers SR','Berger RP','Bayir H','Pineda J','Newth C','Topjian AA','Press CA','Maddux AB','Willyerd F','Hunt EA','Siems A','Chung MG','Smith L','Wenger J','Doughty L','Diddle JW','Patregnani J','Piantino J','Walson KH','Balakrishnan B','Meyer MT','Friess S','Maloney D','Rubin P','Haller TL','Treble-Barna A','Wang C','Clark RRSB','Fabio A'], 'JAMA Netw Open', 2022, 9, '10.1001/jamanetworkopen.2022.30518', '36074465', 'PMC9459665', 'Families and clinicians have limited validated tools available to assist in estimating long-term outcomes early after pediatric cardiac arrest. Blood-based brain-specific biomarkers may be helpful tools to aid in outcome assessment. To analyze the association of blood-based brain injury biomarker concentrations with outcomes 1 year after pediatric cardiac arrest. The Personalizing Outcomes After Child Cardiac Arrest multicenter prospective cohort study was conducted in pediatric intensive care units at 14 academic referral centers in the US between May 16, 2017, and August 19, 2020, with the primary investigators blinded to 1-year outcomes. The study included 120 children aged 48 hours to 17 years who were resuscitated after cardiac arrest, had pre-cardiac arrest Pediatric Cerebral Performance Category scores of 1 to 3 points, and were admitted to an intensive care unit after cardiac arrest. Cardiac arrest. The primary outcome was an unfavorable outcome (death or survival with a Vineland Adaptive Behavior Scales, third edition, score of <70 points) at 1 year after cardiac arrest. Glial fibrillary acidic protein (GFAP), ubiquitin carboxyl-terminal esterase L1 (UCH-L1), neurofilament light (NfL), and tau concentrations were measured in blood samples from days 1 to 3 after cardiac arrest. Multivariate logistic regression and area under the receiver operating characteristic curve (AUROC) analyses were performed to examine the association of each biomarker with outcomes on days 1 to 3. Among 120 children with primary outcome data available, the median (IQR) age was 1.0 (0-8.5) year; 71 children (59.2%) were male. A total of 5 children (4.2%) were Asian, 19 (15.8%) were Black, 81 (67.5%) were White, and 15 (12.5%) were of unknown race; among 110 children with data on ethnicity, 11 (10.0%) were Hispanic, and 99 (90.0%) were non-Hispanic. Overall, 70 children (58.3%) had a favorable outcome, and 50 children (41.7%) had an unfavorable outcome, including 43 deaths. On days 1 to 3 after cardiac arrest, concentrations of all 4 measured biomarkers were higher in children with an unfavorable vs a favorable outcome at 1 year. After covariate adjustment, NfL concentrations on day 1 (adjusted odds ratio [aOR], 5.91; 95% CI, 1.82-19.19), day 2 (aOR, 11.88; 95% CI, 3.82-36.92), and day 3 (aOR, 10.22; 95% CI, 3.14-33.33); UCH-L1 concentrations on day 2 (aOR, 11.27; 95% CI, 3.00-42.36) and day 3 (aOR, 7.56; 95% CI, 2.11-27.09); GFAP concentrations on day 2 (aOR, 2.31; 95% CI, 1.19-4.48) and day 3 (aOR, 2.19; 95% CI, 1.19-4.03); and tau concentrations on day 1 (aOR, 2.44; 95% CI, 1.14-5.25), day 2 (aOR, 2.28; 95% CI, 1.31-3.97), and day 3 (aOR, 2.04; 95% CI, 1.16-3.57) were associated with an unfavorable outcome. The AUROC models were significantly higher with vs without the addition of NfL on day 2 (AUROC, 0.932 [95% CI, 0.877-0.987] vs 0.871 [95% CI, 0.793-0.949]; P = .02) and day 3 (AUROC, 0.921 [95% CI, 0.857-0.986] vs 0.870 [95% CI, 0.786-0.953]; P = .03). In this cohort study, blood-based brain injury biomarkers, especially NfL, were associated with an unfavorable outcome at 1 year after pediatric cardiac arrest. Additional evaluation of the accuracy of the association between biomarkers and neurodevelopmental outcomes beyond 1 year is needed.', 'article', ARRAY['Cardiac Arrest','Biomarkers'], ARRAY['biomarkers','brain injury','cardiac arrest','blood-based','pediatric'], 'Pediatric', TRUE, ARRAY['craig-press'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-51', 'Neuromonitoring in the ICU: noninvasive and invasive modalities for critically ill children and neonates', ARRAY['Agarwal N','Benedetti GM'], 'Curr Opin Pediatr', 2024, 9, '10.1097/MOP.0000000000001399', '39297699', NULL, 'Critically ill children are at risk of neurologic dysfunction and acquiring primary and secondary brain injury. Close monitoring of cerebral function is crucial to prevent, detect, and treat these complications. A variety of neuromonitoring modalities are currently used in pediatric and neonatal ICUs. These include noninvasive modalities, such as electroencephalography, transcranial Doppler, and near-infrared spectroscopy, as well as invasive methods including intracranial pressure monitoring, brain tissue oxygen measurement, and cerebral microdialysis. Each modality offers unique insights into neurologic function, cerebral circulation, or metabolism to support individualized neurologic care based on a patient''s own physiology. Utilization of these modalities in ICUs results in reduced neurologic injury and mortality and improved neurodevelopmental outcomes. Monitoring of neurologic function can significantly improve care of critically ill children. Additional research is needed to establish normative values in pediatric patients and to standardize the use of these modalities.', 'review', ARRAY['Neuromonitoring','Neurocritical Care','Review'], ARRAY['neuromonitoring','ICU','invasive','noninvasive','pediatric'], 'Pediatric', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-52', 'Definitions of adverse events associated with extracorporeal membrane oxygenation in children: results of an international Delphi process from the ECMO-CENTRAL ARC', ARRAY['Alexander PMA','Di Nardo M','Combes A','Vogel AM','Antonini MV','Barrett N','Benedetti GM','Bettencourt A','Brodie D','G&#xf3;mez-Guti&#xe9;rrez R','Gorga SM','Hodgson C','Kapoor PM','Le J','MacLaren G','O''Neil ER','Ostermann M','Paden ML','Patel N','Rojas-Pe&#xf1;a A','Said AS','Sperotto F','Willems A','Vercaemst L','Yoganathan AP','Lorts A','Del Nido PJ','Barbaro RP'], 'Lancet Child Adolesc Health', 2024, 10, '10.1016/S2352-4642(24)00132-9', '39299748', 'PMC12917940', 'Extracorporeal membrane oxygenation (ECMO) is a high-risk and low-volume life support with increasing clinical study. However, heterogenous outcome definitions impede data assimilation into evidence to guide practice. The Academic Research Consortium (ARC), an international collaborative forum committed to facilitating the creation of stakeholder-driven consensus nomenclature and outcomes for clinical trials of medical devices, supported the ECMO Core Elements Needed for Trials Regulation And quality of Life (ECMO-CENTRAL) ARC. The ECMO-CENTRAL ARC was assembled to develop definitions of paediatric ECMO adverse events for use in clinical trials and regulatory device evaluation. An initial candidate list of ECMO adverse events derived from the mechanical circulatory support ARC was supplemented with a review of ECMO-relevant adverse event definitions collated from literature published between Jan 1, 1988, and Feb 20, 2023. Distinct teams of international topic experts drafted separate adverse event definitions that were harmonised to existing literature when appropriate. Draft definitions were revised for paediatric ECMO relevance with input from patients, families, and an international expert panel of trialists, clinicians, statisticians, biomedical engineers, device developers, and regulatory agencies. ECMO-CENTRAL ARC was revised and disseminated across research societies and professional organisations. Up to three rounds of internet-based anonymous surveys were planned as a modified Delphi process. The expert panel defined 13 adverse event definitions: neurological, bleeding, device malfunction, acute kidney injury, haemolysis, infection, vascular access-associated injury, non-CNS thrombosis, hepatic dysfunction, right heart failure, left ventricular overload, lactic acidaemia, and hypoxaemia. Definitional structure varied. Among 165 expert panel members, 114 were eligible to vote and 111 voted. Consensus was achieved for all proposed definitions. Agreement ranged from 82% to 95%. ECMO-CENTRAL ARC paired rigorous development with methodical stakeholder involvement and dissemination to define paediatric ECMO adverse events. These definitions will facilitate new research and the assimilation of data across clinical trials and ECMO device evaluation in children.', 'article', ARRAY['ECMO/ECLS','Neurocritical Care'], ARRAY['ECMO','adverse events','Delphi consensus','pediatric'], 'Pediatric', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-53', 'Life After Neonatal Seizures: Characterizing the Longitudinal Parent Experience', ARRAY['Field NK','Franck LS','Shellhaas RA','Glass HC','Young KA','Dhar S','Hamlett A','Pilon B','Means K','Soul JS','Massey SL','Wusthoff CJ','Chu CJ','Thomas C','Rogers E','Berl MM','Benedetti GM','Anwar T','Lemmon ME'], 'Pediatr Neurol', 2024, 9, '10.1016/j.pediatrneurol.2024.08.007', '39317023', 'PMC11602358', 'Parents of neonates with seizures report persistent symptoms of depression, anxiety, and posttraumatic stress. We aimed to characterize the parent experience of caring for children impacted by neonatal seizures, including longitudinal assessment across childhood. This prospective, observational, multicenter study was conducted at Neonatal Seizure Registry (NSR) sites in partnership with the NSR Parent Advisory Panel. Parents completed surveys at discharge; 12, 18, and 24 months; and 3, 4, 5, 7, and 8 years. Surveys included demographic information and open-ended questions targeting parent experience. A conventional content analysis approach was used. A total of 320 caregivers completed at least one open-ended question, with the majority of respondents at discharge (n = 142), 12 months (n = 169), 18 months (n = 208), and 24 months (n = 245). We identified the following three primary themes. (1) Personal Burden of Care: Parents experienced emotional distress, financial strain, physical demands, and fears for their child''s unknown outcome; (2) Managing Day-to-Day Life: Parents described difficulties navigating their parenting role, including managing their child''s challenging behaviors and understanding their child''s needs amid neurodevelopmental impairment; (3) My Joys as a Parent: Parents valued bonding with their child, being a caregiver, and watching their child''s personality grow. Parents of children impacted by neonatal seizures face persistent challenges, which are interwoven with the joys of being a parent. Our findings suggest that future interventions should promote resiliency, address caregivers'' psychosocial needs longitudinally, and provide enhanced support for parents caring for children with medical complexity.', 'article', ARRAY['Neonatal','Seizures'], ARRAY['neonatal seizures','parent experience','longitudinal','qualitative'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-54', 'Neonatal Seizures: New Evidence, Classification, and Guidelines', ARRAY['Ziobro J','Pilon B','Wusthoff CJ','Benedetti GM','Massey SL','Yozawitz E','Numis AL','Pressler R','Shellhaas RA'], 'Epilepsy Curr', 2024, 5, '10.1177/15357597241253382', '39554267', 'PMC11562284', 'Neonates are susceptible to seizures due to their unique physiology and combination of risks associated with gestation, delivery, and the immediate postnatal period. Advances in neonatal care have improved outcomes for some of our most fragile patients, but there are persistent challenges for epileptologists in identifying neonatal seizures, diagnosing etiologies, and providing the most appropriate care, with an ultimate goal to maximize patient outcomes. In just the last few years, there have been critical advances in the state of the science, as well as new evidence-based guidelines for diagnosis, classification, and treatment of neonatal seizures. This review will provide updated knowledge about the pathophysiology of neonatal seizures, classification of the provoked seizures and neonatal epilepsies, state of the art guidance on EEG monitoring in the neonatal ICU, current treatment guidelines for neonatal seizures, and potential for future advancement in treatment.', 'review', ARRAY['Neonatal','Seizures','Review'], ARRAY['neonatal seizures','classification','guidelines','evidence'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-55', 'Sleep Disorders Five Years After Acute Provoked Neonatal Seizures', ARRAY['Shellhaas RA','Franck LS','Pilon B','Wusthoff CJ','Massey SL','Chu CJ','Soul JS','Lemmon ME','Numis AL','Sturza JS','Thomas C','Benedetti GM','Rau SMD','Anwar T','Berl MM','McCulloch CE','Glass HC'], 'J Pediatr', 2024, 11, '10.1016/j.jpeds.2024.114412', '39557387', 'PMC12377511', 'To evaluate whether abnormal sleep is associated with adverse outcomes for children who survived acute provoked neonatal seizures, and their parents. This 9-center study prospectively followed newborns with acute provoked seizures. When children reached age 5 years, parents completed the Children''s Sleep Habits Questionnaire (CSHQ), the Pediatric Sleep Questionnaire-Sleep Related Breathing Disorders (PSQ-SRBD) subscale, the Vineland Adaptive Behavior Scales-3, and the Hospital Anxiety Depression Scale. Children were also assessed with the Wechsler Preschool and Primary Scale of Intelligence-IV (WPPSI-IV). Spearman correlations and multivariable analyses were used to evaluate risk factors for sleep problems. The mean CSHQ score was 45 &#xb1; 7; 77 of 118 children (65%) had an abnormal score (above the healthy sleep threshold of 41). On the PSQ-SRBD, 32 of 119 children (27%) screened positive for sleep-disordered breathing (SDB). SDB symptoms were more common among children with cerebral palsy (42% with vs 22% without; P = .03) and epilepsy (54% with vs 24% without; P = .02). Children with lower scores on the Vineland-3 (rho = -0.25; P = .01) and WPPSI-IV (rho = -0.31; P = .004) at 5 years of age were more likely to have symptoms of SDB. Worse CSHQ and PSQ-SRBD scores were associated with higher parental anxiety (rho = 0.28 [P = .002] and rho = 0.34 [P = .0002], respectively) and depression scores on the Hospital Anxiety Depression Scale (rho = 0.16 [P = .08] and rho = 0.17 [P = .07], respectively). Two-thirds of early school-aged survivors of acute provoked neonatal seizures had parent-reported sleep abnormalities and one-quarter screened positive for SDB. Early screening and effective treatment for sleep disorders could be an innovative, practice-changing approach to improve outcomes after neonatal seizures.', 'article', ARRAY['Neonatal','Sleep','Seizures'], ARRAY['neonatal seizures','sleep disorders','long-term outcomes'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-56', 'Neonatal Seizures and Associated Neurobehavioral Profiles in Preschool Age Children', ARRAY['Mattes AM','Shellhaas RA','Glass HC','Sturza J','Rau S','Lemmon M','Rogers EE','Numis A','Soul JS','Berl M','Wusthoff CJ','Chu CJ','Massey SL','Thomas C','Franck LS','McCulloch CE','Benedetti GM','Means J','Means K','Anwar T','Gidley Larson JC'], 'Pediatr Neurol', 2024, 11, '10.1016/j.pediatrneurol.2024.11.008', '39708432', NULL, 'Neonatal seizures are common with acute brain injury. Up to 25% of survivors develop postneonatal epilepsy. We hypothesized postneonatal epilepsy diagnosed by age 24 months would increase risk for early markers of neurobehavioral disorders than acute provoked neonatal seizures alone. Neonates with acute provoked seizures born from July 2015 to March 2018 were enrolled at nine Neonatal Seizure Registry sites. Composite scores from parent-completed standardized ratings assessed Adaptive, Social, Externalizing, Internalizing, Self-Regulation, and Sensory Seeking domains. Linear regression demonstrated relationships between composite scores for children who developed postneonatal epilepsy compared with those who did not. Results were adjusted for seizure etiology, sex, gestational age, and cerebral palsy (CP) severity. A total of 151 children (n = 20, 13% with postneonatal epilepsy), 4.1 years median age, participated. Children with epilepsy had impaired adaptive (Cohen d = 1.62, P < 0.0001), social (Cohen d = 0.86, P = 0.004), and executive functioning (Cohen d = 0.56, P = 0.06) compared with children without epilepsy. Mean scores for children without epilepsy were within average range. Risk for impairment among children with epilepsy persisted after adjusting for neonatal seizure etiology, sex, and gestational age, but not when adjusting for CP severity. There was higher incidence of adverse neurobehavioral outcomes among preschool children diagnosed with postneonatal epilepsy compared with those without epilepsy. CP severity was associated with greater impairment; results also suggest that epilepsy is an independent predictor of adaptive functioning. Children with postneonatal epilepsy should be screened for neurobehavioral problems to facilitate early identification and developmental support.', 'article', ARRAY['Neonatal','Seizures','Neurodevelopment'], ARRAY['neonatal seizures','neurobehavioral','preschool','epilepsy'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-57', 'Preferred Parental Language and Neurodevelopmental Outcomes Among Infants With Acute Provoked Neonatal Seizures in the United States', ARRAY['Peng GS','Halsey K','Wusthoff CJ','Chu CJ','Massey SL','Lemmon ME','Thomas C','Numis AL','Benedetti GM','Sturza J','Rogers EE','Franck LS','McCulloch CE','Soul JS','Shellhaas RA','Bonifacio SL','Glass HC'], 'Pediatr Neurol', 2024, 12, '10.1016/j.pediatrneurol.2024.12.010', '39889456', NULL, 'Parental non-English language preference (NELP) is associated with worse pediatric health outcomes. However, little is known about its relationship with developmental outcomes in infants with neonatal seizures. This study evaluated the relationship between parental NELP and neurodevelopment in a multicenter cohort of infants with neonatal seizures. Infants in the Neonatal Seizure Registry-II were included. Parental NELP was defined by the use of a professional interpreter for research consent and survey completion. The Warner Initial Developmental Evaluation of Adaptive and Functional Skills (WIDEA-FS) assessment was conducted at age 24 months. Multivariate regression was used to examine the association between parental NELP and WIDEA-FS. Functional developmental impairment was defined as a WIDEA-FS score 2 S.D.s below the normative mean. Among 270 infants with neonatal seizures, 15 (6%) had parental NELP. Children with parental NELP had a WIDEA-FS score that was on average 13 points lower than that of infants without parental NELP (95% confidence interval [CI]: -27 to 1, P = 0.08) and over five times the odds of functional developmental impairment (odds ratio 4.9, 95% CI: 1.3 to 18.4, P = 0.017). Children with parental NELP were more likely to have functional developmental impairment at age 24 months when compared with children without parental NELP. Since parental NELP does not have a biologically plausible impact on neurodevelopment it likely reflects discriminatory experiences that affect developmental opportunities. These findings highlight the importance of identifying social drivers to decrease potential gaps in neurodevelopmental attainment for children with parental NELP.', 'article', ARRAY['Neonatal','Seizures','Neurodevelopment'], ARRAY['language preference','neurodevelopmental outcomes','neonatal seizures','health disparities'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-58', 'Parent and Family Well-Being and Associated Risk Factors as Children with Neonatal Seizures Reach Preschool and School-Age: A Longitudinal Cohort Study', ARRAY['Franck LS','Lemmon ME','Grossbauer L','Pawlowski K','Sturza JS','Wusthoff CJ','Massey SL','Chu CJ','Soul JS','Numis AL','Thomas C','Benedetti GM','Anwar T','Berl MM','Gidley Larson JC','Rogers EE','Chen C','McCulloch CE','Glass HC','Shellhaas RA'], 'J Pediatr Clin Pract', 2025, 5, '10.1016/j.jpedcp.2025.200149', '40510235', 'PMC12159880', 'To assess parent/family well-being when children with neonatal seizures reach 3-8 years of age and examine factors associated with parent/family well-being. One parent per surviving infant in the Neonatal Seizure Registry-II was invited to complete validated surveys annually when children were between 3 and 8 years of age. Three outcomes were examined: (1) parent well-being (anxiety, depression, and quality of life); (2) parent post-traumatic stress symptoms; and (3) impact on the family. We used mixed model regression with random intercepts and guided backward elimination and included potential predictors that had bivariate associations< .10 in the multivariable analyses. Among 169 parents, 8%-35% experienced symptoms of anxiety, depression, or post-traumatic stress. When children were 8 years of age, about 1 in 3 parents had moderate to severe anxiety symptoms, approximately double the general population, 1 in 5 had post-traumatic stress disorder symptoms and depression symptom frequency was similar to the general population in the final models, only child social communication impairment was associated with poorer parental well-being or post-traumatic stress symptoms. Several child factors, including age at discharge from the neonatal admission, functional impairment at 24 months, social communication impairment, and receiving special services, were associated with greater impact on the family. Child social and functional health challenges following neonatal seizures were associated with poorer parent and family well-being across the preschool and early school years. Longitudinal screening of child social functioning, parent well-being, and family function is indicated for early detection and referral to treatment services. Clinical Trial Registration:NCT04337697.', 'article', ARRAY['Neonatal','Seizures'], ARRAY['family well-being','neonatal seizures','parent','longitudinal'], 'Neonatal', TRUE, ARRAY['giulia-benedetti'])
ON CONFLICT (id) DO NOTHING;

