INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-64', 'Near-infrared spectroscopy to define cognitive frontal lobe functions', ARRAY['Jayakar A','Dunoyer C','Rey G','Yaylali I','Jayakar P'], 'J Clin Neurophysiol', 2005, 12, '10.1097/01.WNP.0000172257.47840.17', '16462198', NULL, 'Near-infrared spectroscopy (NIRS) monitors changes in the regional cerebral oxygenation (rSO) and has been used to study cerebral physiologic functions in normal states and during epileptic seizures. Yet, the limitations and pitfalls of the technique are not fully understood. The authors evaluated NIRS changes over the frontal lobes during language tasks known to be associated with the integrity of the dominant frontal lobe in 17 normal adults (handedness: 14 right, 3 left). Recording protocol involved a baseline (3 minutes) with the subject relaxed and thinking of a blue sky and a second baseline during voluntary mouth movements mimicking speech. Two standardized neuropsychological word-generation tasks (controlled word-association tests: CFL and Animals) were then administered (4 minutes total) followed again by the two baseline procedures. These findings corroborate the usefulness of NIRS to demonstrate focal cerebral activation during an executive language task. However, interpretation of changes can be confounded by extracerebral factors such as mouth movement, a finding of particular relevance in NIRS clinical applications.', 'article', ARRAY['Cardiac Arrest','Seizures','Neuromonitoring'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-65', 'Pediatric epilepsy surgery', ARRAY['Jayakar A','Bolton J'], 'Curr Neurol Neurosci Rep', 2015, 6, '10.1007/s11910-015-0558-9', '25893723', NULL, 'Medically refractory epilepsy is a significant cause of morbidity and mortality in pediatric neurology. Surgical intervention has been well established as a viable treatment option in certain cases. This article reviews the process of selecting appropriate patients using the latest advances in neuroimaging and electrophysiologic techniques. It also discusses the various surgical techniques currently available, including recent advances in minimally invasive approaches.', 'review', ARRAY['Review','Epilepsy','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-66', 'Data integration: Combined imaging and electrophysiology data in the cloud', ARRAY['Kini LG','Davis KA','Wagenaar JB'], 'Neuroimage', 2015, 6, '10.1016/j.neuroimage.2015.05.075', '26044858', 'PMC4651831', 'There has been an increasing effort to correlate electrophysiology data with imaging in patients with refractory epilepsy over recent years. IEEG.org provides a free-access, rapidly growing archive of imaging data combined with electrophysiology data and patient metadata. It currently contains over 1200 human and animal datasets, with multiple data modalities associated with each dataset (neuroimaging, EEG, EKG, de-identified clinical and experimental data, etc.).', 'article', ARRAY['EEG','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-67', 'Forecasting Seizures Using Intracranial EEG Measures and SVM in Naturally Occurring Canine Epilepsy', ARRAY['Brinkmann BH','Patterson EE','Vite C','Vasoli VM','Crepeau D','Stead M','Howbert JJ','Cherkassky V','Wagenaar JB','Litt B','Worrell GA'], 'PLoS One', 2015, 8, '10.1371/journal.pone.0133900', '26241907', 'PMC4524640', 'Management of drug resistant focal epilepsy would be greatly assisted by a reliable warning system capable of alerting patients prior to seizures to allow the patient to adjust activities or medication. Such a system requires successful identification of a preictal, or seizure-prone state. We show that the optimization of feature selection varies for each subject, i.e. algorithms are subject specific, but achieve prediction performance significantly better than a time-matched Poisson random predictor in 5/5 dogs analyzed.', 'article', ARRAY['EEG','Seizures','Machine Learning','Pharmacology','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-68', 'Millimeter-scale epileptiform spike propagation patterns and their relationship to seizures', ARRAY['Vanleer AC','Blanco JA','Wagenaar JB','Viventi J','Contreras D','Litt B'], 'J Neural Eng', 2016, 2, '10.1088/1741-2560/13/2/026015', '26859260', 'PMC4807853', 'Current mapping of epileptic networks in patients prior to epilepsy surgery utilizes electrode arrays with sparse spatial sampling. Recent research demonstrates that sub-millimeter, cortical-column-scale domains have a role in seizure generation that may be clinically significant. We showed that spatially correlated events can be used to distinguish ictal versus interictal spikes. We conclude that sub-millimeter-scale spatiotemporal spike patterns reveal network dynamics that are invisible to standard clinical recordings and contain information related to seizure-state.', 'article', ARRAY['EEG','Seizures'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-69', 'Rapid Increases in proBDNF after Pilocarpine-Induced Status Epilepticus in Mice Are Associated with Reduced proBDNF Cleavage Machinery', ARRAY['Thomas AX','Cruz Del Angel Y','Gonzalez MI','Carrel AJ','Carlsen J','Lam PM','Hempstead BL','Russek SJ','Brooks-Kayal AR'], 'eNeuro', 2016, 3, '10.1523/ENEURO.0020-15.2016', '27057559', 'PMC4814566', 'Brain-derived neurotrophic factor (BDNF) levels are elevated after status epilepticus (SE), leading to activation of multiple signaling pathways. These findings suggest that rapid proBDNF increases following SE are due in part to reduced cleavage, and that proBDNF may be part of the initial neurotrophin response driving intracellular signaling during the acute phase of epileptogenesis.', 'article', ARRAY['Status Epilepticus'], ARRAY['bdnf','pai-1','probdnf','cleavage','epilepsy','tpa'], 'Pediatric', TRUE, ARRAY['ajay-thomas'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-70', 'Correction: Forecasting Seizures Using Bivariate Intracranial EEG Measures and SVM in Naturally Occurring Canine Epilepsy', ARRAY['Brinkmann BH','Patterson EE','Vite C','Vasoli VM','Crepeau D','Stead M','Howbert JJ','Cherkassky V','Wagenaar JB','Litt B','Worrell GA'], 'PLoS One', 2016, 5, '10.1371/journal.pone.0156476', '27227650', 'PMC4881954', '[This corrects the article DOI: 10.1371/journal.pone.0133900.].', 'article', ARRAY['EEG','Seizures','Machine Learning','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-71', 'Crowdsourcing seizure detection: algorithm development and validation on human implanted device recordings', ARRAY['Baldassano SN','Brinkmann BH','Ung H','Blevins T','Conrad EC','Leyde K','Cook MJ','Khambhati AN','Wagenaar JB','Worrell GA','Litt B'], 'Brain', 2017, 6, '10.1093/brain/awx098', '28459961', 'PMC6075622', 'There exist significant clinical and basic research needs for accurate, automated seizure detection algorithms. These algorithms have translational potential in responsive neurostimulation devices and in automatic parsing of continuous intracranial electroencephalography data. The top performing teams submitted highly accurate algorithms with consistent performance in the out-of-sample validation study.', 'article', ARRAY['EEG','Seizures'], ARRAY['crowdsourcing','epilepsy','experimental models','intracranial eeg','seizure detection'], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-72', 'The effect of increased intracranial EEG sampling rates in clinical practice', ARRAY['Davis KA','Devries SP','Krieger A','Mihaylova T','Minecan D','Litt B','Wagenaar JB','Stacey WC'], 'Clin Neurophysiol', 2017, 11, '10.1016/j.clinph.2017.10.039', '29288992', 'PMC5955774', 'Recent research suggests that high frequency intracranial EEG (iEEG) may improve localization of epileptic networks. This study aims to determine whether recording macroelectrode iEEG with higher sampling rates improves seizure localization in clinical practice. When utilizing standard clinical protocols, there was no benefit to acquiring iEEGs with sampling rate greater than 100 Hz.', 'article', ARRAY['EEG','Seizures'], ARRAY['high frequency','macroelectrode','seizure onset'], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-73', 'Diffusion-Weighted Imaging Changes in a Child With Posterior Ischemic Optic Neuropathy', ARRAY['Harrar DB','Solomon J','Shah AS','Vaughn J','Durbin AD','Rivkin MJ'], 'Pediatr Neurol', 2018, 4, '10.1016/j.pediatrneurol.2018.03.014', '29859720', NULL, 'Posterior ischemic optic neuropathy results from ischemia of the retrobulbar aspect of the optic nerve. It presents as acute loss of vision without optic disc swelling. This is rare in children, with only seven cases reported to date. Posterior ischemic optic neuropathy should be considered in the differential diagnosis of any child presenting with acute loss of vision.', 'case_report', ARRAY['Stroke'], ARRAY['acute visual loss','diffusion-weighted imaging','posterior ischemic optic neuropathy','retinoblastoma'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-74', 'Epilepsy surgery near or in eloquent cortex in children-Practice patterns and recommendations for minimizing and reporting deficits', ARRAY['Jayakar P','Jayakar A','Libenson M','Arzimanoglou A','Rydenhag B','Cross JH','Bhatia S','Tassi L','Lachhwani D','Gaillard WD'], 'Epilepsia', 2018, 7, '10.1111/epi.14510', '30033517', NULL, 'We aimed to investigate the current practices guiding surgical resection strategies involving epileptogenic zones near or in eloquent cortex at pediatric epilepsy surgery centers worldwide. A survey was conducted among 40 respondents from 33 pediatric epilepsy surgery centers worldwide. A descriptive analysis was performed that revealed considerable variation in the use of diagnostic tests and resective strategies toward EZ and EC.', 'article', ARRAY['Survey','Epilepsy'], ARRAY['critical cortex','deficit scale','epilepsy surgery strategies','epileptogenic zone'], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-75', 'Conventional and quantitative EEG in status epilepticus', ARRAY['Sansevere AJ','Hahn CD','Abend NS'], 'Seizure', 2018, 10, '10.1016/j.seizure.2018.09.011', '30528098', NULL, 'To summarize the use of continuous electroencephalographic monitoring (cEEG) in the diagnosis and management of pediatric convulsive status epilepticus (CSE) and subsequent non-convulsive seizures (NCS) with a focus on available guidelines and infrastructure. The use of cEEG is important to the diagnosis and treatment of NCS or subtle clinical seizures after pediatric CSE. QEEG allows cEEG data to be reviewed and interpreted quickly and is a useful tool for detection of NCS after CSE.', 'review', ARRAY['qEEG','Status Epilepticus','Review'], ARRAY['convulsive status epilepticus','electroencephalography','pediatric','quantitative eeg','seizure','ceeg'], 'Pediatric', TRUE, ARRAY['arnold-sansevere','cecil-hahn','nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-76', 'Clinical Determination of Brain Death in Children Supported by Extracorporeal Membrane Oxygenation', ARRAY['Harrar DB','Kukreti V','Dean NP','Berger JT','Carpenter JL'], 'Neurocrit Care', 2019, 10, '10.1007/s12028-019-00700-z', '30891693', NULL, 'Children supported by extracorporeal membrane oxygenation (ECMO) are at risk of catastrophic neurologic injury and brain death. Clinical determination of brain death, including apnea testing, can be performed in pediatric patients supported by ECMO. The ECMO circuit can be effectively modified during apnea testing to achieve a timely rise in carbon dioxide while maintaining oxygenation and hemodynamic stability.', 'article', ARRAY['ECMO/ECLS','Neurocritical Care'], ARRAY['apnea test','brain death','extracorporeal membrane oxygenation'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-77', 'Hyperglycemia and Glucose Variability Are Associated with Worse Brain Function and Seizures in Neonatal Encephalopathy: A Prospective Cohort Study', ARRAY['Pinchefsky EF','Hahn CD','Kamino D','Chau V','Brant R','Moore AM','Tam EWY'], 'J Pediatr', 2019, 4, '10.1016/j.jpeds.2019.02.027', '30982528', NULL, 'To investigate how glucose abnormalities correlate with brain function on amplitude-integrated electroencephalography (aEEG) in infants with neonatal encephalopathy. In neonates with encephalopathy, epochs of hyperglycemia were temporally associated with worse global brain function and seizures, even after we adjusted for hypoxia-ischemia severity.', 'article', ARRAY['EEG','Neonatal','Seizures','Neurocritical Care'], ARRAY['amplitude-integrated electroencephalography','glucose derangements','hypoglycemia'], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
