VALUES ('pub-78', 'Course and Outcome of Children with Convulsive Status Epilepticus Admitted to a Pediatric Intensive Care Unit', ARRAY['Chegondi M','Garland MM','Sendi P','Jayakar AR','Totapally BR'], 'Cureus', 2019, 4, '10.7759/cureus.4471', '31249749', 'PMC6579347', 'The objective of this study was to describe the course and the outcomes of children with convulsive status epilepticus and to evaluate the differences between two groups of children with new-onset seizures and known seizure disorders. Among 139 children with status epilepticus, 69.7% had a known seizure disorder.', 'article', ARRAY['Status Epilepticus','Outcomes'], ARRAY['children','outcome','pediatric intensive care unit','status epilepticus'], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
