INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-79', 'The onset of pediatric refractory status epilepticus is not distributed uniformly during the day', ARRAY['Sanchez Fernandez I','Gainza-Lein M','Abend NS','Amengual-Gual M','Anderson A','Arya R','Brenton JN','Carpenter JL','Chapman KE','Clark J','Farias-Moeller R','Davis Gaillard W','Glauser TA','Goldstein J','Goodkin HP','Guerriero RM','Hecox K','Jackson M','Kapur K','Kelley SA','Kossoff EHW','Lai YC','McDonough TL','Mikati MA','Morgan LA','Novotny EJ','Ostendorf AP','Payne ET','Peariso K','Piantino J','Riviello JJ','Sannagowdara K','Stafstrom CE','Tasker RC','Tchapyjnikov D','Topjian AA','Vasquez A','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Seizure', 2019, 6, '10.1016/j.seizure.2019.06.017', '31323566', NULL, 'To evaluate whether the onset of pediatric refractory status epilepticus (rSE) is related to time of day. The distribution of rSE onset is not uniform during the day. rSE onset shows a 24-h distribution with a peak in the mid-morning and a trough at night.', 'article', ARRAY['Status Epilepticus'], ARRAY['24-hour rhythms','chronobiology','epilepsy','pediatric','status epilepticus'], 'Pediatric', TRUE, ARRAY['nicholas-abend','raquel-farias-moeller','adam-ostendorf','james-riviello','tobias-loddenkemper'])
