INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-81', 'Electrographic seizure burden and outcomes following pediatric status epilepticus', ARRAY['Lalgudi Ganesan S','Hahn CD'], 'Epilepsy Behav', 2019, 8, '10.1016/j.yebeh.2019.07.010', '31420288', NULL, 'Pediatric status epilepticus carries a substantial risk for morbidity and mortality, but the relationship between seizure burden, treatment, and outcome remains incompletely understood. This review summarizes the evidence linking seizure burden and outcomes among critically ill children in the intensive care unit (ICU).', 'review', ARRAY['Status Epilepticus','EEG','Review','Outcomes'], ARRAY['child','critical illness','electroencephalography','outcome','seizures','status epilepticus'], 'Pediatric', TRUE, ARRAY['rishi-ganesan','cecil-hahn'])
