INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-82', 'Stroke After Cardiac Catheterization in Children', ARRAY['Harrar DB','Salussolia CL','Vittner P','Danehy A','Sen S','Whitehill R','Chao JH','Bernson-Leung ME','Rivkin MJ'], 'Pediatr Neurol', 2019, 7, '10.1016/j.pediatrneurol.2019.07.005', '31481331', NULL, 'Children with cardiac disease are at high risk for stroke. Approximately one-quarter of strokes in children with cardiac disease occur in the peri-procedural period. Twenty children had a new clinically-apparent post-catheterization arterial ischemic stroke.', 'article', ARRAY['Stroke'], ARRAY['cardiac catheterization','congenital heart disease','pediatric arterial ischemic stroke'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
