INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-84', 'A Stroke Alert Protocol Decreases the Time to Diagnosis of Brain Attack Symptoms in a Pediatric Emergency Department', ARRAY['Harrar DB','Salussolia CL','Kapur K','Danehy A','Kleinman ME','Mannix R','Rivkin MJ'], 'J Pediatr', 2019, 11, '10.1016/j.jpeds.2019.09.027', '31704052', NULL, 'To determine whether a stroke alert system decreases the time to diagnosis of children presenting to the emergency department (ED) with acute-onset focal neurologic deficits.

We performed a retrospective comparison of clinical and demographic information for patients who presented to the ED of a tertiary children''s hospital with acute-onset focal neurologic deficits during the 2.5 years before (n = 14) and after (n = 65) the implementation of a stroke alert system. The primary outcome was the median time to neuroimaging analyzed using a Wilcoxon rank-sum test.

The median time from ED arrival to neuroimaging for patients with acute-onset focal neurologic deficits decreased significantly after implementation of a stroke alert system (196 minutes; IQR, 85-230 minutes before [n = 14] vs 82 minutes; IQR, 54-123 minutes after [n = 65]; P < .01). Potential intravenous tissue plasminogen activator candidates experienced the shortest time to neuroimaging after implementation of a stroke alert system (54 minutes; IQR, 34-66 minutes [n = 13] for intravenous tissue plasminogen activator candidates vs 89.5 minutes; IQR, 62-126.5 minutes [n = 52] for non-intravenous tissue plasminogen activator candidates; P < .01).

A stroke alert system decreases the median time to diagnosis by neuroimaging of children presenting to the ED with acute-onset focal neurologic deficits by more than one-half. Such a protocol constitutes an important step in ensuring that a greater proportion of children with arterial ischemic stroke are diagnosed in a time frame that enables hyperacute treatment.', 'article', ARRAY['Stroke','Outcomes'], ARRAY['acute-onset focal neurologic deficit','intravenous tissue plasminogen activator (iv-tpa)','mechanical thrombectomy','pediatric arterial ischemic stroke','pediatric code stroke','pediatric stroke','pediatric stroke stat'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-85', 'Neonatal seizures: Case definition & guidelines for data collection, analysis, and presentation of immunization safety data', ARRAY['Pellegrin S','Munoz FM','Padula M','Heath PT','Meller L','Top K','Wilmshurst J','Wiznitzer M','Das MK','Hahn CD','Kucuku M','Oleske J','Vinayan KP','Yozawitz E','Aneja S','Bhat N','Boylan G','Sesay S','Shrestha A','Soul JS','Tagbo B','Joshi J','Soe A','Maltezou HC','Gidudu J','Kochhar S','Pressler RM'], 'Vaccine', 2019, 12, '10.1016/j.vaccine.2019.05.031', '31783981', 'PMC6899436', NULL, 'review', ARRAY['Neonatal','Seizures','Review'], ARRAY['adverse event','case definition','guidelines','immunization','neonatal seizures'], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-86', 'IRIS: A Modular Platform for Continuous Monitoring and Caretaker Notification in the Intensive Care Unit', ARRAY['Baldassano SN','Roberson SW','Balu R','Scheid B','Bernabei JM','Pathmanathan J','Oommen B','Leri D','Echauz J','Gelfand M','Bhalla PK','Hill CE','Christini A','Wagenaar JB','Litt B'], 'IEEE J Biomed Health Inform', 2020, 1, '10.1109/JBHI.2020.2965858', '31940568', 'PMC7485608', 'New approaches are needed to interpret large amounts of physiologic data continuously recorded in the ICU. We developed and prospectively validated a versatile platform (IRIS) for real-time ICU physiologic monitoring, clinical decision making, and caretaker notification.

IRIS was implemented in the neurointensive care unit to stream multimodal time series data, including EEG, intracranial pressure (ICP), and brain tissue oxygenation (PO), from ICU monitors to an analysis server. IRIS was applied for 364 patients undergoing continuous EEG, 26 patients undergoing burst suppression monitoring, and four patients undergoing intracranial pressure and brain tissue oxygen monitoring. Custom algorithms were used to identify periods of elevated ICP, compute burst suppression ratios (BSRs), and detect faulty or disconnected EEG electrodes. Hospital staff were notified of clinically relevant events using our secure API to route alerts through a password-protected smartphone application.

Sustained increases in ICP and concordant decreases in POwere reliably detected using user-defined thresholds and alert throttling. BSR trends computed by the platform correlated highly with manual neurologist markings (r 0.633-0.781; p < 0.0001). The platform identified EEG electrodes with poor signal quality with 95% positive predictive value, and reduced latency of technician response by 93%.

This study validates a flexible real-time platform for monitoring and interpreting ICU data and notifying caretakers of actionable results, with potential to reduce the manual burden of continuous monitoring services on care providers.

This work represents an important step toward facilitating translational medical data analytics to improve patient care and reduce health care costs.', 'article', ARRAY['Neurocritical Care','EEG','Biomarkers'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-87', 'Seizure Detection Algorithms in Critically Ill Children: A Comparative Evaluation', ARRAY['Din F','Lalgudi Ganesan S','Akiyama T','Stewart CP','Ochi A','Otsubo H','Go C','Hahn CD'], 'Crit Care Med', 2020, 4, '10.1097/CCM.0000000000004180', '32205601', NULL, 'To evaluate the performance of commercially available seizure detection algorithms in critically ill children.

Diagnostic accuracy comparison between commercially available seizure detection algorithms referenced to electroencephalography experts using quantitative electroencephalography trends.

Multispecialty quaternary children''s hospital in Canada.

Critically ill children undergoing electroencephalography monitoring.

Continuous raw electroencephalography recordings (n = 19) were analyzed by a neurophysiologist to identify seizures. Those recordings were then converted to quantitative electroencephalography displays (amplitude-integrated electroencephalography and color density spectral array) and evaluated by six independent electroencephalography experts to determine the sensitivity and specificity of the amplitude-integrated electroencephalography and color density spectral array displays for seizure identification in comparison to expert interpretation of raw electroencephalography data. Those evaluations were then compared with four commercial seizure detection algorithms: ICTA-S (Stellate Harmonie Version 7; Natus Medical, San Carlos, CA), NB (Stellate Harmonie Version 7; Natus Medical), Persyst 11 (Persyst Development, Prescott, AZ), and Persyst 13 (Persyst Development) to determine sensitivity and specificity in comparison to amplitude-integrated electroencephalography and color density spectral array.

Of the 379 seizures identified on raw electroencephalography, ICTA-S detected 36.9%, NB detected 92.3%, Persyst 11 detected 75.9%, and Persyst 13 detected 74.4%, whereas electroencephalography experts identified 76.5% of seizures using color density spectral array and 73.7% using amplitude-integrated electroencephalography. Daily false-positive rates averaged across all recordings were 4.7 with ICTA-S, 126.3 with NB, 5.1 with Persyst 11, 15.5 with Persyst 13, 1.7 with color density spectral array, and 1.5 with amplitude-integrated electroencephalography. Both Persyst 11 and Persyst 13 had sensitivity comparable to that of electroencephalography experts using amplitude-integrated electroencephalography and color density spectral array. Although Persyst 13 displayed the highest sensitivity for seizure count and seizure burden detected, Persyst 11 exhibited the best trade-off between sensitivity and false-positive rate among all seizure detection algorithms.

Some commercially available seizure detection algorithms demonstrate performance for seizure detection that is comparable to that of electroencephalography experts using quantitative electroencephalography displays. These algorithms may have utility as early warning systems that prompt review of quantitative electroencephalography or raw electroencephalography tracings, potentially leading to more timely seizure identification in critically ill patients.', 'article', ARRAY['EEG','Seizures'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['rishi-ganesan','cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-88', 'Too Much of a Good Thing? Cerebral Sinovenous Thrombosis Due to Excessive Milk Intake Associated Anemia', ARRAY['Farias-Moeller R','Siddiqui S','Orr M','Mondok L'], 'J Child Neurol', 2020, 5, '10.1177/0883073820923807', '32429785', NULL, 'In young children, excessive cow''s milk intake causes iron-deficiency anemia, which is associated with hypercoagulable states. We present a case series of 4 toddlers with excessive milk intake iron-deficiency anemia and cerebral sinovenous thrombosis.

Retrospective chart review of 4 patients was performed for patients with cerebral sinovenous thrombosis and iron-deficiency anemia secondary to excessive milk intake. Iron-deficiency anemia was defined as hemoglobin <11 mg/dL, mean corpuscular volume <70 fL, and serum ferritin <12 μg/L. Excessive milk intake was defined as consumption of >24 oz daily. Clinical, laboratory, and radiographic features were reviewed.

Age ranged from 12 to 24 months. Average hemoglobin, hematocrit, mean corpuscular volume, and ferritin levels were 6.1 g/dL, 22.7 g/dL, 52.7 fL, and 3.2 ng/mL, respectively. Daily milk consumption ranged from 40 to 60 oz. All patients presented with focal neurologic deficits, including seizures in 3. The location of cerebral sinovenous thrombosis varied, and 3 patients had venous infarcts, one of them hemorrhagic. All patients had a limited diet and were described as "picky eaters" by their parents, and only 1 had transitioned of a bottle. All patients were treated with anticoagulation, iron supplementation, and extensive dietary counseling to reduce cow''s milk intake.

Iron-deficiency anemia due to excessive milk intake is an important and preventable etiology of pediatric cerebral sinovenous thrombosis. Focused anticipatory guidance is necessary for at-risk groups to prevent this neurologic emergency.', 'article', ARRAY['Seizures','Stroke'], ARRAY['headache','neuroimaging','ophthalmology','pediatric','stroke'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-89', 'Epilepsy and Electroencephalographic Abnormalities in SATB2-Associated Syndrome', ARRAY['Lewis H','Samanta D','&#xd6;rsell JL','Bosanko KA','Rowell A','Jones M','Dale RC','Taravath S','Hahn CD','Krishnakumar D','Chagnon S','Keller S','Hagebeuk E','Pathak S','Bebin EM','Arndt DH','Alexander JJ','Mainali G','Coppola G','Maclean J','Sparagana S','McNamara N','Smith DM','Raggio V','Cruz M','Fern&#xe1;ndez-Ja&#xe9;n A','Kava MP','Emrick L','Fish JL','Vanderver A','Helman G','Pierson TM','Zarate YA'], 'Pediatr Neurol', 2020, 4, '10.1016/j.pediatrneurol.2020.04.006', '32446642', 'PMC11348677', 'Seizures are an under-reported feature of the SATB2-associated syndrome phenotype. We describe the electroencephalographic findings and seizure semiology and treatment in a population of individuals with SATB2-associated syndrome.

We performed a retrospective review of 101 individuals with SATB2-associated syndrome who were reported to have had a previous electroencephalographic study to identify those who had at least one reported abnormal result. For completeness, a supplemental survey was distributed to the caregivers and input from the treating neurologist was obtained whenever possible.

Forty-one subjects were identified as having at least one prior abnormal electroencephalography. Thirty-eight individuals (93%) had epileptiform discharges, 28 (74%) with central localization. Sleep stages were included as part of the electroencephalographies performed in 31 individuals (76%), and epileptiform activity was recorded during sleep in all instances (100%). Definite clinical seizures were diagnosed in 17 individuals (42%) with a mean age of onset of 3.2 years (four months to six years), and focal seizures were the most common type of seizure observed (42%). Six subjects with definite clinical seizures needed polytherapy (35%). Delayed myelination and/or abnormal white matter hyperintensities were seen on neuroimaging in 19 individuals (61%).

Epileptiform abnormalities are commonly seen in individuals with SATB2-associated syndrome. A baseline electroencephalography that preferably includes sleep stages is recommended during the initial evaluation of all individuals with SATB2-associated syndrome, regardless of clinical suspicion of epilepsy.', 'article', ARRAY['EEG','Seizures','Survey','Neurocritical Care','Epilepsy'], ARRAY['electroencephalography','epilepsy','glass syndrome','satb2','seizure semiology'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-90', 'Association of guideline publication and delays to treatment in pediatric status epilepticus', ARRAY['S&#xe1;nchez Fern&#xe1;ndez I','Abend NS','Amengual-Gual M','Anderson A','Arya R','Barcia Aguilar C','Brenton JN','Carpenter JL','Chapman KE','Clark J','Farias-Moeller R','Gaillard WD','Ga&#xed;nza-Lein M','Glauser T','Goldstein J','Goodkin HP','Guerriero RM','Lai YC','McDonough T','Mikati MA','Morgan LA','Novotny E','Payne E','Peariso K','Piantino J','Ostendorf A','Sands TT','Sannagowdara K','Tasker RC','Tchapyjnikov D','Topjian AA','Vasquez A','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Neurology', 2020, 7, '10.1212/WNL.0000000000010174', '32611646', 'PMC7538224', 'To determine whether publication of evidence on delays in time to treatment shortens time to treatment in pediatric refractory convulsive status epilepticus (rSE), we compared time to treatment before (2011-2014) and after (2015-2019) publication of evidence of delays in treatment of rSE in the Pediatric Status Epilepticus Research Group (pSERG) as assessed by patient interviews and record review.

We performed a retrospective analysis of a prospectively collected dataset from June 2011 to September 2019 on pediatric patients (1 month-21 years of age) with rSE.

We studied 328 patients (56% male) with median (25th-75th percentile [p-p]) age of 3.8 (1.3-9.4) years. There were no differences in the median (p-p) time to first benzodiazepine (BZD) (20 [5-52.5] vs 15 [5-38] minutes,= 0.3919), time to first non-BZD antiseizure medication (68 [34.5-163.5] vs 65 [33-142] minutes,= 0.7328), and time to first continuous infusion (186 [124.2-571] vs 160 [89.5-495] minutes,= 0.2236). Among 157 patients with out-of-hospital onset whose time to hospital arrival was available, the proportion who received at least 1 BZD before hospital arrival increased after publication of evidence of delays (41 of 81 [50.6%] vs 57 of 76 [75%],= 0.0018), and the odds ratio (OR) was also increased in multivariable logistic regression (OR 4.35 [95% confidence interval 1.96-10.3],= 0.0005).

Publication of evidence on delays in time to treatment was not associated with improvements in time to treatment of rSE, although it was associated with an increase in the proportion of patients who received at least 1 BZD before hospital arrival.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend','raquel-farias-moeller','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-91', 'Educational initiatives and implementation of electroencephalography into the acute care environment: a protocol of a systematic review', ARRAY['Taran S','Ahmed W','Bui E','Prisco L','Hahn CD','McCredie VA'], 'Syst Rev', 2020, 8, '10.1186/s13643-020-01439-x', '32778151', 'PMC7418425', 'Use of electroencephalography (EEG) is currently recommended by the American Clinical Neurophysiology Society for a wide range of indications, including diagnosis of nonconvulsive status epilepticus and evaluation of unexplained disorders of consciousness. Data interpretation usually occurs by expert personnel (e.g., epileptologists, neurophysiologists), with information relayed to the primary care team. However, data cannot always be read in time-sensitive fashion, leading to potential delays in EEG interpretation and patient management. Multiple training programs have recently been described to enable non-experts to rapidly interpret EEG at the bedside. A comprehensive review of these training programs, including the tools used, outcomes obtained, and potential pitfalls, is currently lacking. Therefore, the optimum training program and implementation strategy remain unknown.

We will conduct a systematic review of descriptive studies, case series, cohort studies, and randomized controlled trials assessing training programs for EEG interpretation by non-experts. Our primary objective is to comprehensively review educational programs in this domain and report their structure, patterns of implementation, limitations, and trainee feedback. Our secondary objective will be to compare the performance of non-experts for EEG interpretation with a gold standard (e.g., interpretation by a certified electroencephalographers). Studies will be limited to those performed in acute care settings in both adult and pediatric populations (intensive care unit, emergency department, or post-anesthesia care units). Comprehensive search strategies will be developed for MEDLINE, EMBASE, WoS, CINAHL, and CENTRAL to identify studies for review. The gray literature will be scanned for further eligible studies. Two reviewers will independently screen the search results to identify studies for inclusion. A standardized data extraction form will be used to collect important data from each study. If possible, we will attempt to meta-analyze the quantitative data. If heterogeneity between studies is too high, we will present meaningful quantitative comparisons of secondary outcomes as per the synthesis without meta-analysis (SWiM) reporting guidelines.

We will aim to summarize the current literature in this domain to understand the structure, patterns, and pitfalls of EEG training programs for non-experts. This review is undertaken with a view to inform future education designs, potentially enabling rapid detection of EEG abnormalities, and timely intervention by the treating physician.

Submitted and undergoing review. Registration ID: CRD42020171208 .', 'article', ARRAY['Status Epilepticus','EEG','Education','Outcomes'], ARRAY['critical care','eeg','education','electroencephalography','instruction','qeeg','teaching program'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-92', 'First-line medication dosing in pediatric refractory status epilepticus', ARRAY['Vasquez A','Ga&#xed;nza-Lein M','Abend NS','Amengual-Gual M','Anderson A','Arya R','Brenton JN','Carpenter JL','Chapman K','Clark J','Farias-Moeller R','Gaillard WD','Glauser T','Goldstein JL','Goodkin HP','Guerriero RM','Kapur K','Lai YC','McDonough TL','Mikati MA','Morgan LA','Novotny EJ','Ostendorf AP','Payne ET','Peariso K','Piantino J','Riviello JJ','Sannagowdara K','Tasker RC','Tchapyjnikov D','Topjian A','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Neurology', 2020, 9, '10.1212/WNL.0000000000010828', '32913024', 'PMC7713738', 'To identify factors associated with low benzodiazepine (BZD) dosing in patients with refractory status epilepticus (RSE) and to assess the impact of BZD treatment variability on seizure cessation.

This was a retrospective study with prospectively collected data of children with convulsive RSE admitted between June 2011 and January 2019. We analyzed the initial and total BZD dose within 10 minutes of treatment initiation. We used logistic regression modeling to evaluate predictors of low BZD dosing and multivariate Cox regression analysis to assess the impact of low BZD dosing on time to seizure cessation.

We included 289 patients (55.7% male) with a median age of 4.3 (1.3-9.5) years. BZDs were the initial medication in 278 (96.2%). Of those, 161 patients (57.9%) received a low initial dose. Low initial BZD doses occurred in both out-of-hospital (57 of 106; 53.8%) and in-hospital (104 of 172; 60.5%) settings. One hundred three patients (37.1%) received low total BZD dose. Male sex (odds ratio [OR] 2, 95% confidence interval [CI] 1.18-3.49;= 0.012), older age (OR 1.1, 95% CI 1.05-1.17;< 0.001), no prior diagnosis of epilepsy (OR 2.1, 95% CI 1.23-3.69;= 0.008), and delayed BZD treatment (OR 2.2, 95% CI 1.24-3.94;= 0.007) were associated with low total BZD dose. Patients who received low total BZD dosing were less likely to achieve seizure cessation (hazard ratio 0.7, 95% CI 0.57-0.95).

BZD doses were lower than recommended in both out-of-hospital and in-hospital settings. Factors associated with low total BZD dose included male sex, older age, no prior epilepsy diagnosis, and delayed BZD treatment. Low total BZD dosing was associated with decreased likelihood of Seizure cessation.

This study provides Class III evidence that patients with RSE who present with male sex, older age, no prior diagnosis of epilepsy, and delayed BZD treatment are more likely to receive low total BZD doses. This study provides Class III evidence that in pediatric RSE low total BZD dose decreases the likelihood of seizure cessation.', 'article', ARRAY['Status Epilepticus','Pharmacology','Biomarkers'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend','raquel-farias-moeller','adam-ostendorf','james-riviello','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-93', 'American Clinical Neurophysiology Society''s Standardized Critical Care EEG Terminology: 2021 Version', ARRAY['Hirsch LJ','Fong MWK','Leitinger M','LaRoche SM','Beniczky S','Abend NS','Lee JW','Wusthoff CJ','Hahn CD','Westover MB','Gerard EE','Herman ST','Haider HA','Osman G','Rodriguez-Ruiz A','Maciel CB','Gilmore EJ','Fernandez A','Rosenthal ES','Claassen J','Husain AM','Yoo JY','So EL','Kaplan PW','Nuwer MR','van Putten M','Sutter R','Drislane FW','Trinka E','Gaspard N'], 'J Clin Neurophysiol', 2021, 1, '10.1097/WNP.0000000000000806', '33475321', 'PMC8135051', NULL, 'article', ARRAY['EEG'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend','cecil-hahn'])
