INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-94', 'Emergency management of the paediatric patient with convulsive status epilepticus', ARRAY['McKenzie KC','Hahn CD','Friedman JN'], 'Paediatr Child Health', 2021, 1, '10.1093/pch/pxaa127', '33552322', 'PMC7850284', 'This guideline addresses the emergency management of convulsive status epilepticus (CSE) in children and infants older than 1 month of age. It replaces a previous position statement from 2011, and includes a new treatment algorithm and table of recommended medications based on new evidence and reflecting the evolution of clinical practice over the past several years. This statement emphasizes the importance of timely pharmacological management of CSE, and includes some guidance for diagnostic approach and supportive care.', 'review', ARRAY['Status Epilepticus','Review','Pharmacology'], ARRAY['convulsions','emergency management','paediatrics','seizures','status epilepticus'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-95', 'Prevalence, Risk Factors, and Impact of Preoperative Seizures in Neonates With Congenital Heart Disease', ARRAY['Pittet MP','Marini D','Ly L','Au-Young SH','Chau V','Seed M','Miller SP','Hahn CD'], 'J Clin Neurophysiol', 2021, 2, '10.1097/WNP.0000000000000825', '33560701', NULL, 'The purpose of this study was to assess the prevalence, risk factors, and impact of electrographic seizures in neonates with complex congenital heart disease before cardiac surgery.

A cohort of 31 neonates with congenital heart disease monitored preoperatively with continuous video-EEG (cEEG) was first reviewed for electrographic seizure burden and EEG background abnormalities. Second, cEEG findings were correlated with brain MRI and 18-month outcomes.

Continuous video-EEG was recorded preoperatively for a median duration of 20.5 hours (range, 2.5-93.5 hours). The five neonates (16%; 95% confidence interval, 5.5% to 34%) with seizures detected on cEEG in the preoperative period had a diagnosis of transposition of the great arteries or similar physiology, detected in four of five postnatally. None of the 157 recorded electrographic seizures had a clinical correlate. The median time to first seizure was 65 minutes (range, 6-300 minutes) after cEEG hookup. The median maximum hourly seizure burden was 12.4 minutes (range, 7-23 minutes). Before the first electrographic seizure, a prolonged interburst interval (>10 seconds) was not associated with seizures (coefficient 1.2; 95% confidence interval, -1.1 to 3.6). MRI brain lesions were three times more common in neonates with seizures. Sharp wave transients on cEEG were associated with delayed opercular development.

In this cohort, preoperative electrographic seizures were common, were all subclinical, and were associated with MRI brain injury and postnatal diagnosis of transposition of the great arteries. The findings motivate further study of the mechanisms of preoperative brain injury, particularly among neonates with a postnatal diagnosis of transposition of the great arteries.', 'article', ARRAY['EEG','Neonatal','Seizures','Outcomes'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-96', 'Educational initiatives for electroencephalography in the critical care setting: a systematic review and meta-analysis', ARRAY['Taran S','Ahmed W','Pinto R','Bui E','Prisco L','Hahn CD','Englesakis M','McCredie VA'], 'Can J Anaesth', 2021, 3, '10.1007/s12630-021-01962-y', '33709264', 'PMC7952081', 'We systematically reviewed existing critical care electroencephalography (EEG) educational programs for non-neurologists, with the primary goal of reporting the content covered, methods of instruction, overall duration, and participant experience. Our secondary goals were to assess the impact of EEG programs on participants'' core knowledge, and the agreement between non-experts and experts for seizure identification.

Major databases were searched from inception to 30 August 2020. Randomized controlled trials, cohort studies, and descriptive studies were all considered if they reported an EEG curriculum for non-neurologists in a critical care setting. Data were presented thematically for the qualitative primary outcome and a meta-analysis using a random effects model was performed for the quantitative secondary outcomes.

Twenty-nine studies were included after reviewing 7,486 citations. Twenty-two studies were single centre, 17 were from North America, and 16 were published after 2016. Most EEG studies were targeted to critical care nurses (17 studies), focused on processed forms of EEG with amplitude-integrated EEG being the most common (15 studies), and were shorter than one day in duration (24 studies). In pre-post studies, EEG programs significantly improved participants'' knowledge of tested material (standardized mean change, 1.79; 95% confidence interval [CI], 0.86 to 2.73). Agreement for seizure identification between non-experts and experts was moderate (Cohen''s kappa = 0.44; 95% CI, 0.27 to 0.60).

It is feasible to teach basic EEG to participants in critical care settings from different clinical backgrounds, including physicians and nurses. Brief training programs can enable bedside providers to recognize high-yield abnormalities such as non-convulsive seizures.', 'review', ARRAY['EEG','Seizures','Review','Education'], ARRAY['brain injuries','critical care','electroencephalography','medical&#xa0;education','neurophysiology','seizures'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-97', 'Time to Treatment in Pediatric Convulsive Refractory Status Epilepticus: The Weekend Effect', ARRAY['Barcia Aguilar C','Amengual-Gual M','S&#xe1;nchez Fern&#xe1;ndez I','Abend NS','Anderson A','Appavu B','Arya R','Brenton JN','Carpenter JL','Chapman KE','Clark J','Farias-Moeller R','Gaillard WD','Ga&#xed;nza-Lein M','Glauser T','Goldstein JL','Goodkin HP','Guerriero RM','Huh L','Lai YC','McDonough TL','Mikati MA','Morgan LA','Novotny EJ','Ostendorf A','Payne ET','Peariso K','Piantino J','Riviello J','Sannagowdara K','Sheehan T','Sands TT','Tasker RC','Tchapyjnikov D','Topjian AA','Vasquez A','Wainwright MS','Wilfong AA','Williams K','Loddenkemper T'], 'Pediatr Neurol', 2021, 3, '10.1016/j.pediatrneurol.2021.03.009', '34022752', NULL, 'Time to treatment in pediatric refractory status epilepticus is delayed. We aimed to evaluate the influence of weekends and holidays on time to treatment of this pediatric emergency.

We performed a retrospective analysis of prospectively collected observational data of pediatric patients with refractory status epilepticus.

We included 329 patients (56% males) with a median (p25 to p75) age of 3.8 (1.3 to 9) years. The median (p25 to p75) time to first BZD on weekdays and weekends/holidays was 20 (6.8 to 48.3) minutes versus 11 (5 to 35) minutes, P = 0.01; adjusted hazard ratio (HR) = 1.20 (95% confidence interval [CI]: 0.95 to 1.55), P = 0.12. The time to first non-BZD ASM was longer on weekdays than on weekends/holidays (68 [42.8 to 153.5] minutes versus 59 [27 to 120] minutes, P = 0.006; adjusted HR = 1.38 [95% CI: 1.08 to 1.76], P = 0.009). However, this difference was mainly driven by status epilepticus with in-hospital onset: among 108 patients, the time to first non-BZD ASM was longer during weekdays than during weekends/holidays (55.5 [28.8 to 103.5] minutes versus 28 [15.8 to 66.3] minutes, P = 0.003; adjusted HR = 1.65 [95% CI: 1.08 to 2.51], P = 0.01).

The time to first non-BZD ASM in pediatric refractory status epilepticus is shorter on weekends/holidays than on weekdays, mainly driven by in-hospital onset status epilepticus. Data on what might be causing this difference may help tailor policies to improve medication application timing.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY['clinical neurology','epilepsy','outcome research','pediatric','status epilepticus'], 'Pediatric', TRUE, ARRAY['nicholas-abend','brian-appavu','raquel-farias-moeller','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-98', 'Alterations in coordinated EEG activity precede the development of seizures in comatose children', ARRAY['Vakorin VA','Nita DA','Payne ET','McBain KL','Frndova H','Go C','Ribary U','Abend NS','Gallentine WB','Nash KB','Hutchison JS','Parshuram CS','Snead OC','van Straaten IECW','Stam CJ','Doesburg SM','Hahn CD'], 'Clin Neurophysiol', 2021, 3, '10.1016/j.clinph.2021.03.015', '34023630', NULL, 'We aimed to test the hypothesis that computational features of the first several minutes of EEG recording can be used to estimate the risk for development of acute seizures in comatose critically-ill children.

In a prospective cohort of 118 comatose children, we computed features of the first five minutes of artifact-free EEG recording (spectral power, inter-regional synchronization and cross-frequency coupling) and tested if these features could help identify the 25 children who went on to develop acute symptomatic seizures during the subsequent 48 hours of cEEG monitoring.

Children who developed acute seizures demonstrated higher average spectral power, particularly in the theta frequency range, and distinct patterns of inter-regional connectivity, characterized by greater connectivity at delta and theta frequencies, but weaker connectivity at beta and low gamma frequencies. Subgroup analyses among the 97 children with the same baseline EEG background pattern (generalized slowing) yielded qualitatively and quantitatively similar results.

These computational features could be applied to baseline EEG recordings to identify critically-ill children at high risk for acute symptomatic seizures.

If confirmed in independent prospective cohorts, these features would merit incorporation into a decision support system in order to optimize diagnostic and therapeutic management of seizures among comatose children.', 'article', ARRAY['EEG','Seizures'], ARRAY['brain connectivity','coma','critically ill children','electroencephalography (eeg)','icu'], 'Pediatric', TRUE, ARRAY['nicholas-abend','cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-99', 'Parental perception of FIRES outcomes, emotional states, and social media usage', ARRAY['Farias-Moeller R','Wood A','Sawdy R','Koop J','Olson K','van Baalen A'], 'Epilepsia Open', 2021, 6, '10.1002/epi4.12513', '34098587', 'PMC8408589', 'To investigate parental perception of FIRES outcomes, assess emotional states and related social media usage.

A survey-based study of parents of children with FIRES participating in a FIRES-specific Facebook group was performed. The survey collected information on medical aspects of their child''s course in the acute, subacute, and chronic periods, emotional states, and social media usage. Child outcome was assessed utilizing the pediatric extended Glasgow outcome scale (GOS-E). Parental emotional states were assessed utilizing the Depression, Anxiety and Stress Scale (DASS). Descriptive statistics were performed. Associations were described using the Spearman rank correlation. Open-ended questions were included. Thematic analysis was performed.

Twenty-nine surveys were analyzed. All children were in the chronic phase at time of survey response, except for two who died. Mothers answered 22 surveys, and fathers answered seven. Median age at FIRES presentation was 5.6 years [IQR 4.2-8.95], with a median number of 3 seizures per week [IQR 0-10, range 0-50], 4 daily anti-seizure medicines [IQR 3-5], and chronic GOS-E of 6 [IQR 2-8 range 2-8]. Most parents reported none to mild levels of depression, anxiety, and stress. Higher seizure burden positively correlated with parental depression symptoms (r = .41 (95% CI 0.01, 0.70), P = .045). Most parents found social media helpful with coping and 96% desired FIRES research advertised. Twenty-five parents shared their recommendations to fellow parents and the medical team in an open-ended format. Themes included support, expertise, and medical advice.

Despite their children''s significantly impaired functional outcome after FIRES and high rates of medically refractory epilepsy, the cohort demonstrated remarkable emotional resilience. They perceive social media as beneficial, are interested in social media-advertised research, and share valuable advice. Social media may serve as an introductory platform to enhance the physician-scientist-parent/patient relationship.', 'article', ARRAY['Seizures','Survey','NORSE/FIRES','Outcomes'], ARRAY['epilepsy','febrile infection-related epilepsy syndrome','new-onset refractory status epilepticus','social media'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-100', 'Super-Refractory Status Epilepticus in Children: A Retrospective Cohort Study', ARRAY['Vasquez A','Farias-Moeller R','S&#xe1;nchez-Fern&#xe1;ndez I','Abend NS','Amengual-Gual M','Anderson A','Arya R','Brenton JN','Carpenter JL','Chapman K','Clark J','Gaillard WD','Glauser T','Goldstein JL','Goodkin HP','Guerriero RM','Lai YC','McDonough TL','Mikati MA','Morgan LA','Novotny EJ','Ostendorf AP','Payne ET','Peariso K','Piantino J','Riviello JJ','Sands TT','Sannagowdara K','Tasker RC','Tchapyjnikov D','Topjian A','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Pediatr Crit Care Med', 2021, 12, '10.1097/PCC.0000000000002786', '34120133', NULL, 'To characterize the pediatric super-refractory status epilepticus population by describing treatment variability in super-refractory status epilepticus patients and comparing relevant clinical characteristics, including outcomes, between super-refractory status epilepticus, and nonsuper-refractory status epilepticus patients.

Retrospective cohort study with prospectively collected data between June 2011 and January 2019.

Seventeen academic hospitals in the United States.

We included patients 1 month to 21 years old presenting with convulsive refractory status epilepticus. We defined super-refractory status epilepticus as continuous or intermittent seizures lasting greater than or equal to 24 hours following initiation of continuous infusion and divided the cohort into super-refractory status epilepticus and nonsuper-refractory status epilepticus groups.

None.

We identified 281 patients (157 males) with a median age of 4.1 years (1.3-9.5 yr), including 31 super-refractory status epilepticus patients. Compared with nonsuper-refractory status epilepticus group, super-refractory status epilepticus patients had delayed initiation of first nonbenzodiazepine-antiseizure medication (149 min [55-491.5 min] vs 62 min [33.3-120.8 min]; p = 0.030) and of continuous infusion (495 min [177.5-1,255 min] vs 150 min [90-318.5 min]; p = 0.003); prolonged seizure duration (120 hr [58-368 hr] vs 3 hr [1.4-5.9 hr]; p < 0.001) and length of ICU stay (17 d [9.5-40 d] vs [1.8-8.8 d]; p < 0.001); more medical complications (18/31 [58.1%] vs 55/250 [22.2%] patients; p < 0.001); lower return to baseline function (7/31 [22.6%] vs 182/250 [73.4%] patients; p < 0.001); and higher mortality (4/31 [12.9%] vs 5/250 [2%]; p = 0.010). Within the super-refractory status epilepticus group, status epilepticus resolution was attained with a single continuous infusion in 15 of 31 patients (48.4%), two in 10 of 31 (32.3%), and three or more in six of 31 (19.4%). Most super-refractory status epilepticus patients (30/31, 96.8%) received midazolam as first choice. About 17 of 31 patients (54.8%) received additional treatments.

Super-refractory status epilepticus patients had delayed initiation of nonbenzodiazepine antiseizure medication treatment, higher number of medical complications and mortality, and lower return to neurologic baseline than nonsuper-refractory status epilepticus patients, although these associations were not adjusted for potential confounders. Treatment approaches following the first continuous infusion were heterogeneous, reflecting limited information to guide clinical decision-making in super-refractory status epilepticus.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller','nicholas-abend','adam-ostendorf','james-riviello','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-101', 'Altered Protein Profiles During Epileptogenesis in the Pilocarpine Mouse Model of Temporal Lobe Epilepsy', ARRAY['Ahmed MM','Carrel AJ','Cruz Del Angel Y','Carlsen J','Thomas AX','Gonz&#xe1;lez MI','Gardiner KJ','Brooks-Kayal A'], 'Front Neurol', 2021, 5, '10.3389/fneur.2021.654606', '34122302', 'PMC8194494', 'Epilepsy is characterized by recurrent, spontaneous seizures and is a major contributor to the global burden of neurological disease. Although epilepsy can result from a variety of brain insults, in many cases the cause is unknown and, in a significant proportion of cases, seizures cannot be controlled by available treatments. Understanding the molecular alterations that underlie or are triggered by epileptogenesis would help to identify therapeutics to prevent or control progression to epilepsy. To this end, the moderate throughput technique of Reverse Phase Protein Arrays (RPPA) was used to profile changes in protein expression in a pilocarpine mouse model of acquired epilepsy. Levels of 54 proteins, comprising phosphorylation-dependent and phosphorylation-independent components of major signaling pathways and cellular complexes, were measured in hippocampus, cortex and cerebellum of mice at six time points, spanning 15 min to 2 weeks after induction of status epilepticus. Results illustrate the time dependence of levels of the commonly studied MTOR pathway component, pS6, and show, for the first time, detailed responses during epileptogenesis of multiple components of the MTOR, MAPK, JAK/STAT and apoptosis pathways, NMDA receptors, and additional cellular complexes. Also noted are time- and brain region- specific changes in correlations among levels of functionally related proteins affecting both neurons and glia. While hippocampus and cortex are primary areas studied in pilocarpine-induced epilepsy, cerebellum also shows significant time-dependent molecular responses.', 'article', ARRAY['Status Epilepticus'], ARRAY['epileptogenesis','pilocarpine','protein phosphorylation','reverse phase protein array','seizures','signaling'], 'Pediatric', TRUE, ARRAY['ajay-thomas'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-102', 'The SPARC DRC: Building a Resource for the Autonomic Nervous System Community', ARRAY['Osanlouy M','Bandrowski A','de Bono B','Brooks D','Cassar&#xe0; AM','Christie R','Ebrahimi N','Gillespie T','Grethe JS','Guercio LA','Heal M','Lin M','Kuster N','Martone ME','Neufeld E','Nickerson DP','Soltani EG','Tappan S','Wagenaar JB','Zhuang K','Hunter PJ'], 'Front Physiol', 2021, 6, '10.3389/fphys.2021.693735', '34248680', 'PMC8265045', 'The Data and Resource Center (DRC) of the NIH-funded SPARC program is developing databases, connectivity maps, and simulation tools for the mammalian autonomic nervous system. The experimental data and mathematical models supplied to the DRC by the SPARC consortium are curated, annotated and semantically linked via a single knowledgebase. A data portal has been developed that allows discovery of data and models both via semantic search and via an interface that includes Google Map-like 2D flatmaps for displaying connectivity, and 3D anatomical organ scaffolds that provide a common coordinate framework for cross-species comparisons. We discuss examples that illustrate the data pipeline, which includes data upload, curation, segmentation (for image data), registration against the flatmaps and scaffolds, and finally display via the web portal, including the link to freely available online computational facilities that will enable neuromodulation hypotheses to be investigated by the autonomic neuroscience community and device manufacturers.', 'article', ARRAY['Cardiac Arrest'], ARRAY['fair','sparc','autonomic nervous system','computational life sciences','data annotation','data curation','knowledge management','neural mapping'], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-103', 'Factors associated with long-term outcomes in pediatric refractory status epilepticus', ARRAY['Ga&#xed;nza-Lein M','Barcia Aguilar C','Piantino J','Chapman KE','S&#xe1;nchez Fern&#xe1;ndez I','Amengual-Gual M','Anderson A','Appavu B','Arya R','Brenton JN','Carpenter JL','Clark J','Farias-Moeller R','Gaillard WD','Glauser TA','Goldstein JL','Goodkin HP','Huh L','Kahoud R','Kapur K','Lai YC','McDonough TL','Mikati MA','Morgan LA','Nayak A','Novotny E','Ostendorf AP','Payne ET','Peariso K','Reece L','Riviello J','Sannagowdara K','Sands TT','Sheehan T','Tasker RC','Tchapyjnikov D','Vasquez A','Wainwright MS','Wilfong A','Williams K','Zhang B','Loddenkemper T'], 'Epilepsia', 2021, 7, '10.1111/epi.16984', '34251039', 'PMC9291041', 'This study was undertaken to describe long-term clinical and developmental outcomes in pediatric refractory status epilepticus (RSE) and identify factors associated with new neurological deficits after RSE.

We performed retrospective analyses of prospectively collected observational data from June 2011 to March 2020 on pediatric patients with RSE. We analyzed clinical outcomes from at least 30 days after RSE and, in a subanalysis, we assessed developmental outcomes and evaluated risk factors in previously normally developed patients.

Follow-up data on outcomes were available in 276 patients (56.5% males). The median (interquartile range [IQR]) follow-up duration was 1.6 (.9-2.7) years. The in-hospital mortality rate was 4% (16/403 patients), and 15 (5.4%) patients had died after hospital discharge. One hundred sixty-six (62.9%) patients had subsequent unprovoked seizures, and 44 (16.9%) patients had a repeated RSE episode. Among 116 patients with normal development before RSE, 42 of 107 (39.3%) patients with available data had new neurological deficits (cognitive, behavioral, or motor). Patients with new deficits had longer median (IQR) electroclinical RSE duration than patients without new deficits (10.3 [2.1-134.5] h vs. 4 [1.6-16] h, p = .011, adjusted odds ratio = 1.003, 95% confidence interval = 1.0008-1.0069, p = .027). The proportion of patients with an unfavorable functional outcome (Glasgow Outcome Scale-Extended score ≥ 4) was 22 of 90 (24.4%), and they were more likely to have received a continuous infusion.

About one third of patients without prior epilepsy developed recurrent unprovoked seizures after the RSE episode. In previously normally developing patients, 39% presented with new deficits during follow-up, with longer electroclinical RSE duration as a predictor.', 'article', ARRAY['Status Epilepticus','Biomarkers','Outcomes'], ARRAY['clinical neurology','epilepsy','outcome research','pediatric','status epilepticus'], 'Pediatric', TRUE, ARRAY['brian-appavu','raquel-farias-moeller','adam-ostendorf','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-104', 'Benzodiazepine administration patterns before escalation to second-line medications in pediatric refractory convulsive status epilepticus', ARRAY['Sheehan T','Amengual-Gual M','Vasquez A','Abend NS','Anderson A','Appavu B','Arya R','Barcia Aguilar C','Brenton JN','Carpenter JL','Chapman KE','Clark J','Farias-Moeller R','Gaillard WD','Ga&#xed;nza-Lein M','Glauser TA','Goldstein JL','Goodkin HP','Guerriero RM','Huh L','Jackson M','Kapur K','Kahoud R','Lai YC','McDonough TL','Mikati MA','Morgan LA','Novotny EJ','Ostendorf AP','Payne ET','Peariso K','Piantino J','Reece L','Riviello JJ','Sands TT','Sannagowdara K','Shellhaas R','Smith G','Tasker RC','Tchapyjnikov D','Topjian AA','Wainwright MS','Wilfong A','Williams K','Zhang B','Loddenkemper T'], 'Epilepsia', 2021, 8, '10.1111/epi.17043', '34418087', 'PMC9292193', 'This study was undertaken to evaluate benzodiazepine (BZD) administration patterns before transitioning to non-BZD antiseizure medication (ASM) in pediatric patients with refractory convulsive status epilepticus (rSE).

This retrospective multicenter study in the United States and Canada used prospectively collected observational data from children admitted with rSE between 2011 and 2020. Outcome variables were the number of BZDs given before the first non-BZD ASM, and the number of BZDs administered after 30 and 45 min from seizure onset and before escalating to non-BZD ASM.

We included 293 patients with a median (interquartile range) age of 3.8 (1.3-9.3) years. Thirty-six percent received more than two BZDs before escalating, and the later the treatment initiation was after seizure onset, the less likely patients were to receive multiple BZD doses before transitioning (incidence rate ratio [IRR] = .998, 95% confidence interval [CI] = .997-.999 per minute, p = .01). Patients received BZDs beyond 30 and 45 min in 57.3% and 44.0% of cases, respectively. Patients with out-of-hospital seizure onset were more likely to receive more doses of BZDs beyond 30 min (IRR = 2.43, 95% CI = 1.73-3.46, p < .0001) and beyond 45 min (IRR = 3.75, 95% CI = 2.40-6.03, p < .0001) compared to patients with in-hospital seizure onset. Intermittent SE was a risk factor for more BZDs administered beyond 45 min compared to continuous SE (IRR = 1.44, 95% CI = 1.01-2.06, p = .04). Forty-seven percent of patients (n = 94) with out-of-hospital onset did not receive treatment before hospital arrival. Among patients with out-of-hospital onset who received at least two BZDs before hospital arrival (n = 54), 48.1% received additional BZDs at hospital arrival.

Failure to escalate from BZDs to non-BZD ASMs occurs mainly in out-of-hospital rSE onset. Delays in the implementation of medical guidelines may be reduced by initiating treatment before hospital arrival and facilitating a transition to non-BZD ASMs after two BZD doses during handoffs between prehospital and in-hospital settings.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY['benzodiazepine','epilepsy','pediatric','seizure','status epilepticus','treatment'], 'Pediatric', TRUE, ARRAY['nicholas-abend','brian-appavu','raquel-farias-moeller','adam-ostendorf','james-riviello','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-105', 'Spectrograms for Seizure Detection in Critically Ill Children', ARRAY['Lalgudi Ganesan S','Hahn CD'], 'J Clin Neurophysiol', 2022, 3, '10.1097/WNP.0000000000000868', '34510096', NULL, 'Electrographic seizures are common in critically ill children and a significant proportion of these seizures are nonconvulsive. There is an association between electrographic seizures and neurophysiological disturbances, worse short- and long-term neurologic outcomes, and mortality in critically ill patients. In this context, timely diagnosis and treatment of electrographic seizures in critically ill children becomes important. However, most institutions lack the resources to support round-the-clock or frequent review of continuous EEG recordings causing significant delays in seizure diagnosis. Given the current gaps in review of continuous EEG across institutions globally, use of visually simplified, time-compressed quantitative EEG trends such as spectrograms has the potential to enhance timeliness of seizure diagnosis and treatment in critically ill children.', 'article', ARRAY['qEEG','Seizures','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['rishi-ganesan','cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-106', 'Continuous Electroencephalogram and Antiseizure Medication Use in an International Pediatric Traumatic Brain Injury Population', ARRAY['Snooks KC','Yan K','Farias-Moeller R','Fink EL','Hanson SJ'], 'Neurocrit Care', 2021, 9, '10.1007/s12028-021-01337-7', '34553297', NULL, 'Electrographic seizures are frequent and associated with worse outcomes following traumatic brain injury (TBI). Despite this, the use of continuous electroencephalogram (cEEG) remains low. Our study describes cEEG usage and treatment dosing antiseizure medications (ASMs) in an international pediatric TBI population, hypothesizing that children monitored with cEEG have an increased rate of treatment ASMs because of electrographic seizure detection, compared with children who are not monitored with cEEG.

This subanalysis of the TBI cohort of the international PANGEA study included children, 7 days to 17 years of age, with acute neurological insults admitted to pediatric intensive care units. We analyzed demographics, injury severity, and therapies including prophylactic or treatment ASMs. We evaluated the relationships between cEEG use, seizure frequency, and receipt of treatment ASMs. [Formula: see text] or Fisher''s exact test was used to analyze categorical variables, and the Kruskal-Wallis or Mann-Whitney U-test was used for continuous variables. Multivariable analysis for treatment ASM use was performed using logistic regression.

One hundred-twenty-three of 174 patients with TBI were included. Twenty-seven patients (21.9%) underwent cEEG at any point during pediatric intensive care unit admission. Preexisting seizure disorder (18.2% vs. 2.3%, p = 0.014) and neuromuscular blockade use (52.4% vs. 24.1%, p = 0.011) were more frequently observed in the group monitored on cEEG when compared with those that were not. Presenting median Glasgow Coma Scale score was worse in the cEEG group (7 vs. 9, p = 0.044). There was no significant difference in age, use of intracranial pressure monitoring, or hyperosmolar therapy between the cEEG monitored and nonmonitored groups. Patients who were monitored on cEEG were more likely to receive a treatment dose ASM than those without cEEG monitoring (66.7% vs. 28.1%, p = 0.0002). When compared with those without treatment ASM, the treatment ASM group had more electrographic seizures on their first electroencephalogram following injury (51.6% vs. 4%, p = 0.0001) and more clinical seizures (55.8% vs. 0%, p < 0.0001).

Children monitored with cEEG after TBI have an increased prescription of treatment ASMs and clinical and electrographic seizures. The increased rate of treatment ASMs in the cEEG group may indicate increased recognition of electrographic seizures.', 'article', ARRAY['EEG','Seizures','Pharmacology','TBI'], ARRAY['adolescent','anticonvulsants','brain injuries (traumatic)','child','critical care outcomes','electroencephalography','global health','intensive care unit (pediatric)','seizures'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-107', 'Antiepileptic drug management in pediatric patients with brain tumor-related epilepsy', ARRAY['Malbari F','Zhu H','Riviello JJ','Clarke D'], 'Epilepsy Behav', 2021, 10, '10.1016/j.yebeh.2021.108359', '34731721', NULL, 'Patients with brain tumor-related epilepsy (BTRE) are at a higher risk of significant morbidity, lower quality of life, and increased risk of mortality. We surveyed providers regarding anti-seizure medication (ASM) management in pediatric BTRE to determine if practices are standard or markedly variable.

An anonymous voluntary online survey was sent to members of the Child Neurology Society. Providers were asked specific questions regarding initiation and wean of ASMs and if this was dependent on multiple factors. Demographic information was collected.

Fifty-one providers responded to the survey. Ninety-four percent of providers would start an ASM after a second seizure. Eighty-four percent chose levetiracetam as the preferred ASM. Management was variable when based on tumor location, extent of surgical resection, pathology, and tumor prognosis. Statistically significant differences in responses regarding management were identified when comparing neurologists and epileptologists, providers with formal neuro-oncology or epilepsy training, providers at large institutions, and years of experience. For patients who underwent a gross total resection of the tumor, neuro-oncology and epilepsy-trained providers were more likely to wean off ASMs (p < 0.049). Providers without formal training in neuro-oncology or epilepsy were more likely to get an EEG prior to making a decision about weaning off ASMs (p < 0.016).

These results suggest that ASM management in BTRE varies greatly according to sub-specialty and experience. Further studies and potential development of guidelines are needed to identify the most appropriate management of ASMs for BTRE.', 'article', ARRAY['EEG','Seizures','Survey','Education','Pharmacology','Epilepsy'], ARRAY['anti-seizure medications','brain tumor-related epilepsy','epilepsy','pediatric brain tumors'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-108', 'Quantitative EEG-Based Seizure Estimation in Super-Refractory Status Epilepticus', ARRAY['Alkhachroum A','Ganesan SL','Koren JP','Kromm J','Massad N','Reyes RA','Miller MR','Roh D','Agarwal S','Park S','Claassen J'], 'Neurocrit Care', 2021, 11, '10.1007/s12028-021-01395-x', '34791594', 'PMC9987776', 'The objective of this study was to evaluate the accuracy of seizure burden in patients with super-refractory status epilepticus (SRSE) by using quantitative electroencephalography (qEEG).

EEG recordings from 69 patients with SRSE (2009-2019) were reviewed and annotated for seizures by three groups of reviewers: two board-certified neurophysiologists using only raw EEG (gold standard), two neurocritical care providers with substantial experience in qEEG analysis (qEEG experts), and two inexperienced qEEG readers (qEEG novices) using only a qEEG trend panel.

Raw EEG experts identified 35 (51%) patients with seizures, accounting for 2950 seizures (3,126 min). qEEG experts had a sensitivity of 93%, a specificity of 61%, a false positive rate of 6.5 per day, and good agreement (κ = 0.64) between both qEEG experts. qEEG novices had a sensitivity of 98.5%, a specificity of 13%, a false positive rate of 15 per day, and fair agreement (κ = 0.4) between both qEEG novices. Seizure burden was not different between the qEEG experts and the gold standard (3,257 vs. 3,126 min), whereas qEEG novices reported higher burden (6066 vs. 3126 min).

Both qEEG experts and novices had a high sensitivity but a low specificity for seizure detection in patients with SRSE. qEEG could be a useful tool for qEEG experts to estimate seizure burden in patients with SRSE.', 'article', ARRAY['qEEG','Neurocritical Care','Status Epilepticus'], ARRAY['electroencephalogram','quantitative electroencephalography','seizure burden','status epilepticus','super-refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['rishi-ganesan'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-109', 'The role of stereo-electroencephalography to localize the epileptogenic zone in children with nonlesional brain magnetic resonance imaging', ARRAY['Kim W','Shen MY','Provenzano FA','Lowenstein DB','McBrian DK','Mandel AM','Sands TT','Riviello JJ','McKhann GM','Feldstein NA','Akman CI'], 'Epilepsy Res', 2021, 11, '10.1016/j.eplepsyres.2021.106828', '34920378', NULL, 'This study aimed to assess the clinical outcome and outcome predictive factors in pediatric epilepsy patients evaluated with stereo-electroencephalography (SEEG).

Thirty-eight patients who underwent SEEG implantation at the Pediatric Epilepsy Center in New York Presbyterian Hospital between June 2014 and December 2019 were enrolled for retrospective chart review. Postoperative seizure outcomes were evaluated in patients with at least 12-months follow up. Meta-analysis was conducted via electronic literature search of data reported from 2000 to 2020 to evaluate significant surgical outcome predictors for SEEG evaluation in the pediatric population.

In the current case series of 25 postsurgical patients with long-term follow up, 16 patients (64.0%) were seizure free. An additional 7 patients (28.0%) showed significant seizure improvement and 2 patients (8.0%) showed no change in seizure activity. Patients with nonlesional magnetic resonance imaging (MRI) achieved seizure freedom in 50% (5/10) of cases. By comparison, 73% (11/15) of patients with lesional MRI achieved seizure freedom. Out of 12 studies, 158 pediatric patients were identified for inclusion in a meta-analysis of the effectiveness of SEEG. Seizure freedom was reported 54.4% (n = 86/158) of patients at last follow up. Among patients with nonlesional MRI, 45% (n = 24) achieved seizure freedom compared with patients with lesional MRI findings (61.2%, n:= 60) (p = 0.02). The risk for seizure recurrence was 2.15 times higher [95% confidence interval [CI] 1.06-4.37, p = 0.033] in patients diagnosed with nonlesional focal epilepsy compared to those with lesional epilepsy [ 1.49 (95% CI 1.06-2.114, p = 0.021].

Evaluation by SEEG implantation in pediatric epilepsy is effective in localizing the epileptogenic zone with favorable outcome. Presence of a non-lesional brain MRI was associated with lower chances of seizure freedom. Further research is warranted to improve the efficacy of SEEG in localizing the epileptogenic zone in pediatric patients with non-lesional brain MRI.', 'article', ARRAY['EEG','Seizures','Biomarkers','Outcomes'], ARRAY['mri','pediatric epilepsy','stereo-electroencephalography (seeg)'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-110', 'Clinico-radiological features, molecular spectrum, and identification of prognostic factors in developmental and epileptic encephalopathy due to inosine triphosphate pyrophosphatase (ITPase) deficiency', ARRAY['Scala M','Wortmann SB','Kaya N','Stellingwerff MD','Pistorio A','Glamuzina E','van Karnebeek CD','Skrypnyk C','Iwanicka-Pronicka K','Piekutowska-Abramczuk D','Ciara E','Tort F','Sheidley B','Poduri A','Jayakar P','Jayakar A','Upadia J','Walano N','Haack TB','Prokisch H','Aldhalaan H','Karimiani EG','Yildiz Y','Ceylan AC','Santiago-Sim T','Dameron A','Yang H','Toosi MB','Ashrafzadeh F','Akhondian J','Imannezhad S','Mirzadeh HS','Maqbool S','Farid A','Al-Muhaizea MA','Alshwameen MO','Aldowsari L','Alsagob M','Alyousef A','AlMass R','AlHargan A','Alwadei AH','AlRasheed MM','Colak D','Alqudairy H','Khan S','Lines MA','Garc&#xed;a Cazorla M&#xc1;','Ribes A','Morava E','Bibi F','Haider S','Ferla MP','Taylor JC','Alsaif HS','Firdous A','Hashem M','Shashkin C','Koneev K','Kaiyrzhanov R','Efthymiou S','Genomics QS','Schmitt-Mechelke T','Ziegler A','Issa MY','Elbendary HM','Striano P','Alkuraya FS','Zaki MS','Gleeson JG','Barakat TS','Bierau J','van der Knaap MS','Maroofian R','Houlden H'], 'Hum Mutat', 2022, 1, '10.1002/humu.24326', '34989426', 'PMC9152572', 'Developmental and epileptic encephalopathy 35 (DEE 35) is a severe neurological condition caused by biallelic variants in ITPA, encoding inosine triphosphate pyrophosphatase, an essential enzyme in purine metabolism. We delineate the genotypic and phenotypic spectrum of DEE 35, analyzing possible predictors for adverse clinical outcomes. We investigated a cohort of 28 new patients and reviewed previously described cases, providing a comprehensive characterization of 40 subjects. Exome sequencing was performed to identify underlying ITPA pathogenic variants. Brain MRI (magnetic resonance imaging) scans were systematically analyzed to delineate the neuroradiological spectrum. Survival curves according to the Kaplan-Meier method and log-rank test were used to investigate outcome predictors in different subgroups of patients. We identified 18 distinct ITPA pathogenic variants, including 14 novel variants, and two deletions. All subjects showed profound developmental delay, microcephaly, and refractory epilepsy followed by neurodevelopmental regression. Brain MRI revision revealed a recurrent pattern of delayed myelination and restricted diffusion of early myelinating structures. Congenital microcephaly and cardiac involvement were statistically significant novel clinical predictors of adverse outcomes. We refined the molecular, clinical, and neuroradiological characterization of ITPase deficiency, and identified new clinical predictors which may have a potentially important impact on diagnosis, counseling, and follow-up of affected individuals.', 'article', ARRAY['Seizures','Biomarkers','Outcomes','Neurocritical Care'], ARRAY['itpa','itpase','congenital microcephaly','developmental and epileptic encephalopathy 35','heart disease','white matter abnormalities'], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-111', 'Pediatric Critical Care Neurologists in the United States and Canada: A Survey of Clinical Practice Experience', ARRAY['Farias-Moeller R','Jayakar A','Guerriero RM','Carpenter JL','Wainwright MS','Harrar DB'], 'J Child Neurol', 2022, 1, '10.1177/08830738211070099', '35037772', NULL, 'To describe the characteristics of pediatric intensive care neurologists and their practice in the United States and Canada.

We performed a survey-based study of child neurologists who self-identify as ''intensive care neurologists''. The survey included questions about demographics, training, pediatric neurocritical care service and job structure, teaching, academics, challenges, and views on the future of pediatric neurocritical care.

We analyzed 55 surveys. Most respondents were 31-50 years of age with ≤10 years of practice experience. Fifty-four percent identified as female. Most completed subspecialty training after child neurology residency. The majority practice at highly resourced centers with >45 intensive care unit beds. Respondents cover a variety of inpatient (critical and noncritical care) services, at times simultaneously, for a median of 19.5 weeks/y and work >70 hours/wk when on service for pediatric neurocritical care. The top 3 challenges reported were competing demands for time, excess volume, and communication with critical care medicine. Top priorities for the "ideal pediatric neurocritical care service" were attendings with training in pediatric neurocritical care or a related field and joint rounding with critical care medicine.

We report a survey-based analysis of the demographics and scope of practice of pediatric critical care neurologists. We highlight challenges faced and provide a framework for the further development of this rapidly growing field.', 'article', ARRAY['Neurocritical Care','Survey','Education'], ARRAY['pediatric neurocritical care','pediatric neurohospitalist','pediatric neurology','pediatric stroke'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller','anuj-jayakar','dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-112', 'Role of neuropsychology in identification of CSWS in a school-aged child with a remote neurological insult', ARRAY['Kalscheur EJ','Farias-Moeller R','Koop J'], 'Epilepsy Behav Rep', 2021, 12, '10.1016/j.ebr.2021.100514', '35198953', 'PMC8850745', 'Electrical status epilepticus of slow-wave sleep (ESES) is characterized by excessive interictal spike-wave discharges on EEG during sleep and can occur in the absence of overt clinical seizures. Continuous spike-wave during slow wave sleep (CSWS), an epilepsy syndrome associated with ESES, is associated with a plateau/decline in cognitive development and increases in behavioral and emotional dysregulation. Here we present a case in which neuropsychological (NP) evaluation initially ordered based on memory and attention concerns led to the identification of subclinical seizure activity and an evolving epileptic encephalopathy in an 11-year-old child with a history of remote neurological insult. The patient was referred for an initial NP evaluation at age 8 which revealed weaknesses in functions typically mediated by the dominant (usually left) hemisphere juxtaposed with her left hemiparesis. EEG was recommended which showed independent, multifocal spike and sharp wave discharges exacerbated by sleep. Follow-up NP evaluations over the following 26 months, during which time aggressive treatment was initiated, coincided with EEG findings of an evolving epileptic encephalopathy in the patient who continued to remain free from clinical seizures. This case highlights the importance of comprehensive epilepsy care and routine involvement of neuropsychology in the management of complex epilepsy patients.', 'case_report', ARRAY['Status Epilepticus','EEG','Sleep','Neurocritical Care'], ARRAY['csws','eses','neuropsychological assessment','pediatric epilepsy','pediatric stroke'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-113', 'Why monitor the neonatal brain-that is the important question', ARRAY['Vanhatalo S','Stevenson NJ','Pressler RM','Abend NS','Auvin S','Brigo F','Cilio MR','Hahn CD','Hartmann H','Hellstr&#xf6;m-Westas L','Inder TE','Mosh&#xe9; SL','Nunes ML','Shellhaas RA','Vinayan KP','de Vries LS','Wilmshurst JM','Yozawitz E','Boylan GB'], 'Pediatr Res', 2022, 4, '10.1038/s41390-022-02040-9', '35365761', 'PMC9876788', 'A key goal of neonatal neurocritical care is improved outcomes, and brain monitoring plays an essential role. The recent NEST trial reported no outcome benefits using aEEG monitoring compared to clinical seizure identification among neonates treated for seizures. However, the study failed to prove the effects of monitoring on seizure treatment in the first place.', 'article', ARRAY['Neurocritical Care','Neuromonitoring','EEG','Neonatal','Seizures'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend','cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-114', 'Zebras Seize the Day: Rare Causes of Status Epilepticus Across the Continuum of Critical Care', ARRAY['Harrar D','Mondok L','Adams S','Farias-Moeller R'], 'Crit Care Clin', 2022, 4, '10.1016/j.ccc.2021.11.006', '35369951', NULL, 'Status epilepticus (SE) is a common neurologic emergency and is associated with a high risk of morbidity and mortality. The management of SE in the intensive care unit centers on stabilization and treatment, as well as identifying and treating the underlying etiology. This article highlights rare but important causes of SE across the continuum of care from neonates to adults.', 'review', ARRAY['Status Epilepticus','Neonatal','Review','Outcomes'], ARRAY['autoimmune encephalopathy','epileptic encephalopathy','fires','status epilepticus'], 'Neonatal', TRUE, ARRAY['dana-harrar','raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-115', 'Extent of EEG monitoring for detecting epileptic spasms', ARRAY['Katyayan A','Takacs DS','Vanderslice K','Riviello JJ'], 'Seizure', 2022, 3, '10.1016/j.seizure.2022.03.016', '35390640', NULL, 'Epileptic spasms (ES) are the ictal manifestation of West syndrome. We retrospectively analyzed inpatient video EEG recordings of 42 patients with new onset ES. Routine or short duration EEGs are not sufficient to capture ES in most patients. 4-5-hour VEEG monitoring duration should be considered.', 'article', ARRAY['EEG','Seizures'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-116', 'Real-world economic evaluation of prospective rapid whole-genome sequencing compared to a matched retrospective cohort of critically ill pediatric patients in the United States', ARRAY['Diaby V','Babcock A','Huang Y','Moussa RK','Espinal PS','Janvier M','Soler D','Gupta A','Jayakar P','Diaz-Barbosa M','Totapally B','Sasaki J','Jayakar A','Salyakina D'], 'Pharmacogenomics J', 2022, 4, '10.1038/s41397-022-00277-5', '35436997', NULL, 'There is an increasing demand for supporting the adoption of rapid whole-genome sequencing (rWGS) by demonstrating its real-world value. rWGS in critically ill pediatric patients is cost-effective, cost-saving, shortens diagnostic odyssey, and triples the diagnostic yield of traditional approaches.', 'article', ARRAY['Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-117', 'Validation of a Model for Targeted EEG Monitoring Duration in Critically Ill Children', ARRAY['Fung FW','Fan J','Parikh DS','Vala L','Donnelly M','Jacobwitz M','Topjian AA','Xiao R','Abend NS'], 'J Clin Neurophysiol', 2022, 4, '10.1097/WNP.0000000000000940', '35512186', 'PMC9582115', 'Continuous EEG monitoring (CEEG) to identify electrographic seizures (ES) in critically ill children is resource intense. This model enables implementation of a data-driven strategy that targets CEEG duration based on readily available clinical and EEG variables.', 'article', ARRAY['EEG','Seizures'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-118', 'Cerebral Digital Subtraction Angiography in Acute Intracranial Hemorrhage: Considerations in Critically Ill Children', ARRAY['Harrar DB','Sun LR','Goss M','Pearl MS'], 'J Child Neurol', 2022, 6, '10.1177/08830738221106818', '35673704', NULL, 'Cerebrovascular disorders are an important cause of morbidity and mortality in children. Through a case-based approach, we explore the utility of DSA in critically ill children with acute intracranial hemorrhage.', 'article', ARRAY['Stroke','Outcomes'], ARRAY['aneurysm','arteriovenous malformation','digital subtraction angiography','intracranial hemorrhage','pediatric'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
