INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-119', 'A phase 2, randomized, double-blind, placebo-controlled study to evaluate the efficacy and safety of soticlestat as adjunctive therapy in pediatric patients with Dravet syndrome or Lennox-Gastaut syndrome (ELEKTRA)', ARRAY['Hahn CD','Jiang Y','Villanueva V','Zolnowska M','Arkilo D','Hsiao S','Asgharnejad M','Dlugos D'], 'Epilepsia', 2022, 8, '10.1111/epi.17367', '35841234', 'PMC9804149', 'Dravet syndrome (DS) and Lennox-Gastaut syndrome (LGS) are rare treatment-resistant childhood epilepsies. Soticlestat treatment resulted in statistically significant, clinically meaningful reductions from baseline in median seizure frequency.', 'article', ARRAY['Seizures','Clinical Trial','Pharmacology'], ARRAY['dravet syndrome','lennox-gastaut syndrome','soticlestat'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
