INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-121', 'Machine learning to support triage of children at risk for epileptic seizures in the pediatric intensive care unit', ARRAY['Azriel R','Hahn CD','De Cooman T','Van Huffel S','Payne ET','McBain KL','Eytan D','Behar JA'], 'Physiol Meas', 2022, 9, '10.1088/1361-6579/ac8ccd', '36007520', NULL, 'Epileptic seizures are relatively common in critically-ill children admitted to the pediatric intensive care unit (PICU). A novel data-driven model was developed at a patient-level approach, based on features extracted from the first hour of ECG recording and the clinical data of the patient.', 'article', ARRAY['EEG','Seizures','Machine Learning'], ARRAY['epileptic seizures','machine learning','pediatric intensive care unit'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
