INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-123', 'Surgical Treatments for Epilepsies in Children Aged 1-36 Months: A Systematic Review', ARRAY['Tsou AY','Kessler SK','Wu M','Abend NS','Massey SL','Treadwell JR'], 'Neurology', 2022, 10, '10.1212/WNL.0000000000201012', '36270898', 'PMC9827129', 'Early life epilepsies (epilepsies in children 1-36 months old) are common and may be refractory to antiseizure medications. Although existing evidence remains sparse and low quality, some infants achieve seizure freedom after surgery.', 'review', ARRAY['Seizures','Review','Pharmacology','Outcomes','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
