INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-124', 'Pharmacologic and Dietary Treatments for Epilepsies in Children Aged 1-36 Months: A Systematic Review', ARRAY['Treadwell JR','Kessler SK','Wu M','Abend NS','Massey SL','Tsou AY'], 'Neurology', 2022, 10, '10.1212/WNL.0000000000201026', '36270899', 'PMC9827128', 'Early life epilepsies are common and often debilitating, but no evidence-based management guidelines exist outside of those for infantile spasms. Little high-quality evidence exists on pharmacologic and dietary treatments for early life epilepsies.', 'review', ARRAY['Seizures','Review','Pharmacology','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
