INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-125', 'Tonic Seizures in a Patient With Lennox-Gastaut Syndrome Manifest as "Icicles" Rather Than "Flames" on Quantitative EEG Analysis', ARRAY['Catenaccio E','Bennett ML','Massey SL','Abend NS','Bergqvist C'], 'J Clin Neurophysiol', 2022, 10, '10.1097/WNP.0000000000000974', '36308754', NULL, 'Quantitative analysis of continuous electroencephalography (QEEG) is increasingly being used to augment seizure detection in critically ill patients. Here, we present a case of a 16-year-old patient with intractable Lennox-Gastaut syndrome secondary to a pathogenic variant in the SCN2A gene who had tonic seizures that manifest as abrupt decreases in power on QEEG.', 'case_report', ARRAY['qEEG','Seizures'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-126', 'Acute Hospital Management of Pediatric Stroke', ARRAY['Surtees TL','Pearson R','Harrar DB','Lee S','Amlie-Lefond CM','Guilliams KP'], 'Semin Pediatr Neurol', 2022, 8, '10.1016/j.spen.2022.100990', '36344020', NULL, 'The field of pediatric stroke has historically been hampered by limited evidence and small patient cohorts. However the landscape of childhood stroke is rapidly changing. Herein, we review the methods of recognition, diagnosis, management, current knowledge gaps and promising research for pediatric stroke.', 'review', ARRAY['Stroke','Review'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['dana-harrar'])
