INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-128', 'Neuromonitoring in neonatal critical care part II: extremely premature infants and critically ill neonates', ARRAY['El-Dib M','Abend NS','Austin T','Boylan G','Chock V','Cilio MR','Greisen G','Hellstrom-Westas L','Lemmers P','Pellicer A','Pressler RM','Sansevere A','Szakmar E','Tsuchida T','Vanhatalo S','Wusthoff CJ'], 'Pediatr Res', 2022, 11, '10.1038/s41390-022-02392-2', '36434203', NULL, 'Neonatal intensive care has expanded from cardiorespiratory care to a holistic approach emphasizing brain health. This work reviews current evidence to assist decision making for the best utilization of neuromonitoring tools to promote neuroprotective care in extremely premature infants and in critically ill neonates.', 'review', ARRAY['Neuromonitoring','EEG','Neonatal','Seizures','Review'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend','arnold-sansevere'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-129', 'Neuromonitoring in neonatal critical care part I: neonatal encephalopathy and neonates with possible seizures', ARRAY['El-Dib M','Abend NS','Austin T','Boylan G','Chock V','Cilio MR','Greisen G','Hellstrom-Westas L','Lemmers P','Pellicer A','Pressler RM','Sansevere A','Tsuchida T','Vanhatalo S','Wusthoff CJ'], 'Pediatr Res', 2022, 12, '10.1038/s41390-022-02393-1', '36476747', NULL, 'The blooming of neonatal neurocritical care over the last decade reflects substantial advances in neuromonitoring and neuroprotection. This work reviews current evidence to assist decision making for best utilization of neuromonitoring modalities in neonates with encephalopathy or with possible seizures.', 'review', ARRAY['Neurocritical Care','Neuromonitoring','EEG','Neonatal','Seizures','Review'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend','arnold-sansevere'])
