INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-131', 'KCNA1 gain-of-function epileptic encephalopathy treated with 4-aminopyridine', ARRAY['Muller P','Takacs DS','Hedrich UBS','Coorg R','Masters L','Glinton KE','Dai H','Cokley JA','Riviello JJ','Lerche H','Cooper EC'], 'Ann Clin Transl Neurol', 2023, 2, '10.1002/acn3.51742', '36793218', 'PMC10109319', 'Precision medicine for Mendelian epilepsy is rapidly developing. We describe an early infant with severely pharmacoresistant multifocal epilepsy. Clinical use of 4-aminopyridine was associated with reduced seizure burden.', 'article', ARRAY['Seizures','Pharmacology','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['james-riviello'])
