INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-132', 'Neuromonitoring in Children with Cerebrovascular Disorders', ARRAY['Harrar DB','Sun LR','Segal JB','Lee S','Sansevere AJ'], 'Neurocrit Care', 2023, 2, '10.1007/s12028-023-01689-2', '36828980', NULL, 'Cerebrovascular disorders are an important cause of morbidity and mortality in children. Here, we review the use of both invasive and noninvasive neuromonitoring modalities in the care of pediatric patients with arterial ischemic stroke, nontraumatic intracranial hemorrhage, and cerebral sinus venous thrombosis.', 'review', ARRAY['Neuromonitoring','Stroke','Review','Outcomes'], ARRAY['arterial ischemic stroke','continuous electroencephalography','intracranial hemorrhage','near-infrared spectroscopy','quantitative electroencephalography'], 'Pediatric', TRUE, ARRAY['dana-harrar','arnold-sansevere'])
