INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-133', 'Brain network properties of clinical versus subclinical seizures among critically ill children', ARRAY['Koster LK','Zamyadi R','Yan L','Payne ET','McBain KL','Dunkley BT','Hahn CD'], 'Clin Neurophysiol', 2023, 2, '10.1016/j.clinph.2023.02.160', '36878028', NULL, 'Electrographic seizures are common among critically ill children, and have been associated with worse outcomes. Clinical expression of seizures correlates with greater alpha synchronization of distributed brain networks.', 'article', ARRAY['EEG','Seizures','Outcomes'], ARRAY['brain networks','child','critical illness','electroencephalography','seizures'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
