INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-134', 'EEG Monitoring in Critically Ill Children: Establishing High-Yield Subgroups', ARRAY['Fung FW','Parikh DS','Donnelly M','Jacobwitz M','Topjian AA','Xiao R','Abend NS'], 'J Clin Neurophysiol', 2023, 3, '10.1097/WNP.0000000000000995', '36893385', 'PMC10492893', 'Continuous EEG monitoring (CEEG) is increasingly used to identify electrographic seizures (ES) in critically ill children, but it is resource intense. We aimed to assess how patient stratification by known ES risk factors would impact CEEG utilization.

This was a prospective observational study of critically ill children with encephalopathy who underwent CEEG. We calculated the average CEEG duration required to identify a patient with ES for the full cohort and subgroups stratified by known ES risk factors.

ES occurred in 345 of 1,399 patients (25%). For the full cohort, an average of 90 hours of CEEG would be required to identify 90% of patients with ES. If subgroups of patients were stratified by age, clinically evident seizures before CEEG initiation, and early EEG risk factors, then 20 to 1,046 hours of CEEG would be required to identify a patient with ES. Patients with clinically evident seizures before CEEG initiation and EEG risk factors present in the initial hour of CEEG required only 20 (<1 year) or 22 (≥1 year) hours of CEEG to identify a patient with ES. Conversely, patients with no clinically evident seizures before CEEG initiation and no EEG risk factors in the initial hour of CEEG required 405 (<1 year) or 1,046 (≥1 year) hours of CEEG to identify a patient with ES. Patients with clinically evident seizures before CEEG initiation or EEG risk factors in the initial hour of CEEG required 29 to 120 hours of CEEG to identify a patient with ES.

Stratifying patients by clinical and EEG risk factors could identify high- and low-yield subgroups for CEEG by considering ES incidence, the duration of CEEG required to identify ES, and subgroup size. This approach may be critical for optimizing CEEG resource allocation.', 'article', ARRAY['EEG','Neonatal','Seizures','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-135', 'Drug-resistant seizures associated with hyperinflammatory monocytes in FIRES', ARRAY['Howe CL','Johnson RK','Overlee BL','Sagen JA','Mehta N','Farias-Moeller R'], 'Ann Clin Transl Neurol', 2023, 3, '10.1002/acn3.51755', '36924141', 'PMC10187718', 'Therapeutic strategies for patients with febrile infection-related epilepsy syndrome (FIRES) are limited, ad hoc, and frequently ineffective. Based on evidence that inflammation drives pathogenesis in FIRES, we used ex vivo stimulation of peripheral blood mononuclear cells (PBMCs) to characterize the monocytic response profile before and after therapy in a child successfully treated with dexamethasone delivered intrathecally six times between hospital Day 23 and 40 at 0.25 mg/kg/dose.

PBMCs were isolated from serial blood draws acquired during refractory status epilepticus (RSE) and following resolution associated with intrathecal dexamethasone therapy in a previously healthy 9-year-old male that presented with seizures following Streptococcal pharyngitis. Cells were stimulated with bacterial or viral ligands and cytokine release was measured and compared to responses in age-matched healthy control PBMCs. Levels of inflammatory factors in the blood and CSF were also measured and compared to pediatric healthy control ranges.

During RSE, serum levels of IL6, CXCL8, HMGB1, S100A8/A9, and CRP were significantly elevated. IL6 was elevated in CSF. Ex vivo stimulation of PBMCs collected during RSE revealed hyperinflammatory release of IL6 and CXCL8 in response to bacterial stimulation. Following intrathecal dexamethasone, RSE resolved, inflammatory levels normalized in serum and CSF, and the PBMC hyperinflammatory response renormalized.

FIRES may be associated with a hyperinflammatory monocytic response to normally banal bacterial pathogens. This hyperinflammatory response may induce a profound neutrophil burden and the consequent release of factors that further exacerbate inflammation and drive neuroinflammation. Intrathecal dexamethasone may resolve RSE by resetting this inflammatory feedback loop.', 'case_report', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-136', 'Leveraging electronic medical record-embedded standardised electroencephalogram reporting to develop neonatal seizure prediction models: a retrospective cohort study', ARRAY['McKee JL','Kaufman MC','Gonzalez AK','Fitzgerald MP','Massey SL','Fung F','Kessler SK','Witzman S','Abend NS','Helbig I'], 'Lancet Digit Health', 2023, 4, '10.1016/S2589-7500(23)00004-3', '36963911', 'PMC10065843', 'Accurate prediction of seizures can help to direct resource-intense continuous electroencephalogram (CEEG) monitoring to neonates at high risk of seizures. We aimed to use data from standardised EEG reports to generate seizure prediction models for vulnerable neonates.

In this retrospective cohort study, we included neonates who underwent CEEG during the first 30 days of life at the Children''s Hospital of Philadelphia (Philadelphia, PA, USA). The hypoxic ischaemic encephalopathy subgroup included only patients with CEEG data during the first 5 days of life, International Classification of Diseases, revision 10, codes for hypoxic ischaemic encephalopathy, and documented therapeutic hypothermia. In January, 2018, we implemented a novel CEEG reporting system within the electronic medical record (EMR) using common data elements that incorporated standardised terminology. All neonatal CEEG data from Jan 10, 2018, to Feb 15, 2022, were extracted from the EMR using age at the time of CEEG. We developed logistic regression, decision tree, and random forest models of neonatal seizure prediction using EEG features on day 1 to predict seizures on future days.

We evaluated 1117 neonates, including 150 neonates with hypoxic ischaemic encephalopathy, with CEEG data reported using standardised templates between Jan 10, 2018, and Feb 15, 2022. Implementation of a consistent EEG reporting system that documents discrete and standardised EEG variables resulted in more than 95% reporting of key EEG features. Several EEG features were highly correlated, and patients could be clustered on the basis of specific features. However, no simple combination of features adequately predicted seizure risk. We therefore applied computational models to complement clinical identification of neonates at high risk of seizures. Random forest models incorporating background features performed with classification accuracies of up to 90% (95% CI 83-94) for all neonates and 97% (88-99) for neonates with hypoxic ischaemic encephalopathy; recall (sensitivity) of up to 97% (91-100) for all neonates and 100% (100-100) for neonates with hypoxic ischaemic encephalopathy; and precision (positive predictive value) of up to 92% (84-96) in the overall cohort and 97% (80-99) in neonates with hypoxic ischaemic encephalopathy.

Using data extracted from the standardised EEG report on the first day of CEEG, we predict the presence or absence of neonatal seizures on subsequent days with classification performances of more than 90%. This information, incorporated into routine care, could guide decisions about the necessity of continuing EEG monitoring beyond the first day, thereby improving the allocation of limited CEEG resources. Additionally, this analysis shows the benefits of standardised clinical data collection, which can drive learning health system approaches to personalised CEEG use.

Children''s Hospital of Philadelphia, the Hartwell Foundation, the National Institute of Neurological Disorders and Stroke, and the Wolfson Foundation.', 'article', ARRAY['EEG','Neonatal','Seizures','Machine Learning','Stroke'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-137', 'Seizure Burden and Neurologic Outcomes After Neonatal Encephalopathy', ARRAY['Alharbi HM','Pinchefsky EF','Tran MA','Salazar Cerda CI','Parokaran Varghese J','Kamino D','Widjaja E','Mamak E','Ly L','Nevalainen P','Hahn CD','Tam EWY'], 'Neurology', 2023, 3, '10.1212/WNL.0000000000207202', '36990719', 'PMC10186227', 'Seizures are common during neonatal encephalopathy (NE), but the contribution of seizure burden (SB) to outcomes remains controversial. This study aims to examine the relationship between electrographic SB and neurologic outcomes after NE.

This prospective cohort study recruited newborns ≥36 weeks postmenstrual age around 6 hours of life between August 2014 and November 2019 from a neonatal intensive care unit (NICU). Participants underwent continuous electroencephalography for at least 48 hours, brain MRI within 3-5 days of life, and structured follow-up at 18 months. Electrographic seizures were identified by board-certified neurophysiologists and quantified as total SB and maximum hourly SB. A medication exposure score was calculated based on all antiseizure medications given during NICU admission. Brain MRI injury severity was classified based on basal ganglia and watershed scores. Developmental outcomes were measured using the Bayley Scales of Infant Development, Third Edition. Multivariable regression analyses were performed, adjusting for significant potential confounders.

Of 108 enrolled infants, 98 had continuous EEG (cEEG) and MRI data collected, of which 5 were lost to follow-up, and 6 died before age 18 months. All infants with moderate-severe encephalopathy completed therapeutic hypothermia. cEEG-confirmed neonatal seizures occurred in 21 (24%) newborns, with a total SB mean of 12.5 ± 36.4 minutes and a maximum hourly SB mean of 4 ± 10 min/h. After adjusting for MRI brain injury severity and medication exposure, total SB was significantly associated with lower cognitive (-0.21, 95% CI -0.33 to -0.08,= 0.002) and language (-0.25, 95% CI -0.39 to -0.11,= 0.001) scores at 18 months. Total SB of 60 minutes was associated with 15-point decline in language scores and 70 minutes for cognitive scores. However, SB was not significantly associated with epilepsy, neuromotor score, or cerebral palsy (> 0.1).

Higher SB during NE was independently associated with worse cognitive and language scores at 18 months, even after adjusting for exposure to antiseizure medications and severity of brain injury. These observations support the hypothesis that neonatal seizures occurring during NE independently contribute to long-term outcomes.', 'article', ARRAY['EEG','Neonatal','Seizures','Pharmacology'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-138', 'Case Report: Successful Anterior Circulation Thrombectomy After 24 Hours in an Adolescent', ARRAY['Vinarsky V','Sun LR','Yedavalli VS','Schleifer L','Arthur K','Hui F','Harrar DB'], 'Pediatr Neurol', 2023, 1, '10.1016/j.pediatrneurol.2023.01.014', '37003190', NULL, 'Arterial ischemic stroke in children comes with the potential for morbidity and mortality and can result in high cost of care and decreased quality of life among survivors. Children with arterial ischemic stroke are increasingly being treated with mechanical thrombectomy, but little is known about the risks and benefits 24 hours after a patient''s last known well (LKW) time.

A 16-year-old female presented with acute onset of dysarthria and right hemiparesis with LKW time 22 hours prior. Pediatric National Institutes of Health Stroke Scale score was 12. Magnetic resonance imaging showed diffusion restriction and T2 hyperintensity primarily in the left basal ganglia. Magnetic resonance angiography revealed left M1 occlusion. Arterial spin labeling showed a large apparent perfusion deficit. She underwent thrombectomy with TICI3 recanalization 29.5 hours after LKW time.

At 2-month follow-up, her examination showed moderate right-hand weakness and mild diminished sensation of the right arm.

Adult thrombectomy trials include patients up to 24 hours from their LKW time and suggest that some patients maintain a favorable perfusion profile for over 24 hours. Without intervention many go on to experience infarct expansion. The persistence of a favorable perfusion profile likely reflects robust collateral circulation. We hypothesized our patient was relying on collateral circulation to maintain the noninfarcted areas of her left middle cerebral artery territory. Owing to concern for eventual collateral failure, thrombectomy outside of the 24-hour window was performed. This case serves as a call to action to better understand the impact of collateral circulation on cerebral perfusion in children with large vessel occlusions and delineate which children may benefit from thrombectomy in a delayed time window.', 'case_report', ARRAY['Stroke','Outcomes'], ARRAY['arterial ischemic stroke','collateral circulation','pediatric','thrombectomy'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-139', 'An Initial Experience of Completion Hemispherotomy via Magnetic Resonance-Guided Laser Interstitial Therapy', ARRAY['Ravindra VM','Ruggieri L','Gadgil N','Addison AP','Patino I','Gonda DD','Chu J','Whitehead L','Anderson A','Diaz-Medina G','Houck K','Katyayan A','Masters L','Nath A','Quach M','Riviello JJ','Seto E','Sully KE','Agurs L','Sen S','Handoko M','Coorg R','Ali I','Ikeda D','Weiner H','Curry DJ'], 'Stereotact Funct Neurosurg', 2023, 4, '10.1159/000528452', '37062282', NULL, 'In carefully selected patients with medically refractory epilepsy, disconnective hemispherotomy can result in significant seizure freedom; however, incomplete disconnection can result in ongoing seizures and poses a significant challenge. Completion hemispherotomy provides an opportunity to finish the disconnection. We describe the use of magnetic resonance-guided laser interstitial thermal ablation (MRgLITT) for completion hemispherotomy.

Patients treated with completion hemispherotomy using MRgLITT at our institution were identified. Procedural and seizure outcomes were evaluated retrospectively.

Five patients (3 males) underwent six MRgLITT procedures (one child treated twice) for completion hemispherotomy at a median age of 6 years (range 1.8-12.9). Two children had hemimegalencephaly, two had Rasmussen encephalitis, and one had polymicrogyria. All five children had persistent seizures likely secondary to incomplete disconnection after their functional hemispherotomy. The mean time from open hemispherotomy to MRgLITT was 569.5 ± 272.4 days (median 424, range 342-1,095). One patient underwent stereoelectroencephalography before MRgLITT. The mean number of ablation targets was 2.3 ± 0.47 (median 2, range 2-3). The mean length of the procedure was 373 min ± 68.9 (median 374, range 246-475). Four of the five patients were afforded improvement in their neurocognitive functioning and speech performance after ablation, with mean daily seizure frequency at 1 year of 1.03 ± 1.98 (median 0, range 0-5). Two patients achieved Engel Class I outcomes at 1 year after ablation, one was Engel Class III, and two were Engel Class IV. The mean follow-up time was 646.8 ± 179.5 days (median 634, range 384-918). No MRgLITT-related complications occurred. Delayed retreatment (>1 year) occurred in three patients: one child underwent redo ablation and two underwent anatomic hemispherectomy.

We have demonstrated the feasibility of a minimally invasive approach for completion hemispherotomy using MRgLITT. Delayed retreatment was needed in three patients; thus, further study of this technique with comparison to other surgical techniques is warranted.', 'article', ARRAY['Cardiac Arrest','EEG','Seizures','Pharmacology'], ARRAY['hemispherectomy','hemispherotomy','hydrocephalus','laser ablation','medically refractory epilepsy','pediatric epilepsy','stereoelectroencephalography'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-140', 'Investigating the genetic contribution in febrile infection-related epilepsy syndrome and refractory status epilepticus', ARRAY['deCampo D','Xian J','Karlin A','Sullivan KR','Ruggiero SM','Galer P','Ramos M','Abend NS','Gonzalez A','Helbig I'], 'Front Neurol', 2023, 4, '10.3389/fneur.2023.1161161', '37077567', 'PMC10106651', 'Febrile infection-related epilepsy syndrome (FIRES) is a severe childhood epilepsy with refractory status epilepticus after a typically mild febrile infection. The etiology of FIRES is largely unknown, and outcomes in most individuals with FIRES are poor.

Here, we reviewed the current state-of-the art genetic testing strategies in individuals with FIRES. We performed a systematic computational analysis to identify individuals with FIRES and characterize the clinical landscape using the Electronic Medical Records (EMR). Among 25 individuals with a confirmed FIRES diagnosis over the last decade, we performed a comprehensive review of genetic testing and other diagnostic testing.

Management included use of steroids and intravenous immunoglobulin (IVIG) in most individuals, with an increased use of immunomodulatory agents, including IVIG, plasma exchange (PLEX) and immunosuppressants such as cytokine inhibitors, and the ketogenic diet after 2014. Genetic testing was performed on a clinical basis in almost all individuals and was non-diagnostic in all patients. We compared FIRES with both status epilepticus (SE) and refractory status epilepticus (RSE) as a broader comparison cohort and identified genetic causes in 36% of patients with RSE. The difference in genetic signatures between FIRES and RSE suggest distinct underlying etiologies. In summary, despite the absence of any identifiable etiologies in FIRES, we performed an unbiased analysis of the clinical landscape, identifying a heterogeneous range of treatment strategies and characterized real-world clinical practice.

FIRES remains one of the most enigmatic conditions in child neurology without any known etiologies to date despite significant efforts in the field, suggesting a clear need for further studies and novel diagnostic and treatment approaches.', 'article', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Outcomes'], ARRAY['febrile infection-related epilepsy syndrome','genetics','new onset refractory status epilepticus','pediatric epilepsy','refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-141', 'Extracorporeal Membrane Oxygenation for Neonates With Congenital Diaphragmatic Hernia: Prevalence of Seizures and Outcomes', ARRAY['Danzer E','Massey SL','Flohr SJ','Mathew L','Hoffman C','Abramson A','Selenski P','Canning CE','Eppley E','Connelly JT','Herkert L','Rintoul NE','Adzick NS','Abend NS','Hedrick HL'], 'Pediatr Crit Care Med', 2023, 2, '10.1097/PCC.0000000000003197', '37140337', 'PMC10160669', 'We aimed to determine the prevalence of electrographic seizures and associated odds of adverse outcomes of electrographic seizures in neonates with congenital diaphragmatic hernia (CDH) receiving extracorporeal membrane oxygenation (ECMO).

Retrospective, descriptive case series.

Neonatal ICU (NICU) in a quaternary care institution.

All neonates with CDH receiving ECMO undergoing continuous electroencephalographic monitoring (CEEG) and follow-up between January 2012 and December 2019.

None.

All eligible neonates with CDH receiving ECMO underwent CEEG (n = 75). Electrographic seizures occurred in 14 of 75 (19%): they were exclusively electrographic-only in nine of 14, both electrographic-only and electroclinical in three of 14, and electroclinical only in two of 14. Two neonates developed status epilepticus. We identified an association between presence of seizures, rather than not, and longer duration of initial session of CEEG monitoring (55.7 hr [48.2-87.3 hr] vs 48.0 hr [43.0-48.3 hr]; p = 0.001). We also found an association between presence of seizures, rather than not, and greater odds of use of a second CEEG monitoring (12/14 vs 21/61; odds ratio [OR], 11.43 [95% CI, 2.34-55.90; p = 0.0026). Most neonates with seizures (10/14), experienced their onset of seizures more than 96 hours after the start of ECMO. Overall, the presence of electrographic seizures, compared with not, was associated with lower odds of survival to NICU discharge (4/14 vs 49/61; OR 0.10 [95% CI 0.03 to 0.37], p = 0.0006). Also, the presence of seizures-rather than not-was associated with greater odds of a composite of death and all abnormal outcomes on follow-up (13/14 vs 26/61; OR, 17.5; 95% CI, 2.15-142.39; p = 0.0074).

Nearly one in five neonates with CDH receiving ECMO developed seizures during the ECMO course. Seizures were predominantly electrographic-only and when present were associated with great odds of adverse outcomes. The current study provides evidence to support standardized CEEG in this population.', 'article', ARRAY['Status Epilepticus','EEG','Neonatal','ECMO/ECLS'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-142', 'Neural representations of self-perception of voice: An intracortical evoked potential analysis based on an adolescent with right temporal lobe epilepsy', ARRAY['Andrade-Machado R','Javarayee P','Koop JI','Farias-Moeller R','Kim I','Lew SM'], 'Seizure', 2023, 5, '10.1016/j.seizure.2023.04.003', '37172443', NULL, 'The neural bases for language perception have been studied elsewhere using Transcranial Magnetic Stimulation, functional Magnetic Resonance Imaging and Direct Cortical Stimulation. However, to our knowledge, there is no previous report about a patient identifying the change in his voice tone, speed, and prosody because of right temporal cortical stimulation. Nor has there been a cortico-cortical evoked potential (CCEP) assessment of the network underlying this process.

We present CCEP from a patient with right focal refractory temporal lobe epilepsy of tumoral etiology who reported changes in the perception of his own speech prosody during stimulation. This report will serve as a complement to the understanding of the neural networks of language and prosody.

The present report shows that right superior temporal gyrus, transverse temporal gyrus, right amygdala, hippocampus, and fusiform gyrus (FG) are part of the neural network subjacent to own human voice perception.', 'case_report', ARRAY['Machine Learning','Epilepsy'], ARRAY['cortico-cortical evoked potentials','direct cortical stimulation','hippocampus','language','temporal lobe','temporal lobe epilepsy'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-143', 'Intrathecal Dexamethasone in Febrile Infection-Related Epilepsy Syndrome: A Case Report', ARRAY['Mehta NP','Sawdy R','Maloney K','Overlee B','Johnson RK','Howe CL','Farias-Moeller R'], 'Neurol Clin Pract', 2023, 5, '10.1212/CPJ.0000000000200153', '37197372', 'PMC10184555', 'Febrile infection-related epilepsy syndrome (FIRES) is characterized by explosive onset refractory status epilepticus (RSE) in healthy individuals that is refractory to antiseizure medication (ASM), continuous anesthetic infusions (CIs), and immunomodulators. Recently, a case series of patients receiving intrathecal dexamethasone (IT-DEX) was reported with improved RSE control.

We present a child with FIRES with favorable outcome after receiving concomitant anakinra and IT-DaEX. A 9-year-old male patient presented with encephalopathy following a febrile illness. He developed seizures evolving to RSE refractory to multiple ASM, 3 CIs, steroids, IVIG, plasmapheresis, ketogenic diet (KD), and anakinra. After continued seizures and inability to wean off CI, IT-DEX was initiated.

He received 6 doses of IT-DEX with resolution of RSE, rapid wean off CI, and improved inflammatory markers. At discharge, he was ambulating with assistance, speaking 2 languages, and ingesting food orally.

FIRES is a neurologically devastating syndrome with high mortality and morbidity. Proposed guidelines and various treatment strategies are becoming available in the literature. Although treatment with KD, anakinra, and tocilizumab has been successful in previous FIRES cases, our results suggest that the addition of IT-DEX may allow for faster weaning off CI and better cognitive outcomes when initiated early in the course.', 'case_report', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-144', 'Safety of intravenous lacosamide in hospitalized children and neonates', ARRAY['Fong SL','Utidjian L','Kaur M','Abend NS','Wainwright MS','Grande KM','Foskett N','Roebling R','Guerriero RM','Jain B','Rao S','Stoltenberg M','Williams P','Yuen N','Dickinson K','McDonald J','Maltenfort M','Forrest CB'], 'Epilepsia', 2023, 6, '10.1111/epi.17676', '37287398', NULL, 'Seizures are common in critically ill children and neonates, and these patients would benefit from intravenous (IV) antiseizure medications with few adverse effects. We aimed to assess the safety profile of IV lacosamide (LCM) among children and neonates.

This retrospective multicenter cohort study examined the safety of IV LCM use in 686 children and 28 neonates who received care between January 2009 and February 2020.

Adverse events (AEs) were attributed to LCM in only 1.5% (10 of 686) of children, including rash (n = 3, .4%), somnolence (n = 2, .3%), and bradycardia, prolonged QT interval, pancreatitis, vomiting, and nystagmus (n = 1, .1% each). There were no AEs attributed to LCM in the neonates. Across all 714 pediatric patients, treatment-emergent AEs occurring in >1% of patients included rash, bradycardia, somnolence, tachycardia, vomiting, feeling agitated, cardiac arrest, tachyarrhythmia, low blood pressure, hypertension, decreased appetite, diarrhea, delirium, and gait disturbance. There were no reports of PR interval prolongation or severe cutaneous adverse reactions. When comparing children who received a recommended versus a higher than recommended initial dose of IV LCM, there was a twofold increase in the risk of rash in the higher dose cohort (adjusted incidence rate ratio = 2.11, 95% confidence interval = 1.02-4.38).

This large observational study provides novel evidence demonstrating the tolerability of IV LCM in children and neonates.', 'article', ARRAY['Cardiac Arrest','Neonatal','Seizures','Pharmacology'], ARRAY['antiseizure medications','epilepsy','neonatal','pediatric'], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-145', 'Early Clinical Variables Associated With Refractory Convulsive Status Epilepticus in Children', ARRAY['Peariso K','Arya R','Glauser T','Abend NS','Barcia Aguilar C','Amengual-Gual M','Anderson A','Appavu BL','Brenton JN','Carpenter J','Chapman KE','Clark J','Gaillard WD','Ga&#xed;nza-Lein M','Goldstein J','Goodkin H','Grinspan Z','Guerriero RM','Horn PS','Huh L','Kahoud R','Kelley SA','Kossoff EH','Kapur K','Lai YC','Marquis BO','McDonough T','Mikati MA','Morgan L','Novotny E','Ostendorf AP','Payne ET','Piantino J','Riviello J','Sands T','Stafstrom CE','Tasker RC','Tchapyjnikov D','Vasquez A','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Neurology', 2023, 6, '10.1212/WNL.0000000000207472', '37295955', 'PMC10401687', 'The objective of this study was to determine patient-specific factors known proximate to the presentation to emergency care associated with the development of refractory convulsive status epilepticus (RSE) in children.

An observational case-control study was conducted comparing pediatric patients (1 month-21 years) with convulsive SE whose seizures stopped after benzodiazepine (BZD) and a single second-line antiseizure medication (ASM) (responsive established status epilepticus [rESE]) with patients requiring more than a BZD and a single second-line ASM to stop their seizures (RSE). These subpopulations were obtained from the pediatric Status Epilepticus Research Group study cohort. We explored clinical variables that could be acquired early after presentation to emergency medical services with univariate analysis of the raw data. Variables with< 0.1 were retained for univariable and multivariable regression analyses. Multivariable logistic regression models were fit to age-matched and sex-matched data to obtain variables associated with RSE.

We compared data from a total of 595 episodes of pediatric SE. Univariate analysis demonstrated no differences in time to the first BZD (RSE 16 minutes [IQR 5-45]; rESE 18 minutes [IQR 6-44],= 0.068). Time to second-line ASM was shorter in patients with RSE (RSE 65 minutes; rESE 70 minutes;= 0.021). Both univariable and multivariable regression analyses revealed a family history of seizures (OR 0.37; 95% CI 0.20-0.70,= 0.0022) or a prescription for rectal diazepam (OR 0.21; 95% CI 0.078-0.53,= 0.0012) was associated with decreased odds of RSE.

Time to initial BZD or second-line ASM was not associated with progression to RSE in our cohort of patients with rESE. A family history of seizures and a prescription for rectal diazepam were associated with a decreased likelihood of progression to RSE. Early attainment of these variables may help care for pediatric rESE in a more patient-tailored manner.

This study provides Class II evidence that patient and clinical factors may predict RSE in children with convulsive seizures.', 'article', ARRAY['Status Epilepticus','Pharmacology','Biomarkers'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend','brian-appavu','adam-ostendorf','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-146', 'Responsive Neurostimulation for the Treatment of Children With Drug-Resistant Epilepsy in Tuberous Sclerosis Complex', ARRAY['Karakas C','Houck K','Handoko M','Trandafir C','Coorg R','Haneef Z','Riviello JJ','Weiner HL','Curry D','Ali I'], 'Pediatr Neurol', 2023, 5, '10.1016/j.pediatrneurol.2023.05.008', '37302216', NULL, 'To review seizure outcomes in children with tuberous sclerosis complex (TSC) and drug-resistant epilepsy (DRE) treated with the responsive neurostimulation (RNS) System.

We retrospectively reviewed children (<21 years old) with TSC implanted with the RNS System at Texas Children''s Hospital between July 2016 and May 2022.

Five patients meeting the search criteria were identified (all female). The median age of the RNS implantation was 13 years (range: 5 to 20 years). The median epilepsy duration before the RNS implantation was 13 years (range: 5 to 20 years). Surgeries before RNS implantation included vagus nerve stimulator placement (n = 2), left parietal resection (n = 1), and corpus callosotomy (n = 1). The median number of antiseizure medications tried before RNS was 8 (range: 5 to 12). The rationale for the RNS System implantation included seizure onset in eloquent cortex (n = 3) and multifocal seizures (n = 2). The maximum current density for each patient ranged between 1.8 and 3.5 μC/cm, with an average daily stimulation of 2240 (range: 400 to 4200). There was an 86% median seizure reduction (range 0% to 99%) at a median follow-up duration of 25 months (range: 17 to 25 months). No patient experienced implantation or stimulation-related complications.

We observed a favorable improvement in seizure frequency in pediatric patients with DRE secondary to TSC treated with the RNS System. The RNS System may be a safe and effective treatment for DRE in children with TSC.', 'article', ARRAY['Seizures','Pharmacology','Outcomes','Epilepsy'], ARRAY['epilepsy surgery','neurostimulation','pediatric','rns','tuberous sclerosis complex'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-147', 'Inaccuracies in Parental Reporting of Treated Epileptic Spasms: Both Under- and Over-Reporting', ARRAY['Takacs DS','Katyayan A','Vanderslice K','Riviello JJ'], 'Pediatr Neurol', 2023, 5, '10.1016/j.pediatrneurol.2023.05.010', '37331271', NULL, 'The purpose of this study was to evaluate the accuracy of parental reporting of epileptic spasms (ES) after 14 days of appropriate medical therapy for new-onset ES by comparison with extended video electroencephalography (vEEG) monitoring results.

Fifty-eight patients were identified from August 2019 to February 2021 with new-onset ES, confirmed on vEEG. Patients were initiated on appropriate treatment (high-dose steroids or vigabatrin). After two weeks of therapy, patients underwent overnight (18 to 24 hours) vEEG monitoring in the epilepsy monitoring unit. Parental reporting of presence or absence of ES on admission was compared with results of vEEG monitoring.

The 58 patients ranged in age from three to 20 months (average 7.8 months). An underlying etiology was identified in 78%, whereas 22% patients had unknown etiology. The overall accuracy of parental reporting was 74% (43 of 58) when compared with results of vEEG within 14 to 18 days of starting therapy. Of these, 65% (28 of 43) reported ES resolution and 35% (15 of 43) reported continued ES. Of the 26% (15 of 58) families who were incorrect at two-week follow-up, 67% (10 of 15) reported resolution of ES. However, a minority of families, 33% (five of 15), who continued to report spasms clinically, were inaccurate.

Although a majority of inaccurate parental reports at two weeks of treatment were due to unrecognized ES (a widely known phenomenon), a minority were conversely inaccurate due to persistent over-reporting of ES. This fact highlights the importance of correlating parental history with objective vEEG monitoring, to prevent inappropriate escalation of medication therapy.', 'article', ARRAY['EEG','Seizures','Pharmacology'], ARRAY['electroencephalography','epileptic spasms','infantile spasms','west syndrome'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-148', 'Automated Interpretation of Clinical Electroencephalograms Using Artificial Intelligence', ARRAY['Tveit J','Aurlien H','Plis S','Calhoun VD','Tatum WO','Schomer DL','Arntsen V','Cox F','Fahoum F','Gallentine WB','Gardella E','Hahn CD','Husain AM','Kessler S','Kural MA','Nascimento FA','Tankisi H','Ulvin LB','Wennberg R','Beniczky S'], 'JAMA Neurol', 2023, 8, '10.1001/jamaneurol.2023.1645', '37338864', 'PMC10282956', 'Electroencephalograms (EEGs) are a fundamental evaluation in neurology but require special expertise unavailable in many regions of the world. Artificial intelligence (AI) has a potential for addressing these unmet needs. Previous AI models address only limited aspects of EEG interpretation such as distinguishing abnormal from normal or identifying epileptiform activity. A comprehensive, fully automated interpretation of routine EEG based on AI suitable for clinical practice is needed.

To develop and validate an AI model (Standardized Computer-based Organized Reporting of EEG-Artificial Intelligence [SCORE-AI]) with the ability to distinguish abnormal from normal EEG recordings and to classify abnormal EEG recordings into categories relevant for clinical decision-making: epileptiform-focal, epileptiform-generalized, nonepileptiform-focal, and nonepileptiform-diffuse.

In this multicenter diagnostic accuracy study, a convolutional neural network model, SCORE-AI, was developed and validated using EEGs recorded between 2014 and 2020. Data were analyzed from January 17, 2022, until November 14, 2022. A total of 30 493 recordings of patients referred for EEG were included into the development data set annotated by 17 experts. Patients aged more than 3 months and not critically ill were eligible. The SCORE-AI was validated using 3 independent test data sets: a multicenter data set of 100 representative EEGs evaluated by 11 experts, a single-center data set of 9785 EEGs evaluated by 14 experts, and for benchmarking with previously published AI models, a data set of 60 EEGs with external reference standard. No patients who met eligibility criteria were excluded.

Diagnostic accuracy, sensitivity, and specificity compared with the experts and the external reference standard of patients'' habitual clinical episodes obtained during video-EEG recording.

The characteristics of the EEG data sets include development data set (N = 30 493; 14 980 men; median age, 25.3 years [95% CI, 1.3-76.2 years]), multicenter test data set (N = 100; 61 men, median age, 25.8 years [95% CI, 4.1-85.5 years]), single-center test data set (N = 9785; 5168 men; median age, 35.4 years [95% CI, 0.6-87.4 years]), and test data set with external reference standard (N = 60; 27 men; median age, 36 years [95% CI, 3-75 years]). The SCORE-AI achieved high accuracy, with an area under the receiver operating characteristic curve between 0.89 and 0.96 for the different categories of EEG abnormalities, and performance similar to human experts. Benchmarking against 3 previously published AI models was limited to comparing detection of epileptiform abnormalities. The accuracy of SCORE-AI (88.3%; 95% CI, 79.2%-94.9%) was significantly higher than the 3 previously published models (P < .001) and similar to human experts.

In this study, SCORE-AI achieved human expert level performance in fully automated interpretation of routine EEGs. Application of SCORE-AI may improve diagnosis and patient care in underserved areas and improve efficiency and consistency in specialized epilepsy centers.', 'article', ARRAY['EEG','Machine Learning','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-149', 'A Survey of Pediatric Neurocritical Care Fellowship Training in North America', ARRAY['Hong SJ','Wainwright MS','Abend NS','Appavu BL','Francoeur C','Erklauer JC','Guerguerian AM','Guerriero RM','Guilliams KP','Lee-Eng J','Loeb J','Lovett ME','Murphy SA','Pardo AC','Pineda JA','Ruzas CM','Topjian AA'], 'Pediatr Neurol', 2023, 5, '10.1016/j.pediatrneurol.2023.05.015', '37356227', NULL, 'Pediatric neurocritical care (PNCC) has emerged as a field to care for children at the intersection of critical illness and neurological dysfunction. PNCC fellowship programs evolved over the past decade to train physicians to fill this clinical need. We aimed to characterize PNCC fellowship training infrastructure and curriculum in the United States and Canada.

Web-based survey of PNCC fellowship program leaders during November 2019 to January 2020.

There were 14 self-identified PNCC fellowship programs. The programs were supported by Child Neurology and/or Pediatric Critical Care Medicine divisions at tertiary/quaternary care institutions. Most programs accepted trainees who were board-eligible or board-certified in child neurology or pediatric critical care medicine. Clinical training consisted mostly of rotations providing PNCC consultation (n = 13) or as a provider on the pediatric intensive care unit-based neurointensive care team (n = 2). PNCC-specific didactics were delivered at most institutions (n = 13). All institutions provided training in electroencephalography use in the intensive care unit and declaration of death by neurological criteria (n = 14). Scholarly activity was supported by most programs, including protected time for research (n = 10).

We characterized PNCC fellowship training in the United States and Canada, which in this continuously evolving field, lays the foundation for exploring standardization of training going forward.', 'article', ARRAY['Neurocritical Care','EEG','Survey','Education'], ARRAY['critical illness','graduate medical education','intensive care units','neurological disorder','neurology','pediatric'], 'Pediatric', TRUE, ARRAY['nicholas-abend','brian-appavu','conall-francoeur'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-150', 'The truth Hertz-synchronization of electroencephalogram signals with physiological waveforms recorded in an intensive care unit', ARRAY['Goodwin AJ','Dixon W','Mazwi M','Hahn CD','Meir T','Goodfellow SD','Kazazian V','Greer RW','McEwan A','Laussen PC','Eytan D'], 'Physiol Meas', 2023, 8, '10.1088/1361-6579/ace49e', '37406636', NULL, 'The ability to synchronize continuous electroencephalogram (cEEG) signals with physiological waveforms such as electrocardiogram (ECG), invasive pressures, photoplethysmography and other signals can provide meaningful insights regarding coupling between brain activity and other physiological subsystems. Aligning these datasets is a particularly challenging problem because device clocks handle time differently and synchronization protocols may be undocumented or proprietary.We used an ensemble-based model to detect the timestamps of heartbeat artefacts from ECG waveforms recorded from inpatient bedside monitors and from cEEG signals acquired using a different device. Vectors of inter-beat intervals were matched between both datasets and robust linear regression was applied to measure the relative time offset between the two datasets as a function of time.The timing error between the two unsynchronized datasets ranged between -84 s and +33 s (mean 0.77 s, median 4.31 s, IQR25-4.79 s, IQR75 11.38s). Application of our method improved the relative alignment to within ± 5ms for more than 61% of the dataset. The mean clock drift between the two datasets was 418.3 parts per million (ppm) (median 414.6 ppm, IQR25 411.0 ppm, IQR75 425.6 ppm). A signal quality index was generated that described the quality of alignment for each cEEG study as a function of time.We developed and tested a method to retrospectively time-align two clinical waveform datasets acquired from different devices using a common signal. The method was applied to 33,911h of signals collected in a paediatric critical care unit over six years, demonstrating that the method can be applied to long-term recordings collected under clinical conditions. The method can account for unknown clock drift rates and the presence of discontinuities caused by clock resynchronization events.', 'article', ARRAY['EEG'], ARRAY['ecg','eeg','icu','clock drift','signal alignment','timing errors'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-151', 'Pediatric Cerebral Sinovenous Thrombosis and Risk for Epilepsy', ARRAY['Karlin AR','Kumar NK','Vossough A','Abend NS','Ichord RN','Beslow LA'], 'Pediatr Neurol', 2023, 5, '10.1016/j.pediatrneurol.2023.05.014', '37453223', NULL, 'Cerebral sinovenous thrombosis (CSVT) is a rare form of pediatric stroke with significant morbidity. We determined cumulative incidence and predictors of acute seizures, remote seizures, and epilepsy after pediatric CSVT.

Retrospective analysis of 131 neonates and children with neuroimaging-confirmed CSVT enrolled between 2008 and 2020 from a single-center prospective consecutive cohort. Acute seizures occurred within 7 days of CSVT. Remote seizures occurred >7 days after CSVT. Epilepsy was defined as 2 or more remote seizures at least 24 hours apart. Survival methods determined the incidence of and risk factors for remote seizures and epilepsy.

Acute seizures occurred in 14/33 neonates (42%) and 19/98 children (19%). Among children, hemorrhage predicted acute seizures (OR 6.6, 95% CI 1.9 to 22.4, P = 0.003). Remote seizures occurred in six neonates; five developed epilepsy. Remote seizures occurred in 14 children; 10 developed epilepsy. In neonates, 1- and 3-year epilepsy-free survival were 86% (95% CI 62% to 95%) and 66% (95% CI 32% to 87%). One- and 3-year epilepsy-free survival in children were 88% (95% CI 76% to 92%) and 84% (95% CI 59% to 86%). In multivariable analysis for children, acute seizures predicted epilepsy (HR 3.8, 95% CI 1.1-13.3, P = 0.039). In both cohorts, Pediatric Stroke Outcome Measure scores at last follow-up were worse in those with epilepsy compared to those without.

Acute seizures occurred in approximately one quarter of our cohort and are an epilepsy risk factor in children with CSVT. Neonates and children with epilepsy had worse outcomes than those without.', 'article', ARRAY['Neonatal','Seizures','Stroke','Biomarkers','Epilepsy'], ARRAY['acute seizure','csvt','epilepsy','remote seizure','thrombosis'], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-152', 'Neonatal brain MRI and short-term outcomes after acute provoked seizures', ARRAY['Li Y','Scheffler A','Barkovich AJ','Chang T','Chu CJ','Massey SL','Abend NS','Lemmon ME','Thomas C','Numis A','Franck LS','Rogers E','Callen A','McCulloch CE','Shellhaas RA','Glass HC'], 'J Perinatol', 2023, 7, '10.1038/s41372-023-01723-3', '37454174', 'PMC10615741', 'We investigated how diagnosis and injury location on neonatal brain MRI following onset of acute provoked seizures was associated with short term outcome.

A multicenter cohort of neonates with acute provoked seizures enrolled in the Neonatal Seizure Registry. MRIs were centrally evaluated by a neuroradiologist for location of injury and radiologic diagnosis. Clinical outcomes were determined by chart review. Multivariate logistic regression was used to examine the association between MRI findings and outcomes.

Among 236 newborns with MRI at median age 4 days (IQR 3-8), 91% had abnormal MRI. Radiologic diagnoses of intracranial hemorrhage (OR 3.2 [1.6-6.5], p < 0.001) and hypoxic-ischemic encephalopathy (OR 2.7 [1.4-5.4], p < 0.003) were associated with high seizure burden. Radiologic signs of intracranial infection were associated with abnormal neurologic examination at discharge (OR 3.9 [1.3-11.6], p < 0.01).

Findings on initial MRI can help with expectant counseling on short-term outcomes following acute provoked neonatal seizures.', 'article', ARRAY['EEG','Neonatal','Seizures','Stroke'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-153', 'Pediatric Moyamoya Revascularization Perioperative Care: A Modified Delphi Study', ARRAY['Sun LR','Jordan LC','Smith ER','Aldana PR','Kirschen MP','Guilliams K','Gupta N','Steinberg GK','Fox C','Harrar DB','Lee S','Chung MG','Dirks P','Dlamini N','Maher CO','Lehman LL','Hong SJ','Strahle JM','Pineda JA','Beslow LA','Rasmussen L','Mailo J','Piatt J','Lang SS','Adelson PD','Dewan MC','Mineyko A','McClugage S','Vadivelu S','Dowling MM','Hersh DS'], 'Neurocrit Care', 2023, 7, '10.1007/s12028-023-01788-0', '37470933', 'PMC11023720', 'Surgical revascularization decreases the long-term risk of stroke in children with moyamoya arteriopathy but can be associated with an increased risk of stroke during the perioperative period. Evidence-based approaches to optimize perioperative management are limited and practice varies widely. Using a modified Delphi process, we sought to establish expert consensus on key components of the perioperative care of children with moyamoya undergoing indirect revascularization surgery and identify areas of equipoise to define future research priorities.

Thirty neurologists, neurosurgeons, and intensivists practicing in North America with expertise in the management of pediatric moyamoya were invited to participate in a three-round, modified Delphi process consisting of a 138-item practice patterns survey, anonymous electronic evaluation of 88 consensus statements on a 5-point Likert scale, and a virtual group meeting during which statements were discussed, revised, and reassessed. Consensus was defined as ≥ 80% agreement or disagreement.

Thirty-nine statements regarding perioperative pediatric moyamoya care for indirect revascularization surgery reached consensus. Salient areas of consensus included the following: (1) children at a high risk for stroke and those with sickle cell disease should be preadmitted prior to indirect revascularization; (2) intravenous isotonic fluids should be administered in all patients for at least 4 h before and 24 h after surgery; (3) aspirin should not be discontinued in the immediate preoperative and postoperative periods; (4) arterial lines for blood pressure monitoring should be continued for at least 24 h after surgery and until active interventions to achieve blood pressure goals are not needed; (5) postoperative care should include hourly vital signs for at least 24 h, hourly neurologic assessments for at least 12 h, adequate pain control, maintaining normoxia and normothermia, and avoiding hypotension; and (6) intravenous fluid bolus administration should be considered the first-line intervention for new focal neurologic deficits following indirect revascularization surgery.

In the absence of data supporting specific care practices before and after indirect revascularization surgery in children with moyamoya, this Delphi process defined areas of consensus among neurosurgeons, neurologists, and intensivists with moyamoya expertise. Research priorities identified include determining the role of continuous electroencephalography in postoperative moyamoya care, optimal perioperative blood pressure and hemoglobin targets, and the role of supplemental oxygen for treatment of suspected postoperative ischemia.', 'article', ARRAY['EEG','Stroke','Survey','Outcomes'], ARRAY['cerebral revascularization','children','delphi technique','ischemic stroke','moyamoya disease','pediatric stroke','perioperative care'], 'Pediatric', TRUE, ARRAY['matthew-kirschen','dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-154', 'Pediatric status epilepticus management by Emergency Medical Services (the pSERG cohort)', ARRAY['Amengual-Gual M','S&#xe1;nchez Fern&#xe1;ndez I','Vasquez A','Abend NS','Anderson A','Arya R','Barcia Aguilar C','Brenton JN','Carpenter JL','Chapman KE','Clark J','Farias-Moeller R','Gaillard WD','Glauser TA','Goldstein JL','Goodkin HP','Lai YC','Mikati MA','Morgan LA','Novotny EJ','Ostendorf AP','Payne ET','Peariso K','Piantino J','Reece L','Riviello JJ','Sannagowdara K','Sheehan T','Tasker RC','Tchapyjnikov D','Topjian AA','Wainwright MS','Wilfong A','Williams K','Loddenkemper T'], 'Seizure', 2023, 7, '10.1016/j.seizure.2023.07.010', '37523933', NULL, 'Delayed treatment in status epilepticus (SE) is independently associated with increased treatment resistance, morbidity, and mortality. We describe the prehospital management pathway and Emergency Medical Services (EMS) timeliness in children who developed refractory convulsive status epilepticus (RCSE).

Retrospective multicenter study in the United States using prospectively collected observational data from June 2011 to March 2020. We selected pediatric patients (one month-21 years) with RCSE initiated outside the hospital and transported to the hospital by EMS.

We included 91 patients with a median (percentile-percentile) age of 3.0 (1.5-7.3) years. The median time from seizure onset to hospital arrival was 45 (30-67) minutes, with a median time cared for by EMS of 24 (15-36) minutes. Considering treatment by caregivers and EMS before hospital arrival, 20 (22%) patients did not receive any anti-seizure medications (ASM) and 71 (78%) received one to five doses of benzodiazepines (BZD), without non-BZD ASM. We provided the prehospital treatment flow path of these patients through caregivers and EMS including relevant time points. Patients with a history of SE were more likely to receive the first BZD in the prehospital setting compared to patients without a history of SE (adjusted HR 3.25, 95% CI 1.72-6.12, p<0.001).

In this multicenter study of pediatric RCSE, prehospital treatment may be streamlined further. Patients with a history of SE were more likely to receive prehospital rescue medication.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY['emergency medical services (ems)','epilepsy','guidelines','prehospital management','status epilepticus','treatment'], 'Pediatric', TRUE, ARRAY['nicholas-abend','raquel-farias-moeller','adam-ostendorf','james-riviello','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-155', 'Fulminant Anti-Myelin Oligodendrocyte Glycoprotein-Associated Cerebral Cortical Encephalitis: Case Series of a Severe Pediatric Myelin Oligodendrocyte Glycoprotein Antibody-Associated Disease Phenotype', ARRAY['Kannan V','Sandweiss AJ','Erickson TA','Yarimi JM','Ankar A','Hardwick VA','Shukla NM','Lotze TE','Risen SR','Riviello JJ','Lai YC','Moeller KK','Fisher K'], 'Pediatr Neurol', 2023, 7, '10.1016/j.pediatrneurol.2023.07.002', '37544084', NULL, 'We describe a cohort of children with severe myelin oligodendrocyte glycoprotein (MOG)-IgG-associated cerebral cortical encephalitis (CCE), manifesting with bilateral cortical cytotoxic edema and critical neurological illness.

We retrospectively reviewed our pediatric MOG antibody-associated disease (MOGAD) database and identified patients with specific radiographic pattern of bilateral, multifocal cortical cytotoxic lesions. We collected demographic, clinical, and outcomes data from these patients and compared select variables with radiographically distinct cerebral MOGAD syndromes (case-control analysis). We assessed the correlation of quantitative clinical variables with severity/outcomes measures using simple linear regression.

Sixty-five of 88 total MOGAD cases had cerebral disease, and six of 88 met inclusion criteria for fulminant CCE (f-CCE). Age range was 2 to 7 years; five of six were male. Six of six were critically ill with severe encephalopathy and seizures, two of six required barbiturate coma, and two of six required invasive intracranial pressure monitoring. Six of six required treatment escalation beyond steroids. Four of six had favorable outcome; two of six had moderate-severe disability. Compared with other cerebral MOGAD cases (n = 59), children with f-CCE were more likely to have critical illness and poor neurological outcomes scores. Neurofilament light chain and treatment latency positively correlated with intensive care unit length of stay and outcomes scores; cerebrospinal fluid (CSF) white blood cell count and neutrophil-to-lymphocyte ratio did not.

Pediatric CCE with bilateral cytotoxicity is associated with more fulminant disease and worse outcomes than other cerebral MOGAD syndromes.', 'article', ARRAY['Seizures','Outcomes','Neurocritical Care'], ARRAY['encephalitis','mog','mogad','pediatric'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-156', 'Treatment of seizures in the neonate: Guidelines and consensus-based recommendations-Special report from the ILAE Task Force on Neonatal Seizures', ARRAY['Pressler RM','Abend NS','Auvin S','Boylan G','Brigo F','Cilio MR','De Vries LS','Elia M','Espeche A','Hahn CD','Inder T','Jette N','Kakooza-Mwesige A','Mader S','Mizrahi EM','Mosh&#xe9; SL','Nagarajan L','Noyman I','Nunes ML','Samia P','Shany E','Shellhaas RA','Subota A','Triki CC','Tsuchida T','Vinayan KP','Wilmshurst JM','Yozawitz EG','Hartmann H'], 'Epilepsia', 2023, 9, '10.1111/epi.17745', '37655702', NULL, 'Seizures are common in neonates, but there is substantial management variability. The Neonatal Task Force of the International League Against Epilepsy (ILAE) developed evidence-based recommendations about antiseizure medication (ASM) management in neonates in accordance with ILAE standards. Six priority questions were formulated, a systematic literature review and meta-analysis were performed, and results were reported following the PRISMA (Preferred Reporting Items for Systematic Reviews and Meta-Analyses) 2020 standards. Bias was evaluated using the Cochrane tool and risk of Bias in non-randomised studies - of interventions (ROBINS-I), and quality of evidence was evaluated using grading of recommendations, assessment, development and evaluation (GRADE). If insufficient evidence was available, then expert opinion was sought using Delphi consensus methodology. The strength of recommendations was defined according to the ILAE Clinical Practice Guidelines development tool. There were six main recommendations. First, phenobarbital should be the first-line ASM (evidence-based recommendation) regardless of etiology (expert agreement), unless channelopathy is likely the cause for seizures (e.g., due to family history), in which case phenytoin or carbamazepine should be used. Second, among neonates with seizures not responding to first-line ASM, phenytoin, levetiracetam, midazolam, or lidocaine may be used as a second-line ASM (expert agreement). In neonates with cardiac disorders, levetiracetam may be the preferred second-line ASM (expert agreement). Third, following cessation of acute provoked seizures without evidence for neonatal-onset epilepsy, ASMs should be discontinued before discharge home, regardless of magnetic resonance imaging or electroencephalographic findings (expert agreement). Fourth, therapeutic hypothermia may reduce seizure burden in neonates with hypoxic-ischemic encephalopathy (evidence-based recommendation). Fifth, treating neonatal seizures (including electrographic-only seizures) to achieve a lower seizure burden may be associated with improved outcome (expert agreement). Sixth, a trial of pyridoxine may be attempted in neonates presenting with clinical features of vitamin B6-dependent epilepsy and seizures unresponsive to second-line ASM (expert agreement). Additional considerations include a standardized pathway for the management of neonatal seizures in each neonatal unit and informing parents/guardians about the diagnosis of seizures and initial treatment options.', 'review', ARRAY['EEG','Neonatal','Seizures','Stroke','Review','Pharmacology'], ARRAY['delphi','antiseizure medication','epilepsy','evidence-based guideline','neonate','provoked seizures'], 'Neonatal', TRUE, ARRAY['nicholas-abend','cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-157', 'Brain tumor-related epilepsy management: A Society for Neuro-oncology (SNO) consensus review on current management', ARRAY['Avila EK','Tobochnik S','Inati SK','Koekkoek JAF','McKhann GM','Riviello JJ','Rud&#xe0; R','Schiff D','Tatum WO','Templer JW','Weller M','Wen PY'], 'Neuro Oncol', 2024, 1, '10.1093/neuonc/noad154', '37699031', 'PMC10768995', 'Tumor-related epilepsy (TRE) is a frequent and major consequence of brain tumors. Management of TRE is required throughout the course of disease and a deep understanding of diagnosis and treatment is key to improving quality of life. Gross total resection is favored from both an oncologic and epilepsy perspective. Shared mechanisms of tumor growth and epilepsy exist, and emerging data will provide better targeted therapy options. Initial treatment with antiseizure medications (ASM) in conjunction with surgery and/or chemoradiotherapy is typical. The first choice of ASM is critical to optimize seizure control and tolerability considering the effects of the tumor itself. These agents carry a potential for drug-drug interactions and therefore knowledge of mechanisms of action and interactions is needed. A review of adverse effects is necessary to guide ASM adjustments and decision-making. This review highlights the essential aspects of diagnosis and treatment of TRE with ASMs, surgery, chemotherapy, and radiotherapy while indicating areas of uncertainty. Future studies should consider the use of a standardized method of seizure tracking and incorporating seizure outcomes as a primary endpoint of tumor treatment trials.', 'review', ARRAY['Seizures','Review','Pharmacology','Outcomes','Epilepsy'], ARRAY['antiseizure medication','brain tumor','epilepsy','glioma','seizure'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-158', 'A Comparison of Ketamine and Midazolam as First-Line Anesthetic Infusions for Pediatric Status Epilepticus', ARRAY['Jacobwitz M','Mulvihill C','Kaufman MC','Gonzalez AK','Resendiz K','Francoeur C','Helbig I','Topjian AA','Abend NS'], 'Neurocrit Care', 2023, 10, '10.1007/s12028-023-01859-2', '37783824', NULL, 'Pediatric refractory status epilepticus (RSE) often requires management with anesthetic infusions, but few data compare first-line anesthetics. This study aimed to compare the efficacy and adverse effects of midazolam and ketamine infusions as first-line anesthetics for pediatric RSE.

Retrospective single-center study of consecutive study participants treated with ketamine or midazolam as the first-line anesthetic infusions for RSE at a quaternary care children''s hospital from December 1, 2017, until September 15, 2021.

We identified 117 study participants (28 neonates), including 79 (68%) who received midazolam and 38 (32%) who received ketamine as the first-line anesthetic infusions. Seizures terminated more often in study participants administered ketamine (61%, 23/38) than midazolam (28%, 22/79; odds ratio [OR] 3.97, 95% confidence interval [CI] 1.76-8.98; P < 0.01). Adverse effects occurred more often in study participants administered midazolam (24%, 20/79) than ketamine (3%, 1/38; OR 12.54, 95% CI 1.61-97.43; P = 0.016). Study participants administered ketamine were younger, ketamine was used more often for children with acute symptomatic seizures, and midazolam was used more often for children with epilepsy. Multivariable logistic regression of seizure termination by first-line anesthetic infusion (ketamine or midazolam) including age at SE onset, SE etiology category, and individual seizure duration at anesthetic infusion initiation indicated seizures were more likely to terminate following ketamine than midazolam (OR 4.00, 95% CI 1.69-9.49; P = 0.002) and adverse effects were more likely following midazolam than ketamine (OR 13.41, 95% CI 1.61-111.04; P = 0.016). Survival to discharge was higher among study participants who received midazolam (82%, 65/79) than ketamine (55%, 21/38; P = 0.002), although treating clinicians did not attribute any deaths to ketamine or midazolam.

Among children and neonates with RSE, ketamine was more often followed by seizure termination and less often associated with adverse effects than midazolam when administered as the first-line anesthetic infusion. Further prospective data are needed to compare first-line anesthetics for RSE.', 'article', ARRAY['Status Epilepticus','Neonatal'], ARRAY['pediatric neurocritical care','pediatric refractory status epilepticus','pediatric status epilepticus','pediatric superrefractory status epilepticus'], 'Pediatric', TRUE, ARRAY['conall-francoeur','nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-159', 'Feeding and developmental outcomes after neonatal seizures-A prospective observational study', ARRAY['Roberts KH','Barks JDE','Glass HC','Soul JS','Chang T','Wusthoff CJ','Chu CJ','Massey SL','Abend NS','Lemmon ME','Thomas C','Guillet R','Rogers EE','Franck LS','McCaffery H','Li Y','McCulloch CE','Shellhaas RA'], 'Ann Child Neurol Soc', 2022, 12, '10.1002/cns3.6', '37842075', 'PMC10572735', 'Among neonates with acute symptomatic seizures, we evaluated whether inability to take full feeds at time of hospital discharge from neonatal seizure admission is associated with worse neurodevelopmental outcomes, after adjusting for relevant clinical variables.

This prospective, 9-center study of theassessed characteristics of infants with seizures including: evidence of brainstem injury on MRI, mode of feeding upon discharge, and developmental outcomes at 12, 18, and 24 months. Inability to take oral feeds was identified through review of medical records. Brainstem injury was identified through central review of neonatal MRIs. Developmental outcomes were assessed with the Warner Initial Developmental Evaluation of Adaptive and Functional Skills (WIDEA-FS) at 12, 18, and 24 months corrected age.

Among 276 infants, inability to achieve full oral feeds was associated with lower total WIDEA-FS scores (160.2±25.5 for full oral feeds vs. 121.8±42.9 for some/no oral feeds at 24 months, p<0.001). At 12 months, a G-tube was required for 23 of the 49 (47%) infants who did not achieve full oral feeds, compared with 2 of the 221 (1%) who took full feeds at discharge (p<0.001).

Inability to take full oral feeds upon hospital discharge is an objective clinical sign that can identify infants with acute symptomatic neonatal seizures who are at high risk for impaired development at 24 months.', 'article', ARRAY['Neonatal','Seizures','Outcomes'], ARRAY['neonatal neurology','feeding','neonatal seizures','neurodevelopment','tube feed'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-160', 'Quantitative electroencephalogram in term neonates under different sleep states', ARRAY['Yuan I','Georgostathi G','Zhang B','Hodges A','Kurth CD','Kirschen MP','Huh JW','Topjian AA','Lang SS','Richter A','Abend NS','Massey SL'], 'J Clin Monit Comput', 2023, 10, '10.1007/s10877-023-01082-6', '37851153', NULL, 'Electroencephalogram (EEG) can be used to assess depth of consciousness, but interpreting EEG can be challenging, especially in neonates whose EEG undergo rapid changes during the perinatal course. EEG can be processed into quantitative EEG (QEEG), but limited data exist on the range of QEEG for normal term neonates during wakefulness and sleep, baseline information that would be useful to determine changes during sedation or anesthesia. We aimed to determine the range of QEEG in neonates during awake, active sleep and quiet sleep states, and identified the ones best at discriminating between the three states. Normal neonatal EEG from 37 to 46 weeks were analyzed and classified as awake, quiet sleep, or active sleep. After processing and artifact removal, total power, power ratio, coherence, entropy, and spectral edge frequency (SEF) 50 and 90 were calculated. Descriptive statistics were used to summarize the QEEG in each of the three states. Receiver operating characteristic (ROC) curves were used to assess discriminatory ability of QEEG. 30 neonates were analyzed. QEEG were different between awake vs asleep states, but similar between active vs quiet sleep states. Entropy beta, delta2 power %, coherence delta2, and SEF50 were best at discriminating awake vs active sleep. Entropy beta had the highest AUC-ROC ≥ 0.84. Entropy beta, entropy delta1, theta power %, and SEF50 were best at discriminating awake vs quiet sleep. All had AUC-ROC ≥ 0.78. In active sleep vs quiet sleep, theta power % had highest AUC-ROC > 0.69, lower than the other comparisons. We determined the QEEG range in healthy neonates in different states of consciousness. Entropy beta and SEF50 were best at discriminating between awake and sleep states. QEEG were not as good at discriminating between quiet and active sleep. In the future, QEEG with high discriminatory power can be combined to further improve ability to differentiate between states of consciousness.', 'article', ARRAY['qEEG','Neonatal','Sleep','Pharmacology'], ARRAY['eeg','neonatal eeg','neonatal sleep','quantitative eeg'], 'Neonatal', TRUE, ARRAY['matthew-kirschen','nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-161', 'Glial Fibrillary Acidic Protein (GFAP) Astrocytopathy: An Emerging Cause of Meningoencephalomyelitis in Children and Adolescents', ARRAY['Uppal P','Smith J','Castillo-Pinto C','Wells EM','Jayakar A','Harrar D'], 'J Child Neurol', 2023, 11, '10.1177/08830738231214301', '37981797', NULL, 'We describe 5 children with GFAP astrocytopathy with the goal of further characterizing this rare form of meningoencephalomyelitis.Retrospective chart review of patients diagnosed with GFAP astrocytopathy between 2019 and 2021.Patients were 8-17 years old, and all were male. Fever, headache, and vomiting were common presenting symptoms, and weakness, tremor, and ataxia were common initial examination findings. Initial magnetic resonance imaging (MRI) showed spinal cord abnormalities in 2 patients and leptomeningeal enhancement in 1. Most patients had cerebral spinal fluid pleocytosis, and all screened negative for malignancy. Three patients progressed to coma, and all were treated with immunosuppressant therapy. By discharge, all patients had improved over their clinical nadir, although none had returned to baseline.GFAP astrocytopathy is a recently recognized cause of meningoencephalomyelitis in children. Here, we expand our understanding of this entity with the goal of aiding those treating children with GFAP astrocytopathy.', 'article', ARRAY['Neurocritical Care'], ARRAY['gfap','astrocytopathy','glial fibrillary acidic protein','linear radial enhancement','meningoencephalomyelitis'], 'Pediatric', TRUE, ARRAY['anuj-jayakar','dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-162', 'Periodic Discharges in Critically Ill Children: Predictors and Outcome', ARRAY['Fung FW','Parikh DS','Massey SL','Fitzgerald MP','Vala L','Donnelly M','Jacobwitz M','Kessler SK','Xiao R','Topjian AA','Abend NS'], 'J Clin Neurophysiol', 2023, 12, '10.1097/WNP.0000000000000986', '38079254', 'PMC11073928', 'We aimed to identify clinical and EEG monitoring characteristics associated with generalized, lateralized, and bilateral-independent periodic discharges (GPDs, LPDs, and BIPDs) and to determine which patterns were associated with outcomes in critically ill children.

We performed a prospective observational study of consecutive critically ill children undergoing continuous EEG monitoring, including standardized scoring of GPDs, LPDs, and BIPDs. We identified variables associated with GPDs, LPDs, and BIPDs and assessed whether each pattern was associated with hospital discharge outcomes including the Glasgow Outcome Scale-Extended Pediatric version (GOS-E-Peds), Pediatric Cerebral Performance Category (PCPC), and mortality.

PDs occurred in 7% (91/1,399) of subjects. Multivariable logistic regression indicated that patients with coma (odds ratio [OR], 3.45; 95% confidence interval [CI]: 1.55, 7.68) and abnormal EEG background category (OR, 6.85; 95% CI: 3.37, 13.94) were at increased risk for GPDs. GPDs were associated with mortality (OR, 3.34; 95% CI: 1.24, 9.02) but not unfavorable GOS-E-Peds (OR, 1.93; 95% CI: 0.88, 4.23) or PCPC (OR, 1.64; 95% CI: 0.75, 3.58). Patients with acute nonstructural encephalopathy did not experience LPDs, and LPDs were not associated with mortality or unfavorable outcomes. BIPDs were associated with mortality (OR, 3.68; 95% CI: 1.14, 11.92), unfavorable GOS-E-Peds (OR, 5.00; 95% CI: 1.39, 18.00), and unfavorable PCPC (OR, 5.96; 95% CI: 1.65, 21.46).

Patients with coma or more abnormal EEG background category had an increased risk for GPDs and BIPDs, and no patients with an acute nonstructural encephalopathy experienced LPDs. GPDs were associated with mortality and BIPDs were associated with mortality and unfavorable outcomes, but LPDs were not associated with unfavorable outcomes.', 'article', ARRAY['EEG','Biomarkers','Outcomes','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-163', 'Characteristics of non-sleep related apneas in children with alternating hemiplegia of childhood', ARRAY['Thamby J','Prange L','Boggs A','Subei MO','Myers C','Uchitel J','ElMallah M','Bartlett-Lee B','Riviello JJ','Mikati MA'], 'Eur J Paediatr Neurol', 2023, 12, '10.1016/j.ejpn.2023.12.002', '38096596', NULL, 'Non-sleep related apnea (NSA) has been observed in alternating hemiplegia of childhood (AHC) but has yet to be characterized.

Investigate the following hypotheses: 1) AHC patients manifest NSA that is often severe. 2) NSA is usually triggered by precipitating events. 3) NSA is more likely in patients with ATP1A3 mutations.

Retrospective review of 51 consecutive AHC patients (ages 2-45 years) enrolled in our AHC registry. NSAs were classified as mild (not needing intervention), moderate (needing intervention but not perceived as life threatening), or severe (needing intervention and perceived as life threatening).

19/51 patients (37 %) had 52 NSA events (6 mild, 11 moderate, 35 severe). Mean age of onset of NSA (± Standard Error of the Mean (SEM)): 3.8 ± 1.5 (range 0-24) years, frequency during follow up was higher at younger ages as compared to adulthood (year 1: 2.2/year, adulthood: 0.060/year). NSAs were associated with triggering factors, bradycardia and with younger age (p < 0.008 in all) but not with mutation status (p = 0.360). Triggers, observed in 17 patients, most commonly included epileptic seizures in 9 (47 %), anesthesia, AHC spells and intercurrent, stressful, conditions. Management included use of pulse oximeter at home in nine patients, home oxygen in seven, intubation/ventilatory support in seven, and basic CPR in six. An additional patient required tracheostomy. There were no deaths or permanent sequalae.

AHC patients experience NSAs that are often severe. These events are usually triggered by seizures or other stressful events and can be successfully managed with interventions tailored to the severity of the NSA.', 'article', ARRAY['Cardiac Arrest','Seizures','Sleep'], ARRAY['atp1a3','alternating hemiplegia of childhood','apnea','sudep'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-164', 'Electrographic Seizure Characteristics and Electrographic Status Epilepticus Prediction', ARRAY['Fung FW','Parikh DS','Donnelly M','Xiao R','Topjian AA','Abend NS'], 'J Clin Neurophysiol', 2024, 1, '10.1097/WNP.0000000000001068', '38194638', 'PMC11231061', 'We aimed to characterize electrographic seizures (ES) and electrographic status epilepticus (ESE) and determine whether a model predicting ESE exclusively could effectively guide continuous EEG monitoring (CEEG) utilization in critically ill children.

This was a prospective observational study of consecutive critically ill children with encephalopathy who underwent CEEG. We used descriptive statistics to characterize ES and ESE, and we developed a model for ESE prediction.

ES occurred in 25% of 1,399 subjects. Among subjects with ES, 23% had ESE, including 37% with continuous seizures lasting >30 minutes and 63% with recurrent seizures totaling 30 minutes within a 1-hour epoch. The median onset of ES and ESE occurred 1.8 and 0.18 hours after CEEG initiation, respectively. The optimal model for ESE prediction yielded an area under the receiver operating characteristic curves of 0.81. A cutoff selected to emphasize sensitivity (91%) yielded specificity of 56%. Given the 6% ESE incidence, positive predictive value was 11% and negative predictive value was 99%. If the model were applied to our cohort, then 53% of patients would not undergo CEEG and 8% of patients experiencing ESE would not be identified.

ESE was common, but most patients with ESE had recurrent brief seizures rather than long individual seizures. A model predicting ESE might only slightly improve CEEG utilization over models aiming to identify patients at risk for ES but would fail to identify some patients with ESE. Models identifying ES might be more advantageous for preventing ES from evolving into ESE.', 'article', ARRAY['Status Epilepticus','EEG','Biomarkers','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-165', 'Incidence of postoperative seizures in neonates following cardiac surgery with regional cerebral perfusion and deep hypothermic circulatory arrest', ARRAY['Hsia J','Abend NS','Gaynor JW','Chen JM','Fuller S','Maeda K','Mavroudis CD','Nuri M','Leonard J','Ampah SB','Licht DJ','Massey SL','Naim MY'], 'JTCVS Open', 2023, 10, '10.1016/j.xjon.2023.10.026', '38204666', 'PMC10775112', 'Historically, our center has primarily used deep hypothermic circulatory arrest, but in recent years some surgeons have selectively used regional cerebral perfusion as an alternative. We aimed to compare the incidence of postoperative electroencephalographic seizure incidence in neonates undergoing surgery with regional cerebral perfusion and deep hypothermic circulatory arrest.

A retrospective analysis was performed in neonates who underwent surgery between 2012 and 2022 with either deep hypothermic circulatory arrest or regional cerebral perfusion with routine postoperative continuous electroencephalography monitoring for 48 hours. Propensity matching was performed to compare postoperative seizure risk between the 2 groups.

Among 1136 neonates undergoing cardiac surgery with cardiopulmonary bypass, regional cerebral perfusion was performed in 99 (8.7%) and deep hypothermic circulatory arrest in 604 (53%). The median duration of regional cerebral perfusion was 49 minutes (interquartile range, 38-68) and deep hypothermic circulatory arrest was 41 minutes (interquartile range, 31-49). The regional cerebral perfusion group had significantly longer total support, cardiopulmonary bypass, and aortic crossclamp times. Overall seizure incidence was 11% (N = 76) and 13% (N = 35) in the most recent era (2019-2022). The unadjusted seizure incidence was similar in neonates undergoing regional cerebral perfusion (N = 12, 12%) and deep hypothermic circulatory arrest (N = 64, 11%). After propensity matching, the seizure incidence was similar in neonates undergoing regional cerebral perfusion (N = 12, 12%) and deep hypothermic circulatory arrest (N = 37, 12%) (odds ratio, 0.97; 95% CI, 0.55-1.71;92).

In this contemporary single-center experience, the incorporation of regional cerebral perfusion did not result in a change in seizure incidence in comparison with deep hypothermic circulatory arrest. However, unmeasured confounders may have impacted these findings. Further studies are needed to determine the impact, if any, of regional cerebral perfusion on postoperative seizure incidence.', 'article', ARRAY['EEG','Neonatal','Seizures'], ARRAY['deep hypothermic circulatory arrest','regional cerebral perfusion'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-166', 'Association of EEG Background With Diffusion-Weighted Magnetic Resonance Neuroimaging and Short-Term Outcomes After Pediatric Cardiac Arrest', ARRAY['Bach AM','Kirschen MP','Fung FW','Abend NS','Ampah S','Mondal A','Huh JW','Chen SL','Yuan I','Graham K','Berman JI','Vossough A','Topjian A'], 'Neurology', 2024, 2, '10.1212/WNL.0000000000209134', '38350044', 'PMC11384654', 'EEG and MRI features are independently associated with pediatric cardiac arrest (CA) outcomes, but it is unclear whether their combination improves outcome prediction. We aimed to assess the association of early EEG background category with MRI ischemia after pediatric CA and determine whether addition of MRI ischemia to EEG background features and clinical variables improves short-term outcome prediction.

This was a single-center retrospective cohort study of pediatric CA with EEG initiated ≤24 hours and MRI obtained ≤7 days of return of spontaneous circulation. Initial EEG background was categorized as normal, slow/disorganized, discontinuous/burst-suppression, or attenuated-featureless. MRI ischemia was defined as percentage of brain tissue with apparent diffusion coefficient (ADC) <650 × 10mm/s and categorized as high (≥10%) or low (<10%). Outcomes were mortality and unfavorable neurologic outcome (Pediatric Cerebral Performance Category increase ≥1 from baseline resulting in ICU discharge score ≥3). The Kruskal-Wallis test evaluated the association of EEG with MRI. Area under the receiver operating characteristic (AUROC) curve evaluated predictive accuracy. Logistic regression and likelihood ratio tests assessed multivariable outcome prediction.

We evaluated 90 individuals. EEG background was normal in 16 (18%), slow/disorganized in 42 (47%), discontinuous/burst-suppressed in 12 (13%), and attenuated-featureless in 20 (22%) individuals. The median percentage of MRI ischemia was 5% (interquartile range 1-18); 32 (36%) individuals had high MRI ischemia burden. Twenty-eight (31%) individuals died, and 58 (64%) had unfavorable neurologic outcome. Worse EEG background category was associated with more MRI ischemia (< 0.001). The combination of EEG background and MRI ischemia burden had higher predictive accuracy than EEG alone (AUROC: mortality: 0.92 vs 0.87,= 0.03) or MRI alone (AUROC: mortality: 0.92 vs 0.84,= 0.02; unfavorable: 0.83 vs 0.73,< 0.01). Addition of percentage of MRI ischemia to clinical variables and EEG background category improved prediction for mortality (χ= 19.1,< 0.001) and unfavorable neurologic outcome (χ= 4.8,= 0.03) and achieved high predictive accuracy (AUROC: mortality: 0.97; unfavorable: 0.92).

Early EEG background category was associated with MRI ischemia after pediatric CA. Combining EEG and MRI data yielded higher outcome predictive accuracy than either modality alone. The addition of MRI ischemia to clinical variables and EEG background improved short-term outcome prediction.', 'article', ARRAY['Cardiac Arrest','EEG','Biomarkers','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['matthew-kirschen','nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-167', 'Optimizing EEG monitoring in critically ill children at risk for electroencephalographic seizures', ARRAY['Coleman K','Fung FW','Topjian A','Abend NS','Xiao R'], 'Seizure', 2024, 3, '10.1016/j.seizure.2024.03.008', '38522169', NULL, 'Strategies are needed to optimally deploy continuous EEG monitoring (CEEG) for electroencephalographic seizure (ES) identification and management due to resource limitations. We aimed to construct an efficient multi-stage prediction model guiding CEEG utilization to identify ES in critically ill children using clinical and EEG covariates.

The largest prospective single-center cohort of 1399 consecutive children undergoing CEEG was analyzed. A four-stage model was developed and trained to predict whether a subject required additional CEEG at the conclusion of each stage given their risk of ES. Logistic regression, elastic net, random forest, and CatBoost served as candidate methods for each stage and were evaluated using cross validation. An optimal multi-stage model consisting of the top-performing stage-specific models was constructed.

When evaluated on a test set, the optimal multi-stage model achieved a cumulative specificity of 0.197 and cumulative F1 score of 0.326 while maintaining a high minimum cumulative sensitivity of 0.938. Overall, 11 % of test subjects with ES were removed from the model due to a predicted low risk of ES (falsely negative subjects). CEEG utilization would be reduced by 32 % and 47 % compared to performing 24 and 48 h of CEEG in all test subjects, respectively. We developed a web application called EEGLE (EEG Length Estimator) that enables straightforward implementation of the model.

Application of the optimal multi-stage ES prediction model could either reduce CEEG utilization for patients at lower risk of ES or promote CEEG resource reallocation to patients at higher risk for ES.', 'article', ARRAY['EEG','Seizures','Machine Learning','Biomarkers'], ARRAY['critical care','eeg','machine learning','pediatric','seizure'], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-168', 'De novo variants in GABRA4 are associated with a neurological phenotype including developmental delay, behavioral abnormalities and epilepsy', ARRAY['Sajan SA','Gradisch R','Vogel FD','Coffey AJ','Salyakina D','Soler D','Jayakar P','Jayakar A','Bianconi SE','Cooper AH','Liu S','William N','Benkel-Herrenbr&#xfc;ck I','Maiwald R','Heller C','Biskup S','Leiz S','Westphal DS','Wagner M','Clarke A','Stockner T','Ernst M','Kesari A','Krenn M'], 'Eur J Hum Genet', 2024, 4, '10.1038/s41431-024-01600-3', '38565639', 'PMC11291759', 'Nine out of 19 genes encoding GABAreceptor subunits have been linked to monogenic syndromes characterized by seizures and developmental disorders. Previously, we reported the de novo variant p.(Thr300Ile) in GABRA4 in a patient with epilepsy and neurodevelopmental abnormalities. However, no new cases have been reported since then. Through an international collaboration, we collected molecular and phenotype data of individuals carrying de novo variants in GABRA4. Patients and their parents were investigated either by exome or genome sequencing, followed by targeted Sanger sequencing in some cases. All variants within the transmembrane domain, including the previously reported p.(Thr300Ile) variant, were characterized in silico and analyzed by molecular dynamics (MD) simulation studies. We identified three novel de novo missense variants in GABRA4 (NM_000809.4): c.797 C > T, p.(Pro266Leu), c.899 C > A, p.(Thr300Asn), and c.634 G > A, p.(Val212Ile). The p.(Thr300Asn) variant impacts the same codon as the previously reported variant p.(Thr300Ile) and likely arose post-zygotically as evidenced by sequencing oral mucosal cells. Overlapping phenotypes among affected individuals included developmental delay (4/4), epileptiform EEG abnormalities (3/4), attention deficits (3/4), seizures (2/4), autistic features (2/4) and structural brain abnormalities (2/4). MD simulations of the three variants within the transmembrane domain of the receptor indicate that sub-microsecond scale dynamics differ between wild-type and mutated subunits. Taken together, our findings further corroborate an association between GABRA4 and a neurological phenotype including variable neurodevelopmental, behavioral and epileptic abnormalities.', 'case_report', ARRAY['EEG','Seizures','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-169', 'Retrospective Multicenter Cohort Study on Safety and Electroencephalographic Response to Lacosamide for Neonatal Seizures', ARRAY['Kaur M','Utidjian L','Abend NS','Dickinson K','Roebling R','McDonald J','Maltenfort MG','Foskett N','Elmoufti S','Guerriero RM','Jain BG','Pajor NM','Rao S','Shellhaas RA','Slaughter L','Forrest CB'], 'Pediatr Neurol', 2024, 3, '10.1016/j.pediatrneurol.2024.03.007', '38579433', NULL, 'There is growing evidence supporting the safety and effectiveness of lacosamide in older children. However, minimal data are available for neonates. We aimed to determine the incidence of adverse events associated with lacosamide use and explore the electroencephalographic seizure response to lacosamide in neonates.

A retrospective cohort study was conducted using data from seven pediatric hospitals from January 2009 to February 2020. For safety outcomes, neonates were followed for ≤30 days from index date. Electroencephalographic response of lacosamide was evaluated based on electroencephalographic reports for ≤3 days.

Among 47 neonates, 98% received the first lacosamide dose in the intensive care units. During the median follow-up of 12 days, 19% of neonates died, and the crude incidence rate per 1000 patient-days (95% confidence interval) of the adverse events by diagnostic categories ranged from 2.8 (0.3, 10.2) for blood or lymphatic system disorders and nervous system disorders to 10.5 (4.2, 21.6) for cardiac disorders. Electroencephalographic seizures were observed in 31 of 34 patients with available electroencephalographic data on the index date. There was seizure improvement in 29% of neonates on day 1 and also in 29% of neonates on day 2. On day 3, there was no change in 50% of neonates and unknown change in 50% of neonates.

The results are reassuring regarding the safety of lacosamide in neonates. Although some neonates had fewer seizures after lacosamide administration, the lack of a comparator arm and reliance on qualitative statements in electroencephalographic reports limit the preliminary efficacy results.', 'article', ARRAY['EEG','Neonatal','Seizures','Outcomes'], ARRAY['electroencephalographic (eeg) response','lacosamide','neonate','safety'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-170', 'Responsive neurostimulation of thalamic nuclei for regional and multifocal drug-resistant epilepsy in children and young adults', ARRAY['Mohanty D','Houck KM','Trandafir C','Haneef Z','Karakas C','Lee S','Curry DJ','Riviello JJ','Ali I'], 'J Neurosurg Pediatr', 2024, 4, '10.3171/2024.2.PEDS23531', '38608307', NULL, 'Responsive neurostimulation (RNS) is a US FDA-approved form of neuromodulation to treat patients with focal-onset drug-resistant epilepsy (DRE) who are ineligible for or whose condition is refractory to resection. However, the FDA approval only extends to use in patients with one or two epileptogenic foci. Recent literature has shown possible efficacy of thalamic RNS in patients with Lennox-Gastaut syndrome and multifocal epilepsy. The authors hypothesized that RNS of thalamic nuclei may be effective in seizure reduction for patients with multifocal or regionalized-onset DRE.

The authors performed a retrospective chart review of all patients who had an RNS device managed at Texas Children''s Hospital between July 2016 and September 2023, with at least one active electrode in the thalamic nuclei and ≥ 12 months of postimplantation follow-up. Information conveyed by the patient or their caregiver provided data on the change in the clinical seizure frequency, quality of life (QOL), and seizure severity between the preimplantation baseline visit and the last office visit (LOV).

Thirteen patients (ages 8-24 years) were identified with active RNS leads in thalamic nuclei (11 centromedian and 2 anterior nucleus). At LOV, 46% of patients reported 50%-100% clinical seizure reduction (classified as responders), 15% reported 25%-49% reduction, and 38% reported < 25% reduction or no change. Additionally, 42% of patients reported subjective improvement in QOL and 58% reported improved seizure severity. Patients with focal cortical dysplasia (FCD) responded strongly: 3 of 5 (60%) reported ≥ 80% reduction in seizure burden and improvement in seizure severity and QOL. Patients with multifocal epilepsy and bilateral thalamocortical leads also did well, with all 3 reporting ≥ 50% reduction in seizures.

RNS of thalamic nuclei shows promising results in reducing seizure burden for patients with multifocal or regional-onset DRE, particularly in a bilateral thalamocortical configuration or when addressing an underlying FCD.', 'article', ARRAY['Seizures','Pharmacology','Outcomes','Epilepsy'], ARRAY['ethg','bithalamic stimulation','drug-resistant epilepsy','electrothalamography','responsive neurostimulation','thalamic stimulation','thalamocortical neuromodulation'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-171', 'Ictal-Interictal Continuum in the Pediatric Intensive Care Unit', ARRAY['Sansevere AJ','Keenan JS','Pickup E','Conley C','Staso K','Harrar DB'], 'Neurocrit Care', 2024, 4, '10.1007/s12028-024-01978-4', '38671312', NULL, 'The ictal-interictal continuum (IIC) consists of several electroencephalogram (EEG) patterns that are common in critically ill adults. Studies focused on the IIC are limited in critically ill children and have focused primarily on associations with electrographic seizures (ESs). We report the incidence of the IIC in the pediatric intensive care unit (PICU). We then compare IIC patterns to rhythmic and periodic patterns (RPP) not meeting IIC criteria looking for associations with acute cerebral abnormalities, ES, and in-hospital mortality.

This was a retrospective review of prospectively collected data for patients admitted to the PICU at Children''s National Hospital from July 2021 to January 2023 with continuous EEG. We excluded patients with known epilepsy and cerebral injury prior to presentation. All patients were screened for RPP. The American Clinical Neurophysiology Society standardized Critical Care EEG terminology for the IIC was applied to each RPP. Associations between IIC and RPP not meeting IIC criteria, with clinical and EEG variables, were calculated using odds ratios (ORs).

Of 201 patients, 21% (42/201) had RPP and 12% (24/201) met IIC criteria. Among patients with an IIC pattern, the median age was 3.4 years (interquartile range (IQR) 0.6-12 years). Sixty-seven percent (16/24) of patients met a single IIC criterion, whereas the remainder met two criteria. ESs were identified in 83% (20/24) of patients and cerebral injury was identified in 96% (23/24) of patients with IIC patterns. When comparing patients with IIC patterns with those with RPP not qualifying as an IIC pattern, both patterns were associated with acute cerebral abnormalities (IIC OR 26 [95% confidence interval {CI} 3.4-197], p = 0.0016 vs. RPP OR 3.5 [95% CI 1.1-11], p = 0.03), however, only the IIC was associated with ES (OR 121 [95% CI 33-451], p < 0.0001) versus RPP (OR 1.3 [0.4-5], p = 0.7).

Rhythmic and periodic patterns and subsequently the IIC are commonly seen in the PICU and carry a high association with cerebral injury. Additionally, the IIC, seen in more than 10% of critically ill children, is associated with ES. The independent impact of RPP and IIC patterns on secondary brain injury and need for treatment of these patterns independent of ES requires further study.', 'article', ARRAY['EEG','Seizures','Outcomes'], ARRAY['continuous electroencephalography','critical care eeg','ictal&#x2013;interictal continuum','pediatric intensive care','pediatric neurocritical care','pediatrics','periodic and rhythmic patterns'], 'Pediatric', TRUE, ARRAY['arnold-sansevere','dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-172', 'Neurological injury in pediatric heart disease: A review of developmental and acquired risk factors and management considerations', ARRAY['McGetrick ME','Riviello JJ'], 'Semin Pediatr Neurol', 2024, 1, '10.1016/j.spen.2024.101115', '38677794', NULL, 'Medical and surgical advancements have improved survival in children with acquired and congenital heart disease (CHD), but the burden of neurological morbidity is high. Brain disorders associated with CHD include white matter injury, stroke, seizure, and neurodevelopmental delays. While genetics and disease-specific factors play a substantial role in early brain injury, therapeutic management of the heart disease intensifies the risk. There is a growing interest in understanding how to reduce brain injury and improve neurodevelopmental outcomes in cardiac diseases. Pediatric neurologists serve a vital role in care teams managing these complex patients, providing interpretation of neuromonitoring and imaging, managing neurologic emergencies, assisting with neuro prognostication, and identifying future research aims.', 'review', ARRAY['Neuromonitoring','Seizures','Stroke','Review'], ARRAY['mechanical circulatory support','congenital heart disease','heart failure','seizure','stroke','ventricular assist device'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-173', 'Supporting parents while their child is receiving neurocritical care', ARRAY['Farias-Moeller R','Wong N'], 'Semin Pediatr Neurol', 2024, 1, '10.1016/j.spen.2024.101116', '38677795', NULL, 'The post-intensive care syndrome (PICS) concept whereby the ICU experience of the patient as well as their family can have long-term deleterious health outcomes in both the patient and the family provides a rationale and impetus for modifying the ICU experience for the parents of patients receiving pediatric neurocritical care. This article uses the PICS framework to provide insight to that parental experience. Included are the words of parents who tell what they felt and what they most needed from their children''s doctors while their children were receiving neurocritical care. Based on their and many other ICU parents'' advice and the PICS research, we identify a short list of specific steps the medical team can take immediately to support these parents.', 'article', ARRAY['Neurocritical Care','Outcomes'], ARRAY['doctor-family communication','fires','norse','organ donation','palliative care','pediatric neurocritical care','post-intensive care syndrome'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-174', 'Introduction to Pediatric Neurocritical Care, 2024', ARRAY['Riviello JJ','Lai YC','Erklauer JC'], 'Semin Pediatr Neurol', 2024, 4, '10.1016/j.spen.2024.101130', '38677798', NULL, NULL, 'article', ARRAY['Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-175', 'Neurocritical care and neuromonitoring considerations in acute pediatric spinal cord injury', ARRAY['Thomas AX','Erklauer JC'], 'Semin Pediatr Neurol', 2024, 3, '10.1016/j.spen.2024.101122', '38677801', NULL, 'Management of pediatric spinal cord injury (SCI) is an essential skill for all pediatric neurocritical care physicians. In this review, we focus on the evaluation and management of pediatric SCI, highlight a novel framework for the monitoring of such patients in the intensive care unit (ICU), and introduce advancements in critical care techniques in monitoring and management. The initial evaluation and characterization of SCI is crucial for improving outcomes as well as prognostication. While physical examination and imaging are the main stays of the work-up, we propose the use of somatosensory evoked potentials (SSEPs) and transcranial magnetic stimulation (TMS) for challenging clinical scenarios. SSEPs allow for functional evaluation of the dorsal columns consisting of tracts associated with hand function, ambulation, and bladder function. Meanwhile, TMS has the potential for informing prognostication as well as response to rehabilitation. Spine stabilization, and in some cases surgical decompression, along with respiratory and hemodynamic management are essential. Emerging research suggests that targeted spinal cerebral perfusion pressure may provide potential benefits. This review aims to increase the pediatric neurocritical care physician''s comfort with SCI while providing a novel algorithm for monitoring spinal cord function in the ICU.', 'review', ARRAY['Neurocritical Care','Neuromonitoring','Review','Biomarkers'], ARRAY['icu management of sci','map management','pediatric spinal cord injury','spinal cord perfusion pressure','spinal shock'], 'Pediatric', TRUE, ARRAY['ajay-thomas'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-176', 'Late-Onset Findings During Extended EEG Monitoring Are Rare in Critically Ill Children', ARRAY['Fung FW','Parikh DS','Walsh K','Fitzgerald MP','Massey SL','Topjian AA','Abend NS'], 'J Clin Neurophysiol', 2024, 4, '10.1097/WNP.0000000000001083', '38687298', 'PMC11511783', 'Electrographic seizures (ES) are common in critically ill children undergoing continuous EEG (CEEG) monitoring, and previous studies have aimed to target limited CEEG resources to children at highest risk of ES. However, previous studies have relied on observational data in which the duration of CEEG was clinically determined. Thus, the incidence of late occurring ES is unknown. The authors aimed to assess the incidence of ES for 24 hours after discontinuation of clinically indicated CEEG.

This was a single-center prospective study of nonconsecutive children with acute encephalopathy in the pediatric intensive care unit who underwent 24 hours of extended research EEG after the end of clinical CEEG. The authors assessed whether there were new findings that affected clinical management during the extended research EEG, including new-onset ES.

Sixty-three subjects underwent extended research EEG. The median duration of the extended research EEG was 24.3 hours (interquartile range 24.0-25.3). Three subjects (5%) had an EEG change during the extended research EEG that resulted in a change in clinical management, including an increase in ES frequency, differential diagnosis of an event, and new interictal epileptiform discharges. No subjects had new-onset ES during the extended research EEG.

No subjects experienced new-onset ES during the 24-hour extended research EEG period. This finding supports observational data that patients with late-onset ES are rare and suggests that ES prediction models derived from observational data are likely not substantially underrepresenting the incidence of late-onset ES after discontinuation of clinically indicated CEEG.', 'article', ARRAY['EEG','Seizures','Biomarkers','Neurocritical Care'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-177', 'Successful Management of Febrile Infection-Related Epilepsy Syndrome Using Cytokine-Directed Therapy', ARRAY['Harrar DB','Genser I','Najjar M','Davies E','Sule S','Wistinghausen B','Goldbach-Mansky R','Wells E'], 'J Child Neurol', 2024, 8, '10.1177/08830738241273448', '39196283', NULL, 'Here we describe a pediatric patient with febrile infection-related epilepsy syndrome with a good functional and neurologic outcome after treatment with early and aggressive cytokine-directed immunomodulatory therapy and a seizure management strategy that intentionally avoided a barbiturate coma. A 5-year-old previously healthy male presented with staring, behavioral arrest, and encephalopathy evolving to super-refractory status epilepticus. He had had onset of fever 5 days prior. He was treated with early and aggressive immunomodulatory therapy targeted to his evolving cytokine profile. He was also treated with the ketogenic diet, antiseizure medications, and continuous anesthetic infusions. Pentobarbital was purposely avoided. Now, 2½ years later, he attends mainstream school, has attention-deficit hyperactivity disorder (ADHD), mild neurocognitive impairment, and well-controlled epilepsy. By using cytokine-directed immunotherapy and avoiding a barbiturate coma, we were able to successfully treat a pediatric patient with febrile infection-related epilepsy syndrome and achieve a good outcome.', 'case_report', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Outcomes'], ARRAY['cytokines','febrile infection-related epilepsy syndrome','immunotherapy','ketamine','pentobarbital'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-178', 'Communication trends over time in new-onset refractory status epilepticus (NORSE): Interim analysis from the NORSE/FIRES Family Registry', ARRAY['Kazazian K','Gaspard N','Hirsch LJ','Kellogg M','Hocker SE','Wong N','Farias-Moeller R','Eschbach K','Gofton TE'], 'Epilepsy Behav', 2024, 9, '10.1016/j.yebeh.2024.110023', '39241640', NULL, 'The new-onset refractory status epilepticus (NORSE)/febrile infection-related epilepsy syndrome (FIRES) Family Registry contributes to a systematic effort to collect clinical and epidemiological information on individuals affected by NORSE/FIRES. We explore diagnostic and prognostic information provided to patients and their families, their satisfaction with the communication, and utilisation of palliative care services during acute hospitalization. Communication about the diagnosis of NORSE/FIRES to families has improved since the publication of consensus definitions in 2018, with families being more likely to be told about NORSE/FIRES after 2018. Families rate the quality of prognostic information as being moderate. Palliative care services were involved in a minority of patients. Understanding and characterizing the prevalence and satisfaction of diagnostic and prognostic conversations is important for improving overall care, the quality of physician-patient-family relationships, and the recovery process for those affected by NORSE/FIRES.', 'article', ARRAY['Status Epilepticus','Pharmacology','Biomarkers','NORSE/FIRES'], ARRAY['communication','febrile infection-related epilepsy syndrome','new-onset refractory status epilepticus','palliative care','refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-179', 'Cochlear Implant Artifacts in Continuous Electroencephalogram Recording', ARRAY['Nayak A','Traboulsi H','Anderson AE','Runco A','Riviello JJ'], 'J Clin Neurophysiol', 2024, 9, '10.1097/WNP.0000000000001116', '39252164', NULL, 'Cochlear implants to aid sensorineural hearing loss are becoming commonplace. In this study, we describe two cases that showed artifacts related to the cochlear implant device during scalp EEG recording. To our knowledge, cochlear implant artifacts have not been reported previously. Recognizing cochlear implant artifacts will avoid misinterpretation and resultant inappropriate treatment.', 'case_report', ARRAY['EEG'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-180', 'Electrographic Seizures and Predictors of Epilepsy after Pediatric Arteriovenous Malformation Rupture', ARRAY['Keenan JS','Harrar DB','Har C','Conley C','Staso K','Sansevere AJ'], 'J Pediatr', 2024, 9, '10.1016/j.jpeds.2024.114325', '39343131', NULL, 'To assess clinical and electroencephalogram (EEG) predictors of epilepsy and to describe the percentage of electrographic seizures and development of epilepsy among patients with spontaneous intracerebral hemorrhage (ICH) due to arteriovenous malformation (AVM) rupture.

Retrospective review of patients admitted to the pediatric intensive care unit with ICH secondary to AVM rupture over 11 years. Clinical variables were collected by review of the electronic medical record. Seizures were described as acute symptomatic (7 days after AVM rupture), subacute (7-30 days after AVM rupture) and remote (greater than 30 days after AVM rupture). Outcome metrics included mortality, and the development of epilepsy post discharge. Descriptive statistics were used.

Forty-three patients met inclusion criteria with a median age of 12.2 years (IQR 7.3-14.8) and 49% (21/43) were female. Sixteen percent (7/43) presented with a clinical seizure prior to EEG placement. EEG was performed in 62% (27/43) of patients; one had electrographic status epilepticus without clinical signs. Sixteen percent (7/43) of patients were diagnosed with epilepsy, with a median time to diagnosis of 1.34 years (IQR 0.55-2.07) after AVM rupture. One-year epilepsy-free survival was 84% (95% CI 70%-98%) and 2-year epilepsy-free survival was 79% (95% CI 63%-95%) Remote seizures were associated with epilepsy (P < .001), but acute symptomatic seizures were not (P = .16).

EEG-confirmed seizures are uncommon in patients with ICH secondary to AVM rupture; however, when identified, the seizure burden appears to be high. Patients with seizures 30 days after AVM rupture are more likely to develop epilepsy.', 'article', ARRAY['Status Epilepticus','EEG','Stroke','Biomarkers'], ARRAY['icu eeg','arteriovenous malformation','electroencephalography','electrographic seizures','epilepsy','pediatric intensive care','pediatric stroke','pediatrics'], 'Pediatric', TRUE, ARRAY['dana-harrar','arnold-sansevere'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-181', 'Curriculum Innovation: Design and Implementation of Synchronous and Asynchronous Curricula to Enhance Residents'' EEG Knowledge and Experience', ARRAY['Fernandez A','Moeller JJ','Harrar DB','Guerriero RM','Pathmanathan J','Agarwal N','Madan Cohen J','Kephart A','Lado FA','Sahaya K','Weber DJ'], 'Neurol Educ', 2023, 11, '10.1212/NE9.0000000000200101', '39359320', 'PMC11419299', 'There is a need for structured EEG education opportunities to enhance neurology resident education. To address this need, the American Epilepsy Society (AES) supported the development and implementation of both synchronous and asynchronous EEG courses.

To produce EEG curricula that enhance resident EEG learning, increase interest in EEG and improve participants'' knowledge, and to ensure that courses were highly used and available to the broadest range of learners.

A multi-institutional group of EEG educators developed both courses. The synchronous curriculum consisted of a mixture of brief "mini-lectures" and interactive small group activities with self-assessment quizzes at the start and end of the course. The online asynchronous EEG curriculum consisted of self-directed slide sets, multiple-choice self-assessment quizzes and a structured EEG self-assessment tool. Courses were evaluated using postcourse surveys, analysis of pretest and posttest data, and analysis of user data from the asynchronous curriculum.

Between 2019 and 2021, 56 residents participated in the synchronous EEG courses. On the resident survey, mean Likert scores for course design, planning, and learning outcomes ranged from 4.6 to 5.0 for the in-person courses and from 3.9 to 4.5 for the virtual course. On the 24-item pretests and posttests, overall median scores increased from 60% (14.5/24) to 75% (18/24;< 0.001). More than 2,300 learners completed the first submodule of the asynchronous curriculum, but only 164 completed all sections. Most of those who completed the asynchronous curriculum reported that it was effective and appropriate for resident-level learning.

The AES EEG courses provide EEG learning opportunities for neurology residents beyond what is available at their home institutions. There is evidence for the effectiveness of the synchronous course, but the scope is limited to a small number of attendees. The asynchronous curriculum is more broadly available, but very few learners completed all elements. Future steps will include expansion of the in-person synchronous course and providing guidance to learners about the core and optional components of the asynchronous curriculum to increase the impact of both educational offerings.', 'article', ARRAY['EEG','Survey','Education','Epilepsy'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-182', 'Defining neonatal status epilepticus: A scoping review from the ILAE neonatal task force', ARRAY['Nunes ML','Yozawitz EG','Wusthoff CJ','Shellhaas RA','Olivas-Pe&#xf1;a E','Wilmshurst JM','Pressler RM','Triki CC','Hartmann H','Inder T','Boylan GB','Valente K','Moshe SL','Mizrahi EM','Abend NS'], 'Epilepsia Open', 2024, 11, '10.1002/epi4.13090', '39540265', 'PMC11803272', 'To review the available literature concerning the definition of neonatal status epilepticus (SE) and/or seizure burden.

The International League Against Epilepsy Neonatal Task Force performed a scoping review of the definitions of neonatal SE. Following a systematic literature review, articles were screened and data were abstracted regarding: (1) article characteristics (author identification, publication year, journal name, digital object identifier, title, objective, and study design); (2) cohort characteristics (sample size, gestational age, seizure etiology); (3) definition of SE and/or seizure burden; and (4) the method used to identify and classify SE, including routine EEG (EEG), continuous EEG monitoring (cEEG), amplitude-integrated EEG (aEEG), or clinical features.

The scoping review yielded 44 articles containing a definition of neonatal SE. Studies mainly included infants with hypoxic-ischemic encephalopathy or neonates considered at risk for seizures. SE identification and classification most often relied on cEEG. The majority of studies based the definition of SE on seizure duration, including summed duration of seizures comprising ≥50% of any 1-h epoch, recurrent seizures for >50% of the total recording time, or either electrographic seizures lasting >30 min and/or repeated electrographic seizures totaling >50% in any 1-h period. Seizure burden was reported in 20 studies, and the most commonly used approach assessed total seizure burden, defined as total duration of EEG seizures in minutes. Sixteen studies assessed the relationship between seizure burden and outcomes, and most identified a significant association between higher seizure burden and unfavorable outcomes.

This scoping review demonstrates a substantial variation in neonatal SE definitions across the literature. The most common definitions were based around a 30-min seizure duration criterion, but evidence was insufficient to support that 30 min was a cutoff defining prolonged seizures or that seizures exceeding this burden were more likely to be pharmacoresistant or associated with worse outcomes. As a next step, the Neonatal Task Force intends to develop a standardized approach to assessing and describing neonatal seizure burden and defining neonatal SE.

Prolonged seizures are a neurologic emergency, if untreated, can lead to permanent injury or death. In adults and children, seizures lasting longer than 30 min are believed to cause brain damage. However, it is not clear if this definition can be applied to neonates. The International League Against Epilepsy Neonatal Taskforce performed a scoping literature review which identified 44 articles containing a definition of neonatal status epilepticus. In this article, the authors reviewed the current used definitions for prolonged seizures in neonates to establish a relationship between seizure duration and neurological outcome. As a next step, the Neonatal Task Force intends to develop a standardized approach to assessing and describing neonatal seizure burden and defining neonatal SE.', 'review', ARRAY['Status Epilepticus','EEG','Neonatal','Stroke','Review'], ARRAY['neonatal','neurocritical care','outcome','seizure burden','seizures','status epilepticus'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-183', 'New-Onset Refractory Status Epilepticus With Diffuse Cerebral Restricted Diffusion in Young Children: A Novel Clinical-Radiologic Presentation', ARRAY['Reecher HM','Mehta NP','Patel ND','Sawdy RA','Farias-Moeller R'], 'Pediatr Neurol', 2024, 10, '10.1016/j.pediatrneurol.2024.10.009', '39541921', NULL, 'New-onset refractory status epilepticus (NORSE) is a clinical presentation characterized by explosive-onset refractory status epilepticus (RSE) without evident etiology or active epilepsy, often leading to devastating epilepsy. There is heterogeneity in neuroradiographic findings for NORSE. We encountered a series of young patients with NORSE who had diffuse cerebral restriction in diffusion (DCRD) with similar radiographic appearances as acute encephalopathy with biphasic seizures and late restricted diffusion/acute leukoencephalopathy with restricted diffusion (AESD/ALERD). We explore clinical similarities and proposed pathophysiologic overlaps to highlight a novel clinical-radiologic presentation.

Retrospective review was completed for patients younger than five years meeting NORSE criteria and then screened for radiographic evidence of DCRD. Demographic, clinical, and outcome data were collected.

Eleven patients met NORSE criteria, of whom seven displayed DCRD. Immunosuppressant management varied. All patients required multiple antiseizure medications and continuous infusions for RSE. Only one had an etiology identified (genetic). All but one patient developed diffuse, global, and progressive cerebral atrophy. Two patients died: one after prolonged seizure three years post-NORSE and another of unknown causes two months post-NORSE. Of five survivors, three have medically refractory epilepsy. Most survivors have severe disability.

We present a single-center case series of seven patients with NORSE and DCRD, akin to AESD/ALERD. Our patients differed clinically to AESD/ALERD in terms of seizure severity and poorer outcome. There is a need to develop biomarkers for specific NORSE phenotypes. The young child with NORSE and DCRD may represent a novel phenotype with a specific neuroradiographic signature that deserves further attention.', 'article', ARRAY['Status Epilepticus','Pharmacology','Biomarkers','NORSE/FIRES'], ARRAY['aesd','alerd','epilepsy','fires','infants','norse','pediatrics'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-184', 'Automated assessment of EEG background for neurodevelopmental prediction in neonatal encephalopathy', ARRAY['Lagac&#xe9; M','Montazeri S','Kamino D','Mamak E','Ly LG','Hahn CD','Chau V','Vanhatalo S','Tam EWY'], 'Ann Clin Transl Neurol', 2024, 11, '10.1002/acn3.52233', '39543820', 'PMC11651191', 'Assess the capacity of brain state of the newborn (BSN) to predict neurodevelopment outcomes in neonatal encephalopathy.

Trends of BSN, a deep learning-based measure translating EEG background to a continuous trend, were studied from a three-channel montage long-term EEG monitoring from a prospective cohort of 92 infants with neonatal encephalopathy and neurodevelopmental outcomes assessed by Bayley Scales of Infant Development, 3rd edition (Bayley-III) at 18 months. Outcome prediction used categories "Severe impairment" (Bayley-III composite score ≤70 or death) or "Any impairment" (score ≤85 or death).

"Severe impairment" was predicted best for motor outcomes (24 h area under the curve (AUC) = 0.97), followed by cognitive (36 h AUC = 0.90), overall (24 h AUC = 0.84), and language (24 h AUC = 0.82). "Any impairment" was best predicted for motor outcomes (12 h AUC = 0.95), followed by cognitive (24 h AUC = 0.85), overall (12 h AUC = 0.75), and language (12 and 24 h AUC = 0.68). Optimal BSN cutoffs for outcome predictions evolved with the postnatal age. Low BSN scores reached a 100% positive prediction of poor outcomes at 24 h of age.

BSN is an excellent predictor of adverse neurodevelopmental outcomes in survivors of neonatal encephalopathy after therapeutic hypothermia, even at 24 h of life. The trend provides a fully automated, objective, quantified, and reliable interpretation of EEG background. The high temporal resolution supports continuous bedside brain assessment and early prognostication during the initial dynamic recovery phase.', 'article', ARRAY['EEG','Neonatal','Machine Learning','Biomarkers'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-185', 'Electroencephalographic (EEG) Stages in Patients With Cerebral Edema Following Cardiac Arrest', ARRAY['Horvat DE','Keenan JS','Conley C','Staso K','Harrar DB','Sansevere AJ'], 'J Child Neurol', 2024, 11, '10.1177/08830738241289161', '39558681', NULL, 'ObjectiveTo describe electroencephalographic (EEG) changes in pediatric patients with cerebral edema after cardiac arrest.MethodsA retrospective study of patients admitted to the pediatric intensive care unit from July 2021 to January 2023. We included patients with cardiac arrest and changes in EEG background with clinical changes and/or neuroimaging consistent with cerebral edema. We excluded patients with electrographic seizures. We applied American Clinical Neurophysiology Society standardized critical care EEG terminology to classify EEG background, noting timing of the change in background classification. Clinical variables included age, sex, and neuroimaging findings and were described with descriptive statistics.ResultsNine patients met inclusion criteria, with median age 24 months (interquartile range 21-49), and 89% were male. There were 5 common EEG stages: stage 1, burst suppression/burst attenuation; stage 2, continuous/discontinuous ± multifocal sporadic epileptiform discharges ± rhythmic or periodic patterns; stage 3, discontinuous/burst suppression/burst attenuation ± rhythmic or periodic patterns; stage 4, gradual voltage suppression; and stage 5, diffuse suppression. The ranges for each stage were as follows: stage 1, 2-10 hours; stage 2, 2.5-15.5 hours; stage 3, 0.5-6.24 hours; and stage 4, 0.5-11 hours. We could not calculate the duration of stage 5 given no uniform time to EEG discontinuation. One patient had a clinical change in stage 3. Remaining patients presented with fixed and dilated pupils with global anoxic injury.ConclusionsEEG stages of cerebral edema have not been described after pediatric cardiac arrest. These stages may be relevant to other patient populations. Early stages may be a therapeutic target for intracranial pressure-lowering medications and/or neuroprotective strategies to minimize sequalae of cerebral edema.', 'article', ARRAY['Cardiac Arrest','EEG','Seizures','Pharmacology'], ARRAY['eeg','intracranial hypertension','outcome'], 'Pediatric', TRUE, ARRAY['dana-harrar','arnold-sansevere'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-186', 'Development of a model to predict electroencephalographic seizures in neonates with hypoxic ischemic encephalopathy treated with therapeutic hypothermia', ARRAY['Massey SL','Sandoval Karamian AG','Fitzgerald MP','Fung FW','Abramson A','Salmon MK','Parikh D','Abend NS'], 'Epilepsia', 2024, 12, '10.1111/epi.18196', '39680059', 'PMC11827730', 'Electroencephalographic seizures (ES) are common in neonates with hypoxic-ischemic encephalopathy (HIE), but identification with continuous electroencephalographic (EEG) monitoring (CEEG) is resource-intensive. We aimed to develop an ES prediction model.

Using a prospective observational study of 260 neonates with HIE undergoing CEEG, we identified clinical and EEG risk factors for ES, evaluated model performance with area under the receiver operating characteristic curve (AUROC), and calculated test characteristics emphasizing high sensitivity. We assessed ES incidence and timing in neonates subdivided by ES risk group (low, moderate, high) as determined by EEG risk factors.

ES occurred in 32% (83/260) of neonates. Performing CEEG for only 24 h would fail to identify the 7% (17/260) of neonates with later onset ES (20% of all neonates experiencing ES). Identifying 90% or 95% of neonates with ES would require CEEG for 63 or 74 h, respectively. The optimal model included continuity and epileptiform discharges, both assessed in the initial 1 h of CEEG. It yielded an AUROC of .80, and at a cutoff that emphasized sensitivity, had sensitivity of 94%, specificity of 45%, positive predictive value of 44%, and negative predictive value of 95%. The model would avoid CEEG beyond 1 h in 32% (84/260) of neonates, but 6% (5/83) of neonates with ES would not have ES identified. ES incidence was significantly different (p < .01) across ES risk groups (6% low, 40% moderate, and 83% high). Only ~6 h of CEEG would identify all neonates with ES in the low-risk group, whereas 75 and 63 h of CEEG would be required to identify 95% of neonates with ES in the moderate-risk and high-risk groups, respectively.

Among neonates with HIE, a model employing two EEG variables from a 1-h screening EEG and stratifying neonates into low-, moderate-, and high-risk groups could enable evidence-based strategies for targeted CEEG use.', 'article', ARRAY['EEG','Neonatal','Seizures','Stroke'], ARRAY['continuous eeg monitoring','electroencephalogram','hypoxic&#x2013;ischemic encephalopathy','neonatal','seizure','status epilepticus'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-187', 'Navigating life after New-onset refractory status epilepticus (NORSE) and Febrile infection-related epilepsy syndrome (FIRES): Insights from caregiver and patient interviews', ARRAY['Eschbach K','Reedy J','Gofton T','Gopaul M','Farias-Moeller R','Kellogg M','Knupp K','Hirsch LJ','Wong N','Dorsey Holliman B'], 'Epilepsy Behav', 2024, 12, '10.1016/j.yebeh.2024.110236', '39740258', NULL, 'To describe the lived experience of patients with NORSE and explore quality of life (QOL) for patients and their caregivers.

NORSE is a rare condition characterized by refractory status epilepticus, often of unknown cause, in a previously neurologically healthy individual. Febrile infection-related epilepsy syndrome (FIRES) is a subset of NORSE. NORSE is associated with a risk of mortality, acute morbidity, and neurocognitive sequela with limited data about the long-term impacts.

We conducted in-depth individual or dyadic semi-structured interviews with patients and caregivers. Interviews explored the long-term experiences after NORSE and its impacts on patient and caregiver QOL. Data were analyzed using a thematic content analysis approach.

Fourteen interviews, comprising 5 patients and 15 caregivers, were completed between April 2023 - February 2024. The median age at NORSE onset was 17 years (IQR: 11.00 - 20.25) with a median of 5.60 years (IQR: 3.88 - 8.50) since onset. While experiences varied based on NORSE outcomes and time since onset, we identified the following themes: 1) Seizures, medication side effects, and comorbid health concerns impact patient independence and QOL; 2) Mental and behavioral health concerns compounded by loneliness and isolation impact patient QOL; 3) Friend and family relationship changes impact patient social and emotional QOL; 4) Family members take on care of the patient and experience significant life changes.

NORSE has significant life-altering impacts on patients and caregivers. These findings highlight a need to evaluate outcomes and provide support that extends beyond seizure management.', 'article', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Outcomes'], ARRAY['fires','febrile infection related epilepsy syndrome','norse','new onset refractory status epilepticus','qol','quality of life'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-188', 'Prediction of good neurological outcome after return of circulation following paediatric cardiac arrest: A systematic review and meta-analysis', ARRAY['Scholefield BR','Tijssen J','Ganesan SL','Kool M','Couto TB','Topjian A','Atkins DL','Acworth J','McDevitt W','Laughlin S','Guerguerian AM'], 'Resuscitation', 2024, 12, '10.1016/j.resuscitation.2024.110483', '39742939', NULL, 'To evaluate the ability of blood-biomarkers, clinical examination, electrophysiology, or neuroimaging, assessed within 14 days from return of circulation to predict good neurological outcome in children following out- or in-hospital cardiac arrest.

Medline, EMBASE and Cochrane Trials databases were searched (2010-2023). Sensitivity and false positive rates (FPR) for good neurological outcome (defined as either ''no, mild, moderate disability or minimal change from baseline'') in paediatric survivors were calculated for each predictor. Risk of bias was assessed using the QUIPS tool.

Thirty-five studies (2974 children) were included. The presence of any of the following had a FPR < 30% for predicting good neurological outcome with moderate (50-75%) or high (>75%) sensitivity: bilateral reactive pupillary light response within 12 h; motor component ≥ 4 on the Glasgow Coma Scale score at 6 h; bilateral somatosensory evoked potentials at 24-72 h; sleep spindles, and continuous cortical activity on electroencephalography within 24 h; or a normal brain MRI at 4-6d. Early (≤12 h) normal lactate levels (<2mmol/L) or normal s100b, NSE or MBP levels predicted good neurological outcome with FPR rate < 30% and low (<50%) sensitivity. All studies had moderate to high risk of bias with timing of measurement, definition of test, use of multi-modal tests, or outcome assessment heterogeneity.

Clinical examination, electrophysiology, neuroimaging or blood-biomarkers as individual tests can predict good neurological outcome after cardiac arrest in children. However, evidence is often low quality and studies are heterogeneous. Use of a standardised, multimodal, prognostic algorithm should be studied and is likely of added value over single modality testing.', 'review', ARRAY['Cardiac Arrest','EEG','Review','Biomarkers'], ARRAY['biomarker','clinical examination','computed tomography','electroencephalogram','magnetic resonance imaging','paediatric cardiac arrest','prognosis'], 'Pediatric', TRUE, ARRAY['rishi-ganesan'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-189', 'The American Clinical Neurophysiology Society Guideline on Indications for Continuous Electroencephalography Monitoring in Neonates', ARRAY['Wusthoff CJ','Numis AL','Pressler RM','Chu CJ','Massey S','Clancy RR','Nguyen S','Hahn CD','Scher MS','Pilon B','King DT','Wong HN','Tsuchida TN','Riviello JJ','Shellhaas RA'], 'J Clin Neurophysiol', 2024, 10, '10.1097/WNP.0000000000001120', '39752571', NULL, 'Continuous EEG (cEEG) monitoring is increasingly used in the management of neonates with seizures. There remains debate on what clinically relevant information can be gained from cEEG in neonates with suspected seizures, at high risk for seizures, or with definite seizures, as well as the use of cEEG for prognosis in a variety of conditions. In this guideline, we address these questions using American Clinical Neurophysiology Society structured methodology for clinical guideline development.

A working group was formed from American Clinical Neurophysiology Society membership with expertise in neonatal cEEG and a set of priority questions developed. We performed literature searches in PubMed and EMBASE to identify relevant studies. Evidence tables were compiled from extracted data and quality assessments performed. A modification of the GRADE process was used to evaluate the body of evidence and draft recommendations.

Our working group identified six priority questions to evaluate the accuracy of cEEG for neonatal seizure diagnosis and the formulation of prognosis. An initial literature search yielded 18,167 results, which were distilled to a set of 217 articles. Overall, the quality of evidence for most priority questions was rated as very low and we provided conditional recommendations based on published literature and expert consensus. For each priority question, we also considered the benefits and harms of cEEG, with relative harms considered to be far less than the potential benefits across recommendations.

We present evidence-based clinical guidelines regarding indications for cEEG monitoring in neonates. Considering resource utilization and feasibility, when cEEG monitoring results have a likelihood of altering clinical decision making, the authors felt the resource investment was justifiable.', 'article', ARRAY['EEG','Neonatal','Seizures','Outcomes'], ARRAY[]::TEXT[], 'Neonatal', TRUE, ARRAY['cecil-hahn','james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-190', 'Medical & Socioeconomic Risk Factors Associated with Lack of Neurodevelopmental Evaluation Following Neonatal Cardiac Surgery', ARRAY['Essaid L','Haque K','Shillingford A','Zimmerman L','Burnham A','Hampton L','Okunowo O','Gaynor JW','Abend NS','Naim MY','Gardner MM'], 'Pediatr Cardiol', 2025, 1, '10.1007/s00246-024-03761-w', '39755847', NULL, 'Neonates with congenital heart disease (CHD) who undergo cardiopulmonary bypass (CPB) are at high-risk for unfavorable neurodevelopmental (ND) outcomes and are recommended for ND evaluation (NDE); however, poor rates have been reported. We aimed to identify risk factors associated with lack of NDE. This single-center retrospective observational study included neonates < 30 days old who underwent CPB and survived to discharge between 2012 and 2018. Primary outcome (NDE) was ≥ 1 appointment at our center''s dedicated cardiac, neonatal, or general ND clinics before the 3rd birthday. Predictor variables included demographic, medical, and social factors. Social disorganization index (SDI) was obtained with geocoding based on address at time of discharge. Logistic regression identified risk factors associated with lack of NDE. The cohort included 594 patients, predominantly male (59%) and white (59%). A majority (63%) had NDE. Lack of NDE was more common in patients with postnatal CHD diagnosis, CHD without arch obstruction, absence of postoperative seizures, living below 100% poverty level, lack of insurance, younger parental age, and overall higher SDI (p < 0.03). In multivariable analysis, lack of NDE was associated with single-ventricle CHD without arch obstruction (OR 2.17; 95% CI 1.08-4.55), two ventricle CHD without arch obstruction (OR 2.56; 95% CI 1.59-4.17), and higher SDI (OR 1.25; 95% CI 1.05-1.49); all p < 0.05. This study identifies medical and neighborhood-level socioeconomic factors that may help address care gaps in this high-risk population. Patients with socioeconomic disparities may benefit from increased care coordination upon discharge.', 'article', ARRAY['Neonatal','Seizures','Biomarkers','Outcomes'], ARRAY['congenital heart disease','disparities','neurodevelopment','outcomes'], 'Neonatal', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-191', 'Development and Validation of a Postprocedure Stroke Screening Tool in Children With Cardiac Disease', ARRAY['Harrar DB','Salussolia CL','Keith LG','Ye S','Meadows JS','Fialkow A','Zhu G','VanderPluym C','Zhang B','Rivkin MJ'], 'J Child Neurol', 2025, 1, '10.1177/08830738241302511', '39801153', NULL, 'BackgroundCardiac catheterization in children with heart disease is associated with an increased risk of arterial ischemic stroke. We created and evaluated the diagnostic performance of a bedside screening tool administered postprocedure to identify arterial ischemic stroke.MethodsWe developed a postprocedure stroke screen comprising history of stroke, responsiveness, command following, speech, facial and limb strength symmetry, new seizure, and caregiver concern. We compared the performance of the screening tool in a retrospective cohort of 21 patients with a postcatheterization arterial ischemic stroke and a prospective cohort of 100 consecutive control patients after cardiac catheterization.ResultsThe postprocedure stroke screen delivered a maximum Youden index ranging from 0.810 to 0.937 at threshold scores of 2 or 2.5 and gave a sensitivity and specificity >0.9. The area under the receiver operating characteristic curve ranged from 0.931 to 0.946.ConclusionsWe developed a screening tool with high sensitivity and specificity to identify postcatheterization arterial ischemic stroke in children.', 'article', ARRAY['Seizures','Stroke'], ARRAY['arterial ischemic stroke','cardiac catherization','congenital heart disease','stroke screen'], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-192', 'Age-associated differences in FIRES: Characterizing prodromal presentation and long-term outcomes via the web-based NORSE/FIRES Family Registry', ARRAY['Kazazian K','Gaspard N','Hirsch LJ','Kellogg M','Hocker SE','Wong N','Farias-Moeller R','Eschbach K','Gofton TE'], 'Epilepsia', 2025, 1, '10.1111/epi.18260', '39804054', 'PMC11908657', 'Febrile infection-related epilepsy syndrome (FIRES) is a rare clinical presentation of refractory status epilepticus following a febrile infection. This study analyzes data from the NORSE/FIRES Family Registry, an international web-based registry available in six languages with data entered by patients, families, and clinicians to explore clinical presentations, survivorship, and long-term outcomes in adult and pediatric FIRES patients. We characterize and examine differences in demographics, prodromal symptoms, seizure frequency, anti-seizure medications (ASMs), quality of life, cognition, mood, and anxiety in adults vs pediatric populations with FIRES. Eighty-six participants were included in the study. Pediatric patients (n = 54) were predominantly male (77.8%) and experienced a significantly higher post-FIRES seizure burden than adult survivors (67.7% ≥12 seizures/month in pediatrics vs 11.8% in adults, p <.001). Adults (n = 32) were more likely to be female (59.4%) and have flu-like prodromal symptoms (90.6%). At ≥6 months post-FIRES, both groups exhibited high ASM use, with the majority (87.5%) taking three or more medications. Pediatric patients reported worse mood and anxiety outcomes compared to adults (p <.005). Self-reported quality of life and cognition were rated as moderate across in adults (5.2/10) and pediatric (4.7/10) patients, although pediatric patients indicated poorer cognition. Our findings highlight the challenges in managing post-FIRES outcomes across different age groups, particularly in pediatric patients who face a higher seizure burden and report worse cognitive outcomes.', 'article', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES','Outcomes'], ARRAY['febrile infection&#x2013;related epilepsy syndrome','long&#x2010;term outcomes','new&#x2010;onset refractory status epilepticus','refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-193', 'New onset refractory status epilepticus: Long-term outcomes beyond seizures', ARRAY['Espino PH','Eschbach K','Blank LJ','Cervenka MC','Muscal E','Farias-Moeller R','Gilmore EJ','Gopaul MT','Haider HA','Hanin A','Hirsch LJ','Kellogg MA','Kluger G','Lee ST','Melendez-Zaidi AE','Navarro V','Oliger AC','Pasini E','Reuner G','Sharpe CM','Sheikh ZB','Steigleder L','Steriade C','Stredny CM','Strzelczyk A','Taraschenko O','van Baalen A','Vinette SA','Wickstr&#xf6;m R','Wong NW','Yoo J','Gofton TE'], 'Epilepsia', 2025, 1, '10.1111/epi.18267', '39825688', 'PMC11997932', 'We propose and prioritize important outcome domains that should be considered for future research investigating long-term outcomes (LTO) after new onset refractory status epilepticus (NORSE). The study was led by the international NORSE Institute LTO Working Group. First, literature describing the LTO of NORSE survivors was identified using a PubMed search and summarized to identify knowledge gaps. Subsequently, a consensus-building process was performed to prioritize and rank important LTO domains for further research. The prioritization of LTO domains was qualitative, enabling the expert panel to generate ideas, share opinions, and provide reasons for the rankings. A second round took place to allow expansion and agreement regarding specific details for each domain. Outcomes were classified into eight main domains: (1) Function: Neuropsychological, Neurological (other than seizures), and Psychiatric (mood and behavior); (2) Quality of Life; (3) Epilepsy; (4) Nonneurological (medical); (5) Social; (6) Caregiver Burden; (7) Long-Term Mortality; and (8) Health Care System Impact. In addition, the working group suggested obtaining outcome measures for each domain at 6 months and 1 year after discharge and annually thereafter until stability has been reached. There are no currently established time frames set for when LTO in NORSE begin or plateau, and previously there existed no consensus regarding which LTO should be considered. This consensus process identifies and recommends NORSE LTO domains that should be considered in future research studies to provide more consistent results that can be compared between studies. Survivors of NORSE should be evaluated serially and at fixed points over time to maximize our understanding of the recovery trajectory for all LTO domains. Establishing reliable and standardized data describing LTO (beyond seizures) after NORSE will support discussions with families during the acute stages, prognostication, the development of targeted management strategies for survivors, and future comparative research globally helping to identify biomarkers that may predict LTO.', 'review', ARRAY['Status Epilepticus','Review','Pharmacology','Biomarkers','NORSE/FIRES'], ARRAY['fires','norse','epilepsy','neuropsychological','psychiatric','quality of life'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-194', 'Combined Systemic Immunotherapy and Intrathecal Dexamethasone in Febrile Infection Related Epilepsy Syndrome', ARRAY['Fisher KS','Ankar A','Cokley J','Muscal E','Riviello JJ','Lai YC'], 'Ann Clin Transl Neurol', 2025, 2, '10.1002/acn3.70011', '39932904', 'PMC12040501', 'Febrile infection related epilepsy syndrome (FIRES) is a rare presentation of refractory status epilepticus with immune dysregulation as a potential pathologic mechanism. Despite promising results from second-line immunomodulators, approximately 30% remain refractory to treatment. We describe two children with FIRES who were unable to wean from anesthetic infusions with immunomodulatory treatment and subsequently received concurrent intrathecal dexamethasone and anakinra/tocilizumab as escalation of therapy. Following the initiation of this combined regimen, anesthetic infusions were decreased while maintaining seizure freedom. These cases demonstrate proof of principle that a multi-modal approach may be beneficial and should be considered in the treatment of FIRES.', 'case_report', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES'], ARRAY['cns immune modulation','anakinra','febrile infection related epilepsy syndrome (fires)','intrathecal dexamethasone','new onset refractory status epilepticus (norse)','systemic immune modulation','tocilizumab'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-195', 'Comparison of lacosamide, levetiracetam, and valproate as second-line therapy in adult status epilepticus: Analysis of a large cohort', ARRAY['Hahn CD','Novy J','Rossetti AO'], 'Epilepsia', 2025, 3, '10.1111/epi.18380', '40119876', NULL, 'We compared the efficacy of lacosamide to other frequently used second-line anti-seizure medications (ASMs) for adult status epilepticus (SE) by conducting a retrospective analysis of an institutional SE registry between January 2013 and December 2022. Clinical outcomes assessed at discharge were categorized as return to baseline, new disability, or death; we also considered SE termination after the second-line ASM and the need for mechanical ventilation. Potential confounders included the Status Epilepticus Severity Score (STESS), sex, adequacy of initial SE treatment, treatment delay, and potentially fatal etiology. Over 10 years, 961 adult SE episodes were analyzed; 868 were treated with the following second-line ASMs: 413 levetiracetam (47.6%), 110 valproate (12.7%), and 75 lacosamide (8.6%), as well as lower rates of 18 other ASMs including benzodiazepines (not further analyzed). Univariable analysis identified STESS, treatment delay, and adequacy of initial SE treatment as potential confounders. On multivariable analysis adjusting for these variables, patients with episodes treated with second-line lacosamide, levetiracetam, or valproate demonstrated statistically equivalent rates of seizure cessation, need for mechanical ventilation, and clinical outcomes at hospital discharge. We conclude that lacosamide appears to represent a reasonable alternative to levetiracetam and valproate, and warrants consideration for inclusion in future randomized controlled trials for control of SE.', 'article', ARRAY['Status Epilepticus','Pharmacology','Outcomes'], ARRAY['anti&#x2010;seizure medication','cohort study','comparative study','lacosamide','status epilepticus'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-196', 'Association of Physiologic Parameters with Neurologic Outcome After Arteriovenous Malformation Rupture in Children', ARRAY['Keenan JS','Har C','Yan F','Sepeta L','Staso K','Conley CR','Sansevere AJ','Harrar DB'], 'J Child Neurol', 2025, 4, '10.1177/08830738251330110', '40266567', NULL, 'Evidence to guide the critical care management of children with ruptured brain arteriovenous malformations is lacking. We aimed to determine whether there are associations between physiologic parameters and outcome in children with ruptured brain arteriovenous malformations. We performed a single-center retrospective review of patients ≤18 years of age with a ruptured brain arteriovenous malformation from 2011 to 2023. Categorization of outcome was based on the Pediatric Stroke Outcome Measure. Descriptive statistics were used. Most patients with an arteriovenous malformation rupture had a poor outcome at discharge (31/49, 63%) and in follow-up at 3-12 months (21/37, 57%). Patients who were normothermic and normoglycemic for the first 7 days after arteriovenous malformation rupture were less likely to have a poor outcome at discharge than those who had a temperature ≥38 °C (odds ratio [OR] 0.14, 95% confidence interval [CI] 0.04-0.52; = .01) or a blood glucose ≥200 mg/dL (OR 0.11, 95% CI 0.01-0.92; = .04). A lower minimum hemoglobin concentration (10.00 g/dL [standard deviation (SD) 1.67] vs 12.46 g/dL [SD 6.29],(47) 2.07, = .04) and a higher average partial pressure of carbon dioxide (Paco) (40.98 mm Hg [SD 4.30] vs 35.58 mm Hg [SD 7.72],(47) -2.09, = .046) were also associated with a poor discharge outcome. A higher average maximum temperature was associated with a poor outcome in follow-up (37.46° C [SD 0.49] vs 37.09 °C [SD 0.59],(47) -2.09; = .04). Temperature, blood glucose, hemoglobin concentration, and Pacoare potentially modifiable parameters that could be targeted by quality improvement interventions to improve outcomes in this population.', 'article', ARRAY['Stroke','Outcomes'], ARRAY['arteriovenous malformation','hemorrhagic stroke','hyperglycemia','hyperthermia','pediatric stroke'], 'Pediatric', TRUE, ARRAY['arnold-sansevere','dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-197', 'Midazolam infusions for therapeutic management of pediatric refractory status epilepticus: a systematic review', ARRAY['Johnson KT','AlZadjali A','Al Nasseri D','Cunningham J','Shoya K','Hahn CD','Basmaji J','McKinnon NK'], 'Front Pediatr', 2025, 4, '10.3389/fped.2025.1507325', '40297557', 'PMC12034653', 'We aim to determine the optimal dosing of midazolam continuous intravenous infusions for the treatment of pediatric refractory status epilepticus (RSE).

We searched Medline ALL, Embase, Embase Classic, Cochrane CENTRAL, and Web of Science in March 2023 and again in February 2024.

Randomized and non-randomized studies involving pediatric patients who received continuous midazolam for the treatment of RSE were eligible. Two authors independently conducted screening, full-text review, and data extraction. All methods followed PRISMA reporting guidelines. A narrative data synthesis was performed due to data heterogeneity.

Nineteen studies (448 patients) proved eligible; 3 were randomized control trials, while 16 were non-randomized studies. All studies had concerns regarding the risk of bias. Overall, midazolam aborted seizures in 363/448 (81%) participants, with mean effective doses of 1.7-13.0 μg/kg/min (0.17-0.78 mg/kg/h). The remaining 85 participants (19%) who did not achieve seizure cessation received maximum doses of 1.7-32.0 μg/kg/min (0.17-1.92 mg/kg/h) prior to transitioning to another agent. Only 4 studies specified that boluses were given with each titration. Twelve studies reported that seizure cessation occurred at a mean time of 1.4-546.0 min (range 0-720 min) after midazolam initiation. In 8 of these studies, effective midazolam doses clustered at 2.0-5.0 μg/kg/min (0.12-0.30 mg/kg/h), with seizure cessation occurring within 10-70 min in 204/221 (92%) participants. Treatment-associated adverse events included intubation in 42/221 (19%) and hypotension requiring fluids or no intervention in 18/221 (8%). The studies did not differentiate between intubations performed as part of the study protocol or prior to midazolam infusion initiation nor did they specify whether hypotension was related to the co-administration of phenytoin or phenobarbital.

Data supporting midazolam continuous infusion dosing are limited and heterogeneous. Our findings suggest a potential therapeutic window at rates of 2.0-5.0 μg/kg/min (0.12-0.30 mg/kg/h), with limited adverse risks. Earlier seizure cessation may be achieved by targeting this therapeutic window by starting treatment with higher doses than the typically used 1.0 μg/kg/min (0.06 mg/kg/h) or by rapidly escalating the dose.PROSPERO, identifier CRD42023413038.', 'review', ARRAY['Status Epilepticus','Review'], ARRAY['intensive care units','midazolam','pediatric','refractory status epilepticus','therapeutic window','treatment'], 'Pediatric', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-198', 'Improving Timely Diagnosis of Arterial Ischemic Stroke at a Pediatric Emergency Department', ARRAY['Trigylidas TE','McCollum NL','Brown KM','Heffren JC','Wells EM','Pergami P','Murnick J','LaViolette D','Harrar DB'], 'Pediatrics', 2025, 6, '10.1542/peds.2024-067166', '40314401', NULL, 'Pediatric arterial ischemic stroke (AIS) is an important cause of morbidity and mortality that requires early recognition to benefit from hyperacute therapies. We sought to improve timely diagnosis of AIS through an interdisciplinary stroke response protocol.

A quality improvement initiative was implemented at our pediatric hospital emergency department from November 2019 to June 2023. We introduced a series of Plan-Do-Study-Act cycles that included educational initiatives (October 2021), the development of a stroke alert paging system to key stakeholders (November 2021), and stroke order set modifications (April 2022). All patients aged 0 to 21 years with clinical concern for AIS that had neuroimaging performed in the emergency department met criteria for inclusion in analysis. Our outcome measure was improvement of median door-to-imaging time for children with suspected AIS. Median door-to-imaging times for patients with confirmed stroke on imaging were also measured. Statistical process control charts were used to monitor data over time.

A total of 71 patients met criteria for inclusion in analysis during our study period. Four patients had confirmed AIS on neuroimaging. Median door-to-imaging time improved from 128 minutes to 68 minutes after intervention. Times improved from 113 minutes to 68 minutes for patients with confirmed stroke.

Stroke alert teams may be beneficial for coordination of care and support in ensuring a higher proportion of children with clinical concern for AIS receive expedited neuroimaging.', 'article', ARRAY['Neonatal','Stroke','Education','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['dana-harrar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-199', 'Time to treatment in pediatric patients with repeated episodes of status epilepticus', ARRAY['Gettings JV','Fern&#xe1;ndez IS','Anderson A','Brenton JN','Can A','Clark J','Moeller RF','Goodkin HP','Lai YC','Mikati MA','Morgan LA','Novotny E','Ostendorf AP','Piantino J','Riviello JJ','Sannagowdara K','Tasker RC','Tchapyjnikov D','Wainwright MS','Wilfong A','Williams K','Zhang B','Loddenkemper T','Ga&#xed;nza-Lein M'], 'BMC Neurol', 2025, 5, '10.1186/s12883-025-04200-w', '40420060', 'PMC12105332', 'To compare pediatric patients who presented with repeated status epilepticus episodes to patients with a single episode of status epilepticus and identify distinguishing clinical factors.

Retrospective analysis of a multicenter, prospective observational cohort of pediatric patients with status epilepticus between 2011 and 2019.

Out of 504 status epilepticus episodes in 420 patients, 50 patients (10.3%) had repeated episodes of status epilepticus. The only predictor of repeated status epilepticus was a prior diagnosis of epilepsy. There was no difference in time to treatment with the first benzodiazepine in patients presenting with their first status epilepticus episode compared to their second status epilepticus episode [median 10 (interquartile range 5-30) vs. 14 (4.5-52.5) minutes; (p = 0.24)] or in time to treatment with the first non- benzodiazepine anti-seizure medication (ASM) [61 (37-125) vs. 71 (34.5-117.5) minutes; p = 0.61]. In patients with repeated status epilepticus episodes with onset outside the hospital, the percentage of patients treated by caregivers did not improve between the first and second status epilepticus episode (61% vs. 60%, p = 0.56). However, the time to first benzodiazepine was shorter in patients treated by caregivers compared to those who were not [5 (0-25) vs. 55 (41-120) minutes; p < 0.001].

Time to treatment with benzodiazepine and non-benzodiazepine ASM in patients with repeated episodes of status epilepticus does not improve for a second episode of status epilepticus, suggesting additional opportunities for intervention and teaching.', 'article', ARRAY['Status Epilepticus','Education','Pharmacology','Biomarkers'], ARRAY['anti-seizure medications','benzodiazepines','refractory status epilepticus','status epilepticus','treatment delay'], 'Pediatric', TRUE, ARRAY['adam-ostendorf','james-riviello','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-200', 'Harvard Electroencephalography Database: A comprehensive clinical electroencephalographic resource from four Boston hospitals', ARRAY['Sun C','Jing J','Turley N','Alcott C','Kang WY','Cole AJ','Goldenholz DM','Lam A','Amorim E','Chu C','Cash S','Junior VM','Gupta A','Ghanta M','Nearing B','Nascimento FA','Struck A','Kim J','Sartipi S','Tauton AM','Fernandes M','Sun H','Bayas G','Gallagher K','Wagenaar JB','Sinha N','Lee-Messer C','Silvers CT','Gunapati B','Rosand J','Peters J','Loddenkemper T','Lee JW','Zafar S','Westover MB'], 'Epilepsia', 2025, 6, '10.1111/epi.18487', '40464151', 'PMC12455399', 'This article presents the Harvard Electroencephalography Database (HEEDB), a large-scale, deidentified, and standardized electroencephalographic (EEG) resource supporting artificial intelligence-driven and reproducible research in epilepsy and broader clinical neuroscience.

HEEDB aggregates more than 280 000 EEG recordings from more than 108 000 patients across four Harvard-affiliated hospitals. Data are harmonized using the Brain Imaging Data Structure and hosted on the Brain Data Science Platform. EEG data are linked with clinical notes, International Classification of Diseases, 10th Revision codes, medications, and EEG reports. Deidentification follows Health Insurance Portability and Accountability Act Safe Harbor standards.

The database includes routine, epilepsy monitoring unit, and intensive care unit EEGs across all age groups, with 73% linked to deidentified clinical reports and 96% of those matched to recordings. Findings are extracted using expert curation, regular expressions, and medical natural language processing models. Auxiliary data include diagnoses, medications, and hospital course, supporting multimodal analysis.

HEEDB fills a critical gap in EEG data availability for epilepsy research. By enabling large-scale, privacy-compliant, and clinically relevant analysis, it accelerates the development of diagnostic tools, improves training datasets for machine learning, and promotes data-sharing in alignment with FAIR (Findable, Accessible, Interoperable, Reusable) and National Institutes of Health data policies.', 'article', ARRAY['Cardiac Arrest','EEG','Machine Learning','Education','Epilepsy','Pharmacology'], ARRAY['ai for neurology','data&#x2010;driven eeg analysis','deidentified clinical data','eeg data platform','eeg large&#x2010;scale database'], 'Pediatric', TRUE, ARRAY['joost-wagenaar','tobias-loddenkemper'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-201', 'A guide to developing harmonized research workflows in a team science context', ARRAY['Ruiz OE','Wagenaar JB','Mehta B','Ziogas I','Swanson L','Worley KC','Cruz-Almeida Y','Johnson AJ','Boline J','Boccanfuso J','Martone ME','Haelterman NA'], 'Exp Neurol', 2025, 6, '10.1016/j.expneurol.2025.115333', '40482901', 'PMC12233188', 'Large, interdisciplinary team science initiatives are increasingly leveraged to uncover novel insights into complex scientific problems. Such projects typically aim to produce large, harmonized datasets that can be analyzed to yield breakthrough discoveries using cutting-edge scientific methods. Successfully harmonizing and integrating datasets generated by different technologies and research groups is a considerable task, which requires an extensive supportive framework that is built by all members involved. Such a data harmonization framework includes a shared language to communicate across teams and disciplines, harmonized methods and protocols, (meta)data standards and common data elements, and the appropriate infrastructure to support the framework''s development and implementation. In addition, a supportive data harmonization framework also entails adopting processes to decide on which elements to harmonize and to help individual team members implement agreed-upon data workflows in their own laboratories/centers. Building an effective data harmonization framework requires buy-in, team building, and significant effort from all members involved. While the nature and individual elements of these frameworks are project-specific, some common challenges typically arise that are independent of the research questions, scientific techniques, or model systems involved. In this perspective, we build on our collective experiences as part of the REstoring JOINt health and function to reduce pain (RE-JOIN) Consortium to provide guidance for developing research-centered data collection and analysis pipelines that enable downstream integrated analyses within and across diverse teams.', 'review', ARRAY['Review'], ARRAY['big data','chronic pain','common data elements','data harmonization','data integration','joint disease','metadata standard','team science'], 'Pediatric', TRUE, ARRAY['joost-wagenaar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-202', 'Spectrum of Central Nervous System Disease Caused by Streptococcus anginosus Group: A Single-Center Case Series', ARRAY['Meylor J','Farias-Moeller R','Mehta N','Sawdy R','Patel ND'], 'Pediatr Neurol', 2025, 5, '10.1016/j.pediatrneurol.2025.05.022', '40555144', NULL, 'To characterize the electrophysiologic and neurological outcomes of pediatric patients with central nervous system infections secondary to Streptococcus anginosus group (SAG).

We report a retrospective case series of 15 pediatric patients admitted to the pediatric intensive care unit (PICU) with central nervous system infections caused by SAG.

The population was healthy with no significant comorbidities before presentation. Prodromal symptoms had an acute onset (less than four weeks), with most patients experiencing fever (93%), headache (87%), and fatigue (87%). Fourteen patients (93%) had subdural or epidural empyema, while one (7%) had ventriculitis. Nine patients (60%) underwent continuous electroencephalography recording. Seven patients (47%) had seizures, with three patients (20%) having subclinical seizures only. One patient (7%) developed epilepsy. Five patients (33%) had mild to moderate residual deficits on neurological examination at discharge. Neuropsychologic testing revealed emotional dysregulation (e.g., emotional reactivity, anxiety, depression), attention deficits, and difficulty with working memory.

Among our cohort, patients were previously healthy with acute onset of nonspecific symptoms. Hospitalization was typically complicated by intracranial abscesses and seizures; the prognosis was favorable, with only one third of patients experiencing neurological deficits at discharge. Neuropsychologic data showed notable psychological deficits following PICU admission.', 'article', ARRAY['EEG','Seizures','Outcomes'], ARRAY['brain abscess','continuous eeg','outcomes','pediatric','seizures','sinusitis'], 'Pediatric', TRUE, ARRAY['raquel-farias-moeller'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-203', 'Predictive power of phase 1 studies for the identification of seizure onset zone in phase 2 in a pediatric epilepsy cohort', ARRAY['Katlowitz K','Allam A','Laxpati N','Lee S','McGinnis JP','Katyayan A','Ali I','Houck KM','Nayak A','Sen S','Diaz-Medina G','Mohanty D','Clarke D','Coorg R','Seto ES','Riviello JJ','Anderson AE','Weiner HL','Curry DJ'], 'Epilepsia', 2025, 8, '10.1111/epi.18596', '40824682', NULL, 'Surgical outcomes in the management drug-resistant epilepsy (DRE) rely heavily on proper identification of the seizure onset zone (SOZ). Stereo-electroencephalography (sEEG) can be used to localize SOZs but must be hypothesis driven. Proper utilization of phase 1, noninvasive studies can maximize sEEG planning.

We performed a retrospective chart review of pediatric patients who underwent sEEG implantation for DRE at a single institution and then subsequently had treatment for an identified SOZ. Each sEEG lead was identified by phase 1, noninvasive data indicating possible SOZ localization. SOZ and patient outcomes were correlated with phase 1 study findings.

One hundred patients with a total of 1777 leads implanted over the span of 10 years were analyzed. A total of 242 SOZs were identified; 41.5% of patients were seizure-free at 1 year, and 75.4% had at least a 50% reduction in seizure frequency. Multivariate modeling showed that anatomical findings such as lesions (odds ratio [OR] = 1.6) and calcifications (OR = 2.5) as well as magnetoencephalography (OR = 1.5) and semiology (OR = 1.7) were the most predictive of SOZ. Predictive power varied with the underlying seizure etiology.

These results highlight the importance of a multimodal approach to SOZ identification in the noninvasive evaluation phase. A deeper understanding of the potential of each individual preoperative testing modality can guide sEEG placement to minimize surgical risk while maximizing diagnostic yield.', 'article', ARRAY['EEG','Seizures','Pharmacology','Biomarkers','Epilepsy'], ARRAY['epilepsy','laser ablation','pediatrics','phase 1','seeg'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-204', 'Gastrointestinal symptoms are common in patients with new-onset refractory status epilepticus (NORSE)', ARRAY['Shrestha A','Silveira LJ','Thomas D','Leech J','Lai YC','Riviello JJ','Muscal E','Soden J','Eschbach K'], 'Neurol Sci', 2025, 8, '10.1007/s10072-025-08345-x', '40835780', NULL, 'New-onset refractory status epilepticus (NORSE) is a rare clinical presentation in which patients develop refractory status epilepticus without a clear cause. Febrile infection-related epilepsy syndrome (FIRES) is a subset of NORSE preceded by febrile illness. Prolonged critical illness and treatments carry a risk of gastrointestinal (GI) disturbance. This study aimed to characterize GI symptoms in patients with NORSE.

This is a multicenter retrospective study of NORSE patients. Data from initial hospitalization and follow-up was collected via REDCap. Analysis was performed using R-4.2.1.

The study included 19 patients with a median age of 11.20 years (IQR 6.70-15.75) at status epilepticus onset, 2 diagnosed with NORSE and 17 with FIRES. GI symptoms occurred during initial hospitalization in 89% of patients. Most frequently reported were vomiting (79%), constipation (73%), and abdominal pain (47%). Seven patients had GI procedures, including colonoscopy and small bowel resection. At median follow-up of 37 months (IQR 10-41), GI symptoms were present in 31% of 16 surviving patients. Time in burst suppression (r = 0.34, p = 0.052), duration of status epilepticus (r=-0.11, p = 0.670), and ketogenic diet (p = 0.213) were not associated with GI symptoms. Number of anti-seizure medications (r = 0.48, p = 0.043) and highest pentobarbital rate (r = 0.51, p = 0.029) were associated.

GI symptoms are a common manifestation for NORSE patients during hospitalization, and for some may persist after discharge. One limitation is potential underreporting of subjective GI symptoms due to altered levels of consciousness and cognitive impairment. Further research may determine if symptoms are secondary to critical illness or part of the underlying pathogenesis of NORSE.', 'article', ARRAY['Status Epilepticus','Pharmacology','NORSE/FIRES'], ARRAY['febrile infection-related epilepsy syndrome','gastrointestinal symptoms','inflammation','ketogenic diet','new-onset refractory status epilepticus','refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-205', 'A Quality Improvement Initiative to Reduce Underdosing of Rectal Diazepam as Home Seizure Rescue Medication After Hospitalization', ARRAY['Silver MR','Caffe&#xe9; L','Fried LE','Gonzalez AK','Huber R','Kaufman MC','Means M','Patel N','Ramos M','Witzman S','Beam K','Zook J','Abend NS','Press C','Molisani S'], 'Neurol Clin Pract', 2025, 8, '10.1212/CPJ.0000000000200529', '40896559', 'PMC12396600', 'Seizure rescue medications are commonly prescribed to patients with epilepsy to treat and prevent clusters of seizures or status epilepticus. Underdosing of rescue medications decreases their efficacy, which may lead to status epilepticus and potentially avoidable emergency department (ED) visits or hospitalizations. In this quality improvement initiative, we aimed to reduce the rate of underdosed rectal diazepam prescriptions for children discharged from the inpatient neurology service at our institution from a baseline of 6% to 3% by July 2023.

The primary intervention was an order panel in the electronic health record that automated selection of correct dosing for age-based and weight-based seizure rescue medications including rectal diazepam, intranasal diazepam, and intranasal midazolam. A statistical process control p-chart was used to analyze our primary outcome measure, the monthly rate of underdosed rectal diazepam prescriptions for patients discharged from the inpatient neurology service. The process measure was use of the new order panel. Balancing measures included the dispense rate, cost for seizure rescue medications, and provider satisfaction.

During the baseline period, July 2020-August 2022, rectal diazepam was underdosed for 6% of patients discharged from the neurology service. After intervention, we achieved and sustained 0% underdosing of rectal diazepam. We observed no concerning changes in the dispense rate for the medications, the average copay cost remained low, and surveys of ordering providers showed overall high rates of satisfaction. By spreading the intervention, we reduced underdosing from 21% to 0.6% in the ED and from 12% to 4% across the health care system.

An order panel that automated selection of correct dosing effectively and sustainably reduced underdosing of seizure rescue medications and is transferrable across care settings. We expect that proper dosing of seizure rescue medications should reduce the occurrence of status epilepticus and associated complications.', 'article', ARRAY['Status Epilepticus','Survey','Pharmacology','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['nicholas-abend'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-206', 'De novo pathogenic CSF1R variant implicates microglial dysfunction in pathogenesis of febrile infection-related epilepsy syndrome', ARRAY['Fisher KS','Levine JM','Ankar A','Duan R','Lai YC','Muscal E','Risen SR','Riviello JJ','Tsai PC','Calame DG'], 'Epilepsia', 2025, 7, '10.1111/epi.18538', '40956030', 'PMC12455449', 'Febrile infection-related epilepsy syndrome (FIRES) is a rare presentation of refractory status epilepticus following a febrile illness with resulting refractory epilepsy. Evidence supports the presence of immune dysregulation in patients with FIRES, but a monogenic basis for FIRES has not been identified in most cases. We present a case of a previously healthy 16-year-old male with FIRES who was found to have a de novo predicted damaging missense variant in CSF1R on clinical whole genome sequencing, a gene encoding a critical regulator of microglial homeostasis in which pathogenic variants cause adult onset leukoencephalopathy. Molecular modeling demonstrates that the CSF1R variant likely destabilizes the critical ATP-binding domain of the CSF1 receptor. Furthermore, the variant was shown to disrupt CSF1R autophosphorylation in response to CSF1 treatment, thereby establishing its pathogenicity. This case proposes a role of microglial dysfunction in the pathogenesis of FIRES, contributing to the existing literature proposing innate immune dysregulation as an etiology of FIRES. These findings may suggest consideration of interventions targeting microglia specifically in the treatment of patients with FIRES.', 'case_report', ARRAY['Status Epilepticus','Pharmacology','Biomarkers','NORSE/FIRES'], ARRAY['csf1r','fires','norse','refractory status epilepticus'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-207', 'A scoping review on clinical and genetic diagnostic approaches for cerebral visual impairment', ARRAY['Albertos-Arranz H','Juvier-Riesgo T','Sainfort F','Jayakar A','Alfonso EC','Jacko VA','Mendoza-Santiesteban CE'], 'Surv Ophthalmol', 2025, 9, '10.1016/j.survophthal.2025.09.010', '40967510', NULL, 'In recent years, the prevalence of cerebral/cortical visual impairment (CVI) in pediatric population has risen in developed countries; however, the condition''s heterogeneity complicates its assessment and the creation of standardized diagnostic and treatment protocols. We review current clinical and genetic approaches to the diagnosis of CVI. A PubMed search conducted in October, 2024, identified original articles on the genetic and clinical diagnosis of children or young adults with CVI or at risk. Articles differentiating CVI from other diagnoses or typically developing children, as well as those examining screening tools, were also included. Of 565 references, 10 focused on the genetic features of CVI and 56 on clinical characteristics using different protocols or tests. Up to 40 % of CVI patients showed chromosomal abnormalities, and 26.9 % had genetic pathogenic variants linked to seizures, global developmental delay, intellectual disabilities, or birth complications. Ten of 17 questionnaires or screening tools are validated. Diagnostic protocols for identifying or diagnosing CVI (n = 12) included medical history, parent reports, visual field testing, optic nerve and oculomotor examinations, and visual perceptual assessments. Individuals with CVI showed poor visual performance on eye tracking (n = 9). Different visual evoked potential tests can help detect CVI (n = 9), and some studies highlight magnetic resonance imaging abnormalities in the dorsal and ventral stream and the thalamus. Several tests and screening tools are used to diagnose CVI, but their limited validation and variability make it challenging to establish precise protocols. Genetic testing can provide essential diagnostic information given the numerous genes involved, particularly after the main possible causes have been excluded.', 'review', ARRAY['Seizures','Review','Survey','Neurocritical Care'], ARRAY['brain damage','cerebral visual impairment','cortical visual impairment','visual development','visually impaired'], 'Pediatric', TRUE, ARRAY['anuj-jayakar'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-208', 'Neurophysiological changes associated with dysglycemia in term neonates with neonatal encephalopathy', ARRAY['Parokaran Varghese J','Pinchefsky EF','Montazeri S','Kamino D','Hahn CD','Vanhatalo S','Tam EW'], 'Clin Neurophysiol', 2025, 9, '10.1016/j.clinph.2025.2111002', '40974863', 'PMC12626053', 'To investigate the relationship between hypo/hyperglycemia and EEG measures in term neonates with neonatal encephalopathy (NE) treated with therapeutic hypothermia (TH).

Ninety-six neonates underwent concurrent continuous glucose monitoring (CGM) and EEG for 48 h within the first 72 h of life. Five-minute epochs of hypoglycemia (≤2.6 mmol/L; ≤47 mg/dL) and hyperglycemia (>10.1 mmol/L; >182 mg/dL) were identified. Continuous EEG data was segmented into 5-min epochs corresponding to 5-min CGM data. Visual EEG background score and 22 computational EEG measures were estimated and their relationship to dysglycemia was assessed after adjusting for hypoxia-ischemia severity and multiple testing.

Among the 96 neonates, 12 had hypoglycemia, 16 had hyperglycemia, including 1 with both during the recording period. In the adjusted analyses, hyperglycemic epochs were associated with worse visual background scores (1.2, 95 %CI 0.51-1.89, q = 0.003) and 11 computational EEG measures. In contrast, hypoglycemic epochs were not associated with a significant change in visual background scores (-0.28, 95 %CI -0.66 - -0.10, q = 0.549), and were only associated with one computational EEG measure.

Hyperglycemia is temporally associated with changes in brain function in term neonates with NE treated with TH.

This temporal relationship suggests high glucose levels may contribute directly to brain injury after NE.', 'article', ARRAY['EEG','Neonatal','Neurocritical Care'], ARRAY['continuous glucose monitoring','eeg','hyperglycemia','hypoglycemia','neonatal encephalopathy','therapeutic hypothermia'], 'Neonatal', TRUE, ARRAY['cecil-hahn'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-209', 'Clinical outcomes following stereotactic MRI-guided laser ablation in children with tuberous sclerosis complex and intractable epilepsy', ARRAY['Ortman C','Coorg R','Ali I','Clarke D','Diaz-Medina G','Houck K','Katyayan A','Masters L','Mohanty D','Nayak A','Quach M','Ravindra VM','Riviello JJ','Sen S','Seto E','Takacs D','Trandafir C','Freiling JT','Evankovich K','Yuan Y','Katlowitz KA','Curry D','Weiner HL','Anderson A'], 'Epilepsia', 2025, 12, '10.1111/epi.70036', '41367165', 'PMC13007845', 'In children with tuberous sclerosis complex (TSC) and drug-resistant epilepsy (DRE), magnetic resonance imaging-guided stereotactic laser ablation (SLA) therapy offers less-invasive treatment compared to craniotomy and resection. Our study seeks to further expand on the long-term outcomes in patients with TSC-related DRE who have undergone SLA.

Patients with TSC and DRE treated with SLA, between July 1, 2016 and January 1, 2022, at our institution were identified retrospectively. Reduction in number of anti-seizure medications (ASMs), developmental improvement as reported by the patients'' families, seizure frequency measured in surgically targeted seizure type and total seizures per day, and Engel classification were evaluated at 6 months, 1 year, 2 years, and thereafter at the most recent follow-up visit if available.

Forty patients (ages 11 months to 23 years, median age 3.6 years) with TSC underwent SLA. Total follow-up was on average 2.9 years post-surgery. Significant (>50%) reduction in total seizure frequency occurred in 80% of patients (n = 32), with 63% of patients reporting a >90% reduction in seizure frequency (n = 25) at last follow-up. Fifty-eight percent had complete freedom from their surgically targeted seizure type (n = 23). At last follow up, perceived developmental gains occurred in 63% (n = 25), reduction in ASM occurred in 40% (n = 16), and Engel class was III or less in 93% of patients (n = 37).

SLA was safe and effective for most patients, even the very young. A majority of patients achieved improvement in seizure frequency, including the surgically targeted seizure type, but less than half were able to reduce medications. Reported developmental improvement was related to Engel outcomes. Future studies utilizing neuropsychological testing in the full cohort will be required to offer objective insights into post-operative development profiles.', 'article', ARRAY['Seizures','Pharmacology','Outcomes','Epilepsy'], ARRAY['drug&#x2010;resistant epilepsy','laser interstitial thermal therapy (litt)','stereotactic laser ablation (sla)','stereo&#x2010;electroencephalography (seeg)','tuberous sclerosis complex'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-210', 'Methodology for the Pediatric Dose Optimization for Seizures in Emergency Medical Services (PediDOSE) study', ARRAY['Shah MI','Adelgais KM','Chamberlain JM','Wang HE','Morgan LA','Riviello JJ','Said RR','Sullivan JE','Ghaffari KF','Kothari KM','Saidinejad M','Lowe RA','Fowler RL','Counts CR','Morris CR','Studnek JR','Glober NK','Ward CE','Clemency BM','Patrick N','Munn RD','Brant-Zawadzki GM','Martin-Gill C','Nishijima DK','Li K','Sepulveda N','VanBuren JM'], 'Trials', 2025, 12, '10.1186/s13063-025-09342-3', '41388551', 'PMC12821847', 'Seizures are one of the most common reasons for emergency medical services (EMS) activation for children, and current EMS practice results in underdosing and delayed delivery of anti-seizure medication. A prehospital evidence-based guideline recommends using intranasal or intramuscular midazolam as first-line treatment for pediatric seizures. Despite attempts to implement these guidelines, one-third of children having a paramedic-witnessed seizure have ongoing seizures on emergency department (ED) arrival; this may be due to inadequate or delayed midazolam dosing. Replacing the error-prone, sequential calculations with age-based midazolam dosing may be simpler, faster, and more effective without compromising safety. The objective of this manuscript is to describe the methodology of the Pediatric Dose Optimization for Seizures in EMS (PediDOSE) study, a clinical trial designed to compare the effectiveness and safety of an EMS protocol with four age-based categories for midazolam dosing relative to the current weight-based dosing.

We are conducting a large EMS-based stepped wedge trial in the Pediatric Emergency Care Applied Research Network (PECARN) by implementing midazolam dosing based on four age categories in seizure protocols in EMS systems in 20 cities. We believe that this implementation will stop more seizures before ED arrival without increasing respiratory failure rates. The primary aim of this study is to compare the effectiveness of age-based EMS midazolam dosing compared to the current weight-based dosing on seizure cessation upon ED arrival. The secondary aim is to determine the frequency of respiratory failure in children after the implementation of EMS midazolam dosing based on these age categories.

If this study demonstrates that an EMS patient care protocol with age-based midazolam dosing is safe and more effective than current practice, the potential impact of this study is a paradigm shift in the treatment of pediatric seizures that can be easily implemented in EMS systems across the country. Beyond seizures, the concept of age-based dosing may also be applicable to other commonly encountered pediatric prehospital conditions for which medication may be indicated.', 'article', ARRAY['Seizures','Clinical Trial','Pharmacology','Outcomes'], ARRAY[]::TEXT[], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-211', 'Association of EEG Response to Hypertonic Saline and Neurologic Outcomes in Pediatric Acute Brain Injury', ARRAY['Mazzio EL','Catenaccio E','Liu R','Vossough A','Abend NS','Alcamo A','Huh JW','Lang SS','Berg RA','Topjian AA','Press C','Kirschen MP'], 'Neurocrit Care', 2026, 1, '10.1007/s12028-025-02422-x', '41507672', NULL, 'Electroencephalography (EEG) is a critical tool for neuromonitoring and neuroprognostication in children with acute brain injury. Quantitative EEG (qEEG), particularly the alpha-delta ratio (ADR), can detect worsening cerebral ischemia in adults, but it is unknown whether it can identify more subtle and transient changes in cerebral blood flow, such as those induced by hypertonic saline (HTS), in children with acute brain injury. We aimed to determine whether we could identify a cohort of patients with an ADR response to HTS and to evaluate the association between an ADR response and neurologic outcomes in critically ill children with acute brain injury.

We conducted a retrospective cohort study of patients admitted to a pediatric intensive care unit with acute brain injury who received HTS during EEG monitoring from 2018 to 2023. The ADR was calculated before and after HTS administration. An ADR response was defined as a > 20% increase from baseline to within 30 min of receiving HTS in either hemisphere. The primary outcome was survival with favorable neurologic outcome, defined as a Functional Status Scale score change < 3 from prehospital baseline to discharge. Secondary outcome was survival to hospital discharge.

Among 87 patients (median age 10 years [interquartile range 3.6-14.5], 46% female), 28% (24 of 87) had an ADR response to HTS. ADR responders were older (12.9 vs. 8.0 years; p = 0.004) and more likely to have continuous, normal-voltage EEG backgrounds (67% vs. 40%; p = 0.006). Patients with an ADR response had four times increased odds of favorable outcome and survival (odds ratio [OR] 4.0 [95% confidence interval (CI) 1.3-12.7] and OR 3.9 [95% CI 1.0-10.7], respectively).

An ADR increase > 20% following HTS was associated with increased odds of survival with favorable neurologic outcome and survival to hospital discharge in critically ill pediatric patients with acute brain injury. qEEG response to HTS may serve as a real-time, noninvasive biomarker of cerebral perfusion responsiveness.', 'article', ARRAY['qEEG','Neuromonitoring','Biomarkers','Outcomes'], ARRAY['brain injuries','cerebral blood flow','critical care','hypertonic saline','pediatrics','prognosis','quantitative eeg'], 'Pediatric', TRUE, ARRAY['nicholas-abend','matthew-kirschen'])
ON CONFLICT (id) DO NOTHING;

INSERT INTO publications (id, title, authors, journal, year, month, doi, pmid, pmcid, abstract, pub_type, categories, keywords, patient_population, is_member_paper, member_author_ids)
VALUES ('pub-212', 'Responsive neurostimulation in children, adolescents, and young Adults-Longitudinal effectiveness and safety', ARRAY['Lee ST','Patel S','Karakas C','Houck K','Trandafir C','McGinley MJ','Mohanty D','Riviello JJ','Weiner HL','Curry D','Ali I'], 'Neurotherapeutics', 2026, 3, '10.1016/j.neurot.2026.e00865', '41863185', NULL, 'Drug-resistant epilepsy (DRE) remains challenging to treat, and seizure control often fluctuates over time. Responsive neurostimulation (RNS) is increasingly used in pediatric and young adult populations, yet long-term effectiveness and safety data are limited. RNS provided durable benefit for most, though not all, patients, reflecting the dynamic nature of seizure control. The favorable effectiveness and safety profile support use of RNS in young patients with DRE.', 'article', ARRAY['Seizures','Pharmacology'], ARRAY['pediatric rns','pediatric drug-resistant epilepsy','responsive neurostimulation'], 'Pediatric', TRUE, ARRAY['james-riviello'])
ON CONFLICT (id) DO NOTHING;


